const FLASHCARDS = [
  {"id":"mp01-def-01","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Application linéaire.","a":"Une application \\(f : E \\to F\\) est dite linéaire (ou est un morphisme d'espaces vectoriels) si : \\n- \\(\\forall\\, (x, y) \\in E^2,\\quad f(x + y) = f(x) + f(y)\\) \\n- \\(\\forall\\, \\lambda \\in \\mathbb{K},\\ \\forall\\, x \\in E,\\quad f(\\lambda x) = \\lambda f(x)\\) On note \\(\\mathcal{L}(E, F)\\) l'ensemble des applications linéaires de \\(E\\) dans \\(F\\), et \\(\\mathcal{L}(E) = \\mathcal{L}(E, E)\\) l'algèbre des endomorphismes de \\(E\\).","hint":"Application linéaire"},
  {"id":"mp01-def-02","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Noyau et image.","a":"Soit \\(f \\in \\mathcal{L}(E, F)\\). On définit : \\n- Le noyau : \\(\\ker(f) = \\{ x \\in E \\mid f(x) = 0_F \\}\\), sous-espace vectoriel de \\(E\\). \\n- L'image : \\(\\text{Im}(f) = \\{ f(x) \\mid x \\in E \\}\\), sous-espace vectoriel de \\(F\\). Le rang de \\(f\\) est \\(\\text{rg}(f) = \\dim(\\text{Im}(f))\\).","hint":"Noyau image"},
  {"id":"mp01-thm-01","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"thm","q":"Énoncer le théorème : Théorème du rang.","a":"Soit \\(f \\in \\mathcal{L}(E, F)\\) avec \\(E\\) de dimension finie. Alors : \\[\\]","hint":"Théorème rang"},
  {"id":"mp01-prop-01","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Inégalité du rang de la composée.","a":"Soient \\(f \\in \\mathcal{L}(E, F)\\) et \\(g \\in \\mathcal{L}(F, G)\\). Alors : \\[\\]","hint":"Inégalité rang composée"},
  {"id":"mp01-prop-02","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Caractérisations.","a":"Soit \\(f \\in \\mathcal{L}(E, F)\\). \\n- \\(f\\) est injective si et seulement si \\(\\ker(f) = \\{0_E\\}\\). \\n- \\(f\\) est surjective si et seulement si \\(\\text{Im}(f) = F\\). \\n- \\(f\\) est bijective si et seulement si \\(f\\) est injective et surjective.","hint":"Caractérisations"},
  {"id":"mp01-prop-03","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Image de familles libres, liées, génératrices.","a":"Soit \\(f \\in \\mathcal{L}(E, F)\\) et \\((x_1, \\ldots, x_p)\\) une famille de vecteurs de \\(E\\). \\n- Si \\(f\\) est injective et \\((x_1, \\ldots, x_p)\\) est libre, alors \\((f(x_1), \\ldots, f(x_p))\\) est libre. \\n- Si \\(f\\) est surjective et \\((x_1, \\ldots, x_p)\\) est génératrice de \\(E\\), alors \\((f(x_1), \\ldots, f(x_p))\\) est génératrice de \\(F\\). \\n- Si \\((x_1, \\ldots, x_p)\\) est liée, alors \\((f(x_1), \\ldots, f(x_p))\\) est liée.","hint":"Image familles libres, liées,..."},
  {"id":"mp01-thm-02","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"thm","q":"Énoncer le théorème : Isomorphisme en dimension finie.","a":"Soit \\(f \\in \\mathcal{L}(E, F)\\) avec \\(\\dim(E) = \\dim(F) = n \\n- \\(f\\) est injective \\n- \\(f\\) est surjective \\n- \\(f\\) est bijective (i.e. \\(f\\) est un isomorphisme)","hint":"Isomorphisme dimension finie"},
  {"id":"mp01-def-03","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Somme de sous-espaces.","a":"La somme de \\(F_1\\) et \\(F_2\\) est le sous-espace vectoriel : \\[\\]","hint":"Somme sous-espaces"},
  {"id":"mp01-def-04","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Somme directe.","a":"On dit que la somme \\(F_1 + F_2\\) est directe, et on note \\(F_1 \\oplus F_2\\), lorsque : \\[\\]","hint":"Somme directe"},
  {"id":"mp01-thm-03","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"thm","q":"Énoncer le théorème : Caractérisation de la somme directe.","a":"Soient \\(F_1\\) et \\(F_2\\) deux sous-espaces de \\(E\\). Les assertions suivantes sont équivalentes : \\n- \\(F_1 + F_2\\) est une somme directe (i.e. \\(F_1 \\cap F_2 = \\{0_E\\}\\)) ; \\n- Tout vecteur \\(x \\in F_1 + F_2\\) admet une unique décomposition \\(x = x_1 + x_2\\) avec \\(x_1 \\in F_1\\), \\(x_2 \\in F_2\\).","hint":"Caractérisation somme directe"},
  {"id":"mp01-thm-04","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"thm","q":"Énoncer le théorème : Formule de Grassmann.","a":"Si \\(E\\) est de dimension finie et \\(F_1, F_2\\) sont des sous-espaces de \\(E\\), alors : \\[\\]","hint":"Formule Grassmann"},
  {"id":"mp01-def-05","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Sous-espaces supplémentaires.","a":"On dit que \\(F_1\\) et \\(F_2\\) sont supplémentaires dans \\(E\\) lorsque : \\[\\]","hint":"Sous-espaces supplémentaires"},
  {"id":"mp01-prop-04","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Dimension et supplémentaires.","a":"Si \\(E\\) est de dimension finie \\(n\\), alors \\(F_1\\) et \\(F_2\\) sont supplémentaires dans \\(E\\) si et seulement si l'une des conditions suivantes est remplie : \\n- \\(F_1 \\cap F_2 = \\{0_E\\}\\) et \\(\\dim F_1 + \\dim F_2 = n\\) ; \\n- \\(F_1 + F_2 = E\\) et \\(\\dim F_1 + \\dim F_2 = n\\).","hint":"Dimension supplémentaires"},
  {"id":"mp01-def-06","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Somme directe de \\(n\\) sous-espaces.","a":"On dit que la somme \\(F_1 + F_2\\) est directe, et on note \\(F_1 \\oplus F_2\\), lorsque : \\[\\]","hint":"Somme directe sous-espaces"},
  {"id":"mp01-prop-05","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Caractérisation de la somme directe de \\(n\\) sous-espaces.","a":"On dit que la somme \\(F_1 + F_2\\) est directe, et on note \\(F_1 \\oplus F_2\\), lorsque : \\[\\]","hint":"Caractérisation somme directe sous-espaces"},
  {"id":"mp01-def-07","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Projection.","a":"Soit \\(E = F_1 \\oplus F_2\\). La projection sur \\(F_1\\) parallèlement à \\(F_2\\) est l'application linéaire \\(p : E \\to E\\) définie par : \\[\\]","hint":"Projection"},
  {"id":"mp01-thm-05","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"thm","q":"Énoncer le théorème : Caractérisation des projecteurs (idempotence).","a":"Un endomorphisme \\(p \\in \\mathcal{L}(E)\\) est un projecteur si et seulement si : \\[\\]","hint":"Caractérisation des projecteurs (idempotence)"},
  {"id":"mp01-prop-06","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Image d'un projecteur.","a":"Soit \\(p\\) un projecteur. Alors : \\[\\]","hint":"Image d'un projecteur"},
  {"id":"mp01-def-08","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Symétrie.","a":"Soit \\(E = F_1 \\oplus F_2\\). La symétrie par rapport à \\(F_1\\) parallèlement à \\(F_2\\) est l'application linéaire \\(s : E \\to E\\) définie par : \\[\\]","hint":"Symétrie"},
  {"id":"mp01-prop-07","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Caractérisation des symétries.","a":"Un endomorphisme \\(s \\in \\mathcal{L}(E)\\) est une symétrie si et seulement si : \\[\\]","hint":"Caractérisation des symétries"},
  {"id":"mp01-prop-08","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Lien projection-symétrie.","a":"Soit \\(E = F_1 \\oplus F_2\\), \\(p\\) la projection sur \\(F_1\\) parallèlement à \\(F_2\\), et \\(s\\) la symétrie correspondante. Alors : \\[\\]","hint":"Lien projection-symétrie"},
  {"id":"mp01-def-09","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Dual d'un espace vectoriel.","a":"Le dual de \\(E\\) est l'espace des formes linéaires sur \\(E\\) : \\[\\]","hint":"Dual d'un espace vectoriel"},
  {"id":"mp01-def-10","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Base duale.","a":"Soit \\(\\mathcal{B} = (e_1, \\ldots, e_n)\\) une base de \\(E\\). La base duale est la famille \\((e_1^*, \\ldots, e_n^*)\\) d'éléments de \\(E^*\\) définis par : \\[\\]","hint":"Base duale"},
  {"id":"mp01-thm-06","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"thm","q":"Énoncer le théorème : La base duale est une base de \\(E^*\\).","a":"Soit \\(\\mathcal{B} = (e_1, \\ldots, e_n)\\) une base de \\(E\\). La base duale est la famille \\((e_1^*, \\ldots, e_n^*)\\) d'éléments de \\(E^*\\) définis par : \\[\\]","hint":"base duale est une..."},
  {"id":"mp01-prop-09","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Coordonnées via la base duale.","a":"Pour tout \\(x \\in E\\), on a : \\[\\]","hint":"Coordonnées via base duale"},
  {"id":"mp01-def-11","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Orthogonal d'un sous-espace.","a":"Soit \\(F\\) un sous-espace de \\(E\\). L'orthogonal (ou annulateur) de \\(F\\) est le sous-espace de \\(E^*\\) : \\[\\]","hint":"Orthogonal d'un sous-espace"},
  {"id":"mp01-thm-07","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"thm","q":"Énoncer le théorème : Dimension de l'orthogonal.","a":"Si \\(E\\) est de dimension \\(n\\) et \\(F\\) un sous-espace de dimension \\(p\\), alors : \\[\\]","hint":"Dimension l'orthogonal"},
  {"id":"mp01-def-12","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Matrice par blocs.","a":"Une matrice \\(M \\in \\mathcal{M}_{m,n}(\\mathbb{K})\\) est dite écrite par blocs lorsqu'on la décompose en sous-matrices par un découpage compatible des lignes et des colonnes : \\[\\]","hint":"Matrice par blocs"},
  {"id":"mp01-thm-08","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"thm","q":"Énoncer le théorème : Produit par blocs.","a":"Si les découpages sont compatibles (le découpage en colonnes de la première matrice coïncide avec le découpage en lignes de la seconde), alors le produit par blocs suit les mêmes règles que le produit matriciel usuel : \\[\\]","hint":"Produit par blocs"},
  {"id":"mp01-prop-10","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Matrice d'une projection dans une base adaptée.","a":"Soit \\(E = F_1 \\oplus F_2\\) avec \\(\\dim F_1 = r\\) et \\(p\\) la projection sur \\(F_1\\) parallèlement à \\(F_2\\). Dans une base adaptée \\(\\mathcal{B} = (\\underbrace{e_1,\\ldots,e_r}_{F_1}, \\underbrace{e_{r+1},\\ldots,e_n}_{F_2})\\), la matrice de \\(p\\) est : \\[\\]","hint":"Matrice d'une projection dans..."},
  {"id":"mp01-prop-11","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Sous-espace stable et matrice triangulaire.","a":"Soit \\(u \\in \\mathcal{L}(E)\\) et \\(F\\) un sous-espace de \\(E\\) stable par \\(u\\) (i.e. \\(u(F) \\subset F\\)). Si on choisit une base \\(\\mathcal{B}\\) dont les \\(p\\) premiers vecteurs forment une base de \\(F\\), alors : \\[\\]","hint":"Sous-espace stable matrice triangulaire"},
  {"id":"mp01-def-13","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Matrice de passage.","a":"Soient \\(\\mathcal{B} = (e_1, \\ldots, e_n)\\) et \\(\\mathcal{B}' = (e_1', \\ldots, e_n')\\) deux bases de \\(E\\). La matrice de passage de \\(\\mathcal{B}\\) à \\(\\mathcal{B}'\\) est la matrice dont la \\(j\\)-ème colonne contient les coordonnées de \\(e_j'\\) dans la base \\(\\mathcal{B}\\) : \\[\\]","hint":"Matrice passage"},
  {"id":"mp01-thm-09","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"thm","q":"Énoncer le théorème : Formule de changement de base.","a":"Soit \\(f \\in \\mathcal{L}(E, F)\\), \\(\\mathcal{B}, \\mathcal{B}'\\) deux bases de \\(E\\) et \\(\\mathcal{C}, \\mathcal{C}'\\) deux bases de \\(F\\). Si \\(P = P_{\\mathcal{B} \\to \\mathcal{B}'}\\) et \\(Q = P_{\\mathcal{C} \\to \\mathcal{C}'}\\), alors : \\[\\]","hint":"Formule changement base"},
  {"id":"mp01-def-14","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Matrices équivalentes.","a":"Deux matrices \\(A, B \\in \\mathcal{M}_{m,n}(\\mathbb{K})\\) sont dites équivalentes s'il existe \\(P \\in GL_n(\\mathbb{K})\\) et \\(Q \\in GL_m(\\mathbb{K})\\) telles que : \\[\\]","hint":"Matrices équivalentes"},
  {"id":"mp01-def-15","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"def","q":"Définir : Matrices semblables.","a":"Deux matrices carrées \\(A, B \\in \\mathcal{M}_n(\\mathbb{K})\\) sont dites semblables s'il existe \\(P \\in GL_n(\\mathbb{K})\\) telle que : \\[\\]","hint":"Matrices semblables"},
  {"id":"mp01-prop-12","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"prop","q":"Énoncer la proposition : Invariants de similitude.","a":"Si \\(A\\) et \\(B\\) sont semblables, alors elles ont mêmes : \\n- rang : \\(\\text{rg}(A) = \\text{rg}(B)\\) \\n- trace : \\(\\text{tr}(A) = \\text{tr}(B)\\) \\n- déterminant : \\(\\det(A) = \\det(B)\\) \\n- polynôme caractéristique : \\(\\chi_A = \\chi_B\\)","hint":"Invariants similitude"},
  {"id":"mp01-thm-10","ch":"mp-01","chName":"Compléments d'algèbre linéaire","type":"thm","q":"Énoncer le théorème : Classification par le rang (équivalence).","a":"Soit \\(A \\in \\mathcal{M}_{m,n}(\\mathbb{K})\\) de rang \\(r\\). Alors \\(A\\) est équivalente à la matrice : \\[\\]","hint":"Classification par rang (équivalence)"},
  {"id":"mp02-def-01","ch":"mp-02","chName":"Réduction avancée","type":"def","q":"Définir : Polynôme d'un endomorphisme.","a":"Soit \\(P = a_0 + a_1 X + \\cdots + a_n X^n \\in \\mathbb{K}[X]\\) et \\(u \\in \\mathcal{L}(E)\\). On définit : \\[\\]","hint":"Polynôme d'un endomorphisme"},
  {"id":"mp02-def-02","ch":"mp-02","chName":"Réduction avancée","type":"def","q":"Définir : Polynôme annulateur.","a":"Un polynôme \\(P \\in \\mathbb{K}[X]\\) est dit annulateur de \\(u\\) si \\(P(u) = 0_{\\mathcal{L}(E)}\\). L'ensemble des polynômes annulateurs forme un idéal de \\(\\mathbb{K}[X]\\).","hint":"Polynôme annulateur"},
  {"id":"mp02-def-03","ch":"mp-02","chName":"Réduction avancée","type":"def","q":"Définir : Polynôme minimal.","a":"Si l'idéal des polynômes annulateurs est non nul, il est engendré par un unique polynôme unitaire \\(\\Pi_u\\), appelé polynôme minimal de \\(u\\). Il vérifie : \\n- \\(\\Pi_u(u) = 0\\) et \\(\\Pi_u\\) est de degré minimal parmi les annulateurs non nuls. \\n- \\(P(u) = 0 \\Longleftrightarrow \\Pi_u \\mid P\\).","hint":"Polynôme minimal"},
  {"id":"mp02-prop-01","ch":"mp-02","chName":"Réduction avancée","type":"prop","q":"Énoncer la proposition : Existence en dimension finie.","a":"Si \\(\\dim(E) = n < +\\infty\\), alors tout endomorphisme de \\(E\\) admet un polynôme minimal, de degré \\(\\deg(\\Pi_u) \\leq n^2\\).","hint":"Existence dimension finie"},
  {"id":"mp02-prop-02","ch":"mp-02","chName":"Réduction avancée","type":"prop","q":"Énoncer la proposition : Structure de \\(\\mathbb{K}[u]\\).","a":"Si \\(d = \\deg(\\Pi_u)\\), alors \\(\\mathbb{K}[u]\\) est de dimension \\(d\\) avec base \\((\\mathrm{Id}_E, u, \\ldots, u^{d-1})\\). En particulier, \\(\\deg(\\Pi_u) = 1\\) si et seulement si \\(u\\) est une homothétie.","hint":"Structure mathbb{K}[u]"},
  {"id":"mp02-prop-03","ch":"mp-02","chName":"Réduction avancée","type":"prop","q":"Énoncer la proposition : Inversibilité et polynôme minimal.","a":"Soit \\(u \\in \\mathcal{L}(E)\\) admettant un polynôme minimal \\(\\Pi_u\\). Alors : \\[\\]","hint":"Inversibilité polynôme minimal"},
  {"id":"mp02-def-04","ch":"mp-02","chName":"Réduction avancée","type":"def","q":"Définir : Spectre et espaces propres.","a":"Soit \\(u \\in \\mathcal{L}(E)\\). Un scalaire \\(\\lambda \\in \\mathbb{K}\\) est une valeur propre de \\(u\\) s'il existe \\(x \\neq 0_E\\) tel que \\(u(x) = \\lambda x\\). L'ensemble des valeurs propres est le spectre \\(\\mathrm{Sp}(u)\\). L'espace propre associé est \\(E_\\lambda = \\ker(u - \\lambda\\,\\mathrm{Id}_E)\\).","hint":"Spectre espaces propres"},
  {"id":"mp02-prop-04","ch":"mp-02","chName":"Réduction avancée","type":"prop","q":"Énoncer la proposition : Indépendance des espaces propres.","a":"Les espaces propres associés à des valeurs propres distinctes sont en somme directe : \\[\\]","hint":"Indépendance des espaces propres"},
  {"id":"mp02-def-05","ch":"mp-02","chName":"Réduction avancée","type":"def","q":"Définir : Polynôme caractéristique.","a":"Soit \\(A \\in \\mathcal{M}_n(\\mathbb{K})\\). Le polynôme caractéristique de \\(A\\) est : \\[\\]","hint":"Polynôme caractéristique"},
  {"id":"mp02-thm-01","ch":"mp-02","chName":"Réduction avancée","type":"thm","q":"Énoncer le théorème : Valeurs propres et polynôme caractéristique.","a":"Les valeurs propres de \\(A\\) sont exactement les racines de \\(\\chi_A\\). De plus, si \\(\\chi_A\\) est scindé avec racines \\(\\lambda_1, \\ldots, \\lambda_n\\) (comptées avec multiplicité) : \\[\\]","hint":"Valeurs propres polynôme caractéristique"},
  {"id":"mp02-prop-05","ch":"mp-02","chName":"Réduction avancée","type":"prop","q":"Énoncer la proposition : Dimension des espaces propres.","a":"Si \\(\\lambda\\) est valeur propre de \\(u\\) de multiplicité \\(m_\\lambda\\) (en tant que racine de \\(\\chi_u\\)), alors : \\[\\]","hint":"Dimension des espaces propres"},
  {"id":"mp02-prop-06","ch":"mp-02","chName":"Réduction avancée","type":"prop","q":"Énoncer la proposition : Valeurs propres et polynôme minimal.","a":"\\(\\lambda \\in \\mathrm{Sp}(u) \\iff \\Pi_u(\\lambda) = 0\\). Autrement dit, le spectre est l'ensemble des racines du polynôme minimal.","hint":"Valeurs propres polynôme minimal"},
  {"id":"mp02-thm-02","ch":"mp-02","chName":"Réduction avancée","type":"thm","q":"Énoncer le théorème : de Cayley-Hamilton.","a":"Soit \\(E\\) un \\(\\mathbb{K}\\)-espace vectoriel de dimension finie \\(n\\) et \\(u \\in \\mathcal{L}(E)\\). Alors : \\[\\]","hint":"Cayley-Hamilton"},
  {"id":"mp02-cor-01","ch":"mp-02","chName":"Réduction avancée","type":"cor","q":"Énoncer le corollaire : Forme du polynôme minimal.","a":"Si \\(\\chi_A = (X - \\lambda_1)^{\\alpha_1} \\cdots (X - \\lambda_p)^{\\alpha_p}\\), alors : \\[\\]","hint":"Forme polynôme minimal"},
  {"id":"mp02-thm-03","ch":"mp-02","chName":"Réduction avancée","type":"thm","q":"Énoncer le théorème : Décomposition des noyaux.","a":"Soit \\(u \\in \\mathcal{L}(E)\\) et \\(P_1, \\ldots, P_r \\in \\mathbb{K}[X]\\) deux à deux premiers entre eux. Alors : \\[\\]","hint":"Décomposition des noyaux"},
  {"id":"mp02-def-06","ch":"mp-02","chName":"Réduction avancée","type":"def","q":"Définir : Endomorphisme diagonalisable.","a":"\\(u \\in \\mathcal{L}(E)\\) est diagonalisable s'il existe une base de \\(E\\) dans laquelle la matrice de \\(u\\) est diagonale. Une matrice \\(A \\in \\mathcal{M}_n(\\mathbb{K})\\) est diagonalisable si elle est semblable à une matrice diagonale.","hint":"Endomorphisme diagonalisable"},
  {"id":"mp02-thm-04","ch":"mp-02","chName":"Réduction avancée","type":"thm","q":"Énoncer le théorème : Caractérisations de la diagonalisabilité.","a":"Pour \\(u \\in \\mathcal{L}(E)\\) avec \\(\\dim(E) = n\\), les assertions suivantes sont équivalentes : \\n- \\(u\\) est diagonalisable. \\n- Il existe une base de \\(E\\) formée de vecteurs propres de \\(u\\). \\n- \\(E = E_{\\lambda_1} \\oplus \\cdots \\oplus E_{\\lambda_p}\\) où \\(\\mathrm{Sp}(u) = \\{\\lambda_1, \\ldots, \\lambda_p\\}\\). \\n- \\(\\chi_u\\) est scindé et \\(\\forall\\, \\lambda \\in \\mathrm{Sp}(u),\\ \\dim(E_\\lambda) = m_\\lambda\\). \\n- \\(\\Pi_u\\) est scindé à racines simples.","hint":"Caractérisations diagonalisabilité"},
  {"id":"mp02-cor-02","ch":"mp-02","chName":"Réduction avancée","type":"cor","q":"Énoncer le corollaire : Racines simples.","a":"Si \\(\\chi_A\\) est scindé à racines simples (toutes de multiplicité 1), alors \\(A\\) est diagonalisable.","hint":"Racines simples"},
  {"id":"mp02-prop-07","ch":"mp-02","chName":"Réduction avancée","type":"prop","q":"Énoncer la proposition : Stabilité de la diagonalisabilité.","a":"Si \\(A\\) est diagonalisable : \\n- \\(\\forall\\, k \\in \\mathbb{N},\\ A^k\\) est diagonalisable. \\n- \\(\\forall\\, P \\in \\mathbb{K}[X],\\ P(A)\\) est diagonalisable. \\n- \\(A^\\top\\) est diagonalisable. \\n- Si \\(A \\in \\mathrm{GL}_n(\\mathbb{K})\\), alors \\(A^{-1}\\) est diagonalisable.","hint":"Stabilité diagonalisabilité"},
  {"id":"mp02-def-07","ch":"mp-02","chName":"Réduction avancée","type":"def","q":"Définir : Endomorphismes codiagonalisables.","a":"Deux endomorphismes \\(u, v \\in \\mathcal{L}(E)\\) sont codiagonalisables s'il existe une base de \\(E\\) dans laquelle les matrices de \\(u\\) et \\(v\\) sont simultanément diagonales.","hint":"Endomorphismes codiagonalisables"},
  {"id":"mp02-thm-05","ch":"mp-02","chName":"Réduction avancée","type":"thm","q":"Énoncer le théorème : CNS de codiagonalisation.","a":"Deux endomorphismes diagonalisables \\(u\\) et \\(v\\) sont codiagonalisables si et seulement si \\(u \\circ v = v \\circ u\\).","hint":"CNS codiagonalisation"},
  {"id":"mp02-def-08","ch":"mp-02","chName":"Réduction avancée","type":"def","q":"Définir : Endomorphisme trigonalisable.","a":"\\(u \\in \\mathcal{L}(E)\\) est trigonalisable s'il existe une base de \\(E\\) dans laquelle la matrice de \\(u\\) est triangulaire supérieure.","hint":"Endomorphisme trigonalisable"},
  {"id":"mp02-thm-06","ch":"mp-02","chName":"Réduction avancée","type":"thm","q":"Énoncer le théorème : CNS de trigonalisabilité.","a":"Pour \\(A \\in \\mathcal{M}_n(\\mathbb{K})\\), les assertions suivantes sont équivalentes : \\n- \\(A\\) est trigonalisable. \\n- \\(\\chi_A\\) est scindé sur \\(\\mathbb{K}\\). \\n- \\(\\Pi_A\\) est scindé sur \\(\\mathbb{K}\\). \\n- Il existe un polynôme annulateur scindé sur \\(\\mathbb{K}\\).","hint":"CNS trigonalisabilité"},
  {"id":"mp02-cor-03","ch":"mp-02","chName":"Réduction avancée","type":"cor","q":"Énoncer le corollaire : Sur \\(\\mathbb{C}\\).","a":"Si \\(d = \\deg(\\Pi_u)\\), alors \\(\\mathbb{K}[u]\\) est de dimension \\(d\\) avec base \\((\\mathrm{Id}_E, u, \\ldots, u^{d-1})\\). En particulier, \\(\\deg(\\Pi_u) = 1\\) si et seulement si \\(u\\) est une homothétie.","hint":"Sur mathbb{C}"},
  {"id":"mp02-prop-08","ch":"mp-02","chName":"Réduction avancée","type":"prop","q":"Énoncer la proposition : Cotrigonalisation sur \\(\\mathbb{C}\\).","a":"Toute matrice de \\(\\mathcal{M}_n(\\mathbb{C})\\) est trigonalisable (d'Alembert-Gauss : tout polynôme non constant de \\(\\mathbb{C}[X]\\) est scindé).","hint":"Cotrigonalisation sur mathbb{C}"},
  {"id":"mp02-def-09","ch":"mp-02","chName":"Réduction avancée","type":"def","q":"Définir : Nilpotence.","a":"Un endomorphisme \\(u \\in \\mathcal{L}(E)\\) est nilpotent s'il existe \\(p \\in \\mathbb{N}^*\\) tel que \\(u^p = 0\\). Le plus petit tel \\(p\\) est l'indice de nilpotence.","hint":"Nilpotence"},
  {"id":"mp02-prop-09","ch":"mp-02","chName":"Réduction avancée","type":"prop","q":"Énoncer la proposition : Propriétés des nilpotents.","a":"Soit \\(u\\) nilpotent d'indice \\(p\\) sur un espace de dimension \\(n\\). Alors : \\n- \\(p \\leq n\\). \\n- \\(\\chi_u = X^n\\) et \\(\\Pi_u = X^p\\). \\n- \\(\\mathrm{Sp}(u) = \\{0\\}\\). \\n- \\(\\mathrm{Id}_E + u\\) et \\(\\mathrm{Id}_E - u\\) sont inversibles. \\n- Le seul endomorphisme nilpotent diagonalisable est l'endomorphisme nul.","hint":"Propriétés des nilpotents"},
  {"id":"mp02-prop-10","ch":"mp-02","chName":"Réduction avancée","type":"prop","q":"Énoncer la proposition : Opérations sur les nilpotents.","a":"Soient \\(u, v \\in \\mathcal{L}(E)\\) nilpotents avec \\(u \\circ v = v \\circ u\\). Alors : \\n- \\(\\forall\\, \\lambda \\in \\mathbb{K},\\ \\lambda u\\) est nilpotent. \\n- \\(u \\circ v\\) est nilpotent. \\n- \\(u + v\\) est nilpotent (formule du binôme applicable car \\(uv = vu\\)).","hint":"Opérations sur les nilpotents"},
  {"id":"mp02-def-10","ch":"mp-02","chName":"Réduction avancée","type":"def","q":"Définir : Sous-espace caractéristique.","a":"Soit \\(u \\in \\mathcal{L}(E)\\) avec \\(\\chi_u\\) scindé : \\(\\chi_u = (X - \\lambda_1)^{\\alpha_1} \\cdots (X - \\lambda_p)^{\\alpha_p}\\). Le sous-espace caractéristique associé à \\(\\lambda_i\\) est : \\[\\]","hint":"Sous-espace caractéristique"},
  {"id":"mp02-thm-07","ch":"mp-02","chName":"Réduction avancée","type":"thm","q":"Énoncer le théorème : Décomposition en sous-espaces caractéristiques.","a":"Si \\(\\chi_u\\) est scindé, alors : \\[\\]","hint":"Décomposition sous-espaces caractéristiques"},
  {"id":"mp02-thm-08","ch":"mp-02","chName":"Réduction avancée","type":"thm","q":"Énoncer le théorème : de Dunford.","a":"Soit \\(u \\in \\mathcal{L}(E)\\) avec \\(\\chi_u\\) scindé. Il existe un unique couple \\((d, n)\\) d'endomorphismes de \\(E\\) tels que : \\n- \\(u = d + n\\) \\n- \\(d\\) est diagonalisable et \\(n\\) est nilpotent \\n- \\(d \\circ n = n \\circ d\\) De plus, \\(d\\) et \\(n\\) sont des polynômes en \\(u\\) : \\(d, n \\in \\mathbb{K}[u]\\).","hint":"Dunford"},
  {"id":"mp03-def-01","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"def","q":"Définir : Forme bilinéaire.","a":"Une forme bilinéaire sur \\(E\\) est une application \\(\\varphi : E \\times E \\to \\mathbb{K}\\) qui est linéaire par rapport à chacune de ses deux variables : \\n- Pour tout \\(y \\in E\\), l'application \\(x \\mapsto \\varphi(x, y)\\) est linéaire. \\n- Pour tout \\(x \\in E\\), l'application \\(y \\mapsto \\varphi(x, y)\\) est linéaire. On note \\(\\mathcal{B}(E)\\) l'espace des formes bilinéaires sur \\(E\\).","hint":"Forme bilinéaire"},
  {"id":"mp03-def-02","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"def","q":"Définir : Symétrie et antisymétrie.","a":"Soit \\(\\varphi \\in \\mathcal{B}(E)\\). On dit que \\(\\varphi\\) est : \\n- symétrique si \\(\\varphi(x, y) = \\varphi(y, x)\\) pour tous \\(x, y \\in E\\). \\n- antisymétrique si \\(\\varphi(x, y) = -\\varphi(y, x)\\) pour tous \\(x, y \\in E\\). On note \\(\\mathcal{S}(E)\\) l'espace des formes bilinéaires symétriques et \\(\\mathcal{A}(E)\\) celui des antisymétriques. Si \\(\\mathrm{car}(\\mathbb{K}) \\neq 2\\), on a la décomposition \\(\\mathcal{B}(E) = \\mathcal{S}(E) \\oplus \\mathcal{A}(E)\\).","hint":"Symétrie antisymétrie"},
  {"id":"mp03-def-03","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"def","q":"Définir : Matrice d'une forme bilinéaire.","a":"Soit \\(\\mathcal{B} = (e_1, \\ldots, e_n)\\) une base de \\(E\\) et \\(\\varphi \\in \\mathcal{B}(E)\\). La matrice de \\(\\varphi\\) dans la base \\(\\mathcal{B}\\) est la matrice \\(M = (m_{ij}) \\in \\mathcal{M}_n(\\mathbb{K})\\) définie par : \\[\\]","hint":"Matrice d'une forme bilinéaire"},
  {"id":"mp03-prop-01","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"prop","q":"Énoncer la proposition : Changement de base.","a":"Soient \\(\\mathcal{B}\\) et \\(\\mathcal{B}'\\) deux bases de \\(E\\), et \\(P\\) la matrice de passage de \\(\\mathcal{B}\\) à \\(\\mathcal{B}'\\). Si \\(M_{\\mathcal{B}}\\) est la matrice de \\(\\varphi\\) dans \\(\\mathcal{B}\\), alors la matrice dans \\(\\mathcal{B}'\\) est : \\[\\]","hint":"Changement base"},
  {"id":"mp03-def-04","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"def","q":"Définir : Forme quadratique.","a":"Soit \\(\\varphi\\) une forme bilinéaire symétrique sur \\(E\\). La forme quadratique associée à \\(\\varphi\\) est l'application \\(q : E \\to \\mathbb{K}\\) définie par : \\[\\]","hint":"Forme quadratique"},
  {"id":"mp03-prop-02","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"prop","q":"Énoncer la proposition : Identités de polarisation.","a":"Si \\(\\mathrm{car}(\\mathbb{K}) \\neq 2\\), on peut retrouver la forme polaire \\(\\varphi\\) à partir de \\(q\\) : \\[\\]","hint":"Identités polarisation"},
  {"id":"mp03-def-05","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"def","q":"Définir : Matrice, rang et noyau.","a":"Soit \\(q \\in \\mathcal{Q}(E)\\) de forme polaire \\(\\varphi\\). La matrice de \\(q\\) dans une base \\(\\mathcal{B}\\) est la matrice \\(M = M_{\\mathcal{B}}(\\varphi)\\). On a alors : \\[\\]","hint":"Matrice, rang noyau"},
  {"id":"mp03-prop-03","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"prop","q":"Énoncer la proposition : Homogénéité.","a":"Toute forme quadratique est une application homogène de degré 2 : pour tout \\(\\lambda \\in \\mathbb{K}\\) et \\(x \\in E\\), \\[\\]","hint":"Homogénéité"},
  {"id":"mp03-def-06","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"def","q":"Définir : Vecteurs orthogonaux.","a":"Deux vecteurs \\(x, y \\in E\\) sont dits orthogonaux (pour \\(\\varphi\\)) si \\(\\varphi(x, y) = 0\\). On note \\(x \\perp y\\). Un vecteur \\(x\\) est dit isotrope si \\(q(x) = \\varphi(x, x) = 0\\), c'est-à-dire s'il est orthogonal à lui-même. Le cône isotrope de \\(q\\) est l'ensemble \\(C(q) = \\{x \\in E \\mid q(x) = 0\\}\\).","hint":"Vecteurs orthogonaux"},
  {"id":"mp03-def-07","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"def","q":"Définir : Orthogonal d'une partie.","a":"Soit \\(F\\) un sous-espace de \\(E\\). L'orthogonal de \\(F\\) est : \\[\\]","hint":"Orthogonal d'une partie"},
  {"id":"mp03-prop-04","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"prop","q":"Énoncer la proposition : Propriétés de l'orthogonal.","a":"Soit \\(F, G\\) des sous-espaces de \\(E\\). On a : \\n- \\(F \\subset G \\Rightarrow G^{\\perp} \\subset F^{\\perp}\\). \\n- \\(\\ker(q) = E^{\\perp}\\). \\n- \\(\\dim(F) + \\dim(F^{\\perp}) = \\dim(E) + \\dim(F \\cap \\ker q)\\). \\n- \\((F + G)^{\\perp} = F^{\\perp} \\cap G^{\\perp}\\).","hint":"Propriétés l'orthogonal"},
  {"id":"mp03-def-08","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"def","q":"Définir : Forme non dégénérée.","a":"La forme bilinéaire \\(\\varphi\\) (ou la forme quadratique \\(q\\)) est dite non dégénérée si \\(\\ker(q) = \\{0\\}\\), c'est-à-dire : \\[\\]","hint":"Forme non dégénérée"},
  {"id":"mp03-thm-01","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"thm","q":"Énoncer le théorème : Supplémentaire orthogonal.","a":"Soit \\(\\varphi\\) une forme bilinéaire symétrique non dégénérée sur \\(E\\), et \\(F\\) un sous-espace de \\(E\\). Si la restriction \\(\\varphi|_{F \\times F}\\) est non dégénérée, alors : \\[\\]","hint":"Supplémentaire orthogonal"},
  {"id":"mp03-thm-02","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"thm","q":"Énoncer le théorème : Existence d'une base orthogonale.","a":"Toute forme quadratique \\(q\\) sur un \\(\\mathbb{K}\\)-espace vectoriel \\(E\\) de dimension finie admet une base orthogonale, c'est-à-dire une base \\(\\mathcal{B} = (e_1, \\ldots, e_n)\\) telle que : \\[\\]","hint":"Existence d'une base orthogonale"},
  {"id":"mp03-def-09","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"def","q":"Définir : Algorithme de Gauss.","a":"L'algorithme de Gauss (ou méthode de complétion du carré) permet de construire explicitement une base orthogonale. Le principe est de mettre \\(q\\) sous forme de somme de carrés par des opérations élémentaires successives : \\n- Cas 1 : s'il existe un terme \\(a_{ii} x_i^2\\) avec \\(a_{ii} \\neq 0\\), on regroupe tous les termes contenant \\(x_i\\) et on complète le carré.","hint":"Algorithme Gauss"},
  {"id":"mp03-thm-03","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"thm","q":"Énoncer le théorème : Inertie de Sylvester.","a":"Soit \\(q\\) une forme quadratique sur un \\(\\mathbb{R}\\)-espace vectoriel \\(E\\) de dimension \\(n\\). Si l'on écrit \\(q\\) sous forme réduite dans une base orthogonale : \\[\\]","hint":"Inertie Sylvester"},
  {"id":"mp03-def-10","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"def","q":"Définir : Formes définies et semi-définies.","a":"Soit \\(q\\) une forme quadratique réelle de signature \\((p, q')\\) sur \\(E\\) de dimension \\(n\\). On dit que \\(q\\) est : \\n- positive si \\(q(x) \\geq 0\\) pour tout \\(x \\in E\\), c'est-à-dire \\(q' = 0\\). \\n- définie positive si \\(q(x) > 0\\) pour tout \\(x \\neq 0\\), c'est-à-dire \\((p, q') = (n, 0)\\). \\n- négative si \\(q(x) \\leq 0\\) pour tout \\(x\\), c'est-à-dire \\(p = 0\\).","hint":"Formes définies semi-définies"},
  {"id":"mp03-prop-05","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"prop","q":"Énoncer la proposition : Classification par la signature.","a":"Sur \\(\\mathbb{R}\\), deux formes quadratiques de même dimension sont congruentes si et seulement si elles ont la même signature. Toute forme quadratique réelle de signature \\((p, q')\\) est congruente à : \\[\\]","hint":"Classification par signature"},
  {"id":"mp03-prop-06","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"prop","q":"Énoncer la proposition : Critère de Sylvester (mineurs principaux).","a":"Soit \\(M = (m_{ij}) \\in \\mathcal{S}_n(\\mathbb{R})\\) et \\(\\Delta_k = \\det(m_{ij})_{1 \\leq i,j \\leq k}\\) les mineurs principaux dominants. Alors : \\n- \\(q\\) est définie positive si et seulement si \\(\\Delta_k > 0\\) pour tout \\(k \\in \\{1, \\ldots, n\\}\\). \\n- \\(q\\) est définie négative si et seulement si \\((-1)^k \\Delta_k > 0\\) pour tout \\(k \\in \\{1, \\ldots, n\\}\\).","hint":"Critère Sylvester (mineurs principaux)"},
  {"id":"mp03-def-11","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"def","q":"Définir : Équation quadratique.","a":"Une équation quadratique dans \\(\\mathbb{R}^n\\) est une équation de la forme : \\[\\]","hint":"Équation quadratique"},
  {"id":"mp03-prop-07","ch":"mp-03","chName":"Formes bilinéaires et quadratiques","type":"prop","q":"Énoncer la proposition : Classification des coniques.","a":"Soit \\(q(x,y) = ax^2 + 2bxy + cy^2\\) la partie quadratique d'une conique. La nature de la conique (à isométrie et cas non dégénéré près) dépend de la signature de \\(q\\) : \\n- Signature \\((2, 0)\\) ou \\((0, 2)\\) : \\(q\\) est définie, la conique est une ellipse. \\n- Signature \\((1, 1)\\) : \\(q\\) est indéfinie, la conique est une hyperbole. \\n- Signature \\((1, 0)\\) ou \\((0, 1)\\) : \\(q\\) est dégénérée de rang 1, la conique est une parabole.","hint":"Classification des coniques"},
  {"id":"mp04-def-01","ch":"mp-04","chName":"Espaces euclidiens","type":"def","q":"Définir : Produit scalaire.","a":"On appelle produit scalaire sur \\(E\\) toute application \\(\\langle \\cdot, \\cdot \\rangle : E \\times E \\to \\mathbb{R}\\) vérifiant : \\n- Bilinéarité : \\(\\langle \\cdot, \\cdot \\rangle\\) est bilinéaire, c'est-à-dire linéaire en chaque variable. \\n- Symétrie : \\(\\forall\\, (x, y) \\in E^2,\\quad \\langle x, y \\rangle = \\langle y, x \\rangle\\). \\n- Définie positive : \\(\\forall\\, x \\in E,\\quad \\langle x, x \\rangle \\geqslant 0\\) et \\(\\langle x, x \\rangle = 0 \\Leftrightarrow x = 0_E\\).","hint":"Produit scalaire"},
  {"id":"mp04-def-02","ch":"mp-04","chName":"Espaces euclidiens","type":"def","q":"Définir : Espace euclidien.","a":"Un espace euclidien est un couple \\((E, \\langle \\cdot, \\cdot \\rangle)\\) où \\(E\\) est un \\(\\mathbb{R}\\)-espace vectoriel de dimension finie et \\(\\langle \\cdot, \\cdot \\rangle\\) est un produit scalaire sur \\(E\\).","hint":"Espace euclidien"},
  {"id":"mp04-def-03","ch":"mp-04","chName":"Espaces euclidiens","type":"def","q":"Définir : Norme euclidienne.","a":"Soit \\((E, \\langle \\cdot, \\cdot \\rangle)\\) un espace euclidien. On appelle norme euclidienne associée l'application : \\[\\]","hint":"Norme euclidienne"},
  {"id":"mp04-thm-01","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Inégalité de Cauchy-Schwarz.","a":"Pour tous \\(x, y \\in E\\) : \\[\\]","hint":"Inégalité Cauchy-Schwarz"},
  {"id":"mp04-prop-01","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Inégalité triangulaire.","a":"Pour tous \\(x, y \\in E\\) : \\[\\]","hint":"Inégalité triangulaire"},
  {"id":"mp04-def-04","ch":"mp-04","chName":"Espaces euclidiens","type":"def","q":"Définir : Angle entre deux vecteurs.","a":"Pour \\(x, y \\in E \\setminus \\{0\\}\\), l'inégalité de Cauchy-Schwarz garantit que \\(\\dfrac{\\langle x, y \\rangle}{\\|x\\| \\cdot \\|y\\|} \\in [-1, 1]\\). On appelle angle (non orienté) entre \\(x\\) et \\(y\\) l'unique \\(\\theta \\in [0, \\pi]\\) tel que : \\[\\]","hint":"Angle entre deux vecteurs"},
  {"id":"mp04-def-05","ch":"mp-04","chName":"Espaces euclidiens","type":"def","q":"Définir : Orthogonalité.","a":"Deux vecteurs \\(x, y \\in E\\) sont orthogonaux, noté \\(x \\perp y\\), si \\(\\langle x, y \\rangle = 0\\). Si \\(A \\subset E\\), on note \\(A^\\perp = \\{ x \\in E \\mid \\forall\\, a \\in A,\\ \\langle x, a \\rangle = 0 \\}\\) l'orthogonal de \\(A\\), qui est un sous-espace vectoriel de \\(E\\).","hint":"Orthogonalité"},
  {"id":"mp04-prop-02","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Propriétés de l'orthogonal.","a":"Soit \\(F\\) un sous-espace vectoriel de l'espace euclidien \\(E\\). Alors : \\n- \\(F^\\perp\\) est un sous-espace vectoriel de \\(E\\). \\n- \\(\\dim(F) + \\dim(F^\\perp) = \\dim(E)\\). \\n- \\(E = F \\oplus F^\\perp\\). \\n- \\((F^\\perp)^\\perp = F\\).","hint":"Propriétés l'orthogonal"},
  {"id":"mp04-thm-02","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Identité de Pythagore.","a":"Si \\(x \\perp y\\), alors \\(\\|x + y\\|^2 = \\|x\\|^2 + \\|y\\|^2\\). Plus généralement, si \\(x_1, \\ldots, x_p\\) sont deux à deux orthogonaux : \\[\\]","hint":"Identité Pythagore"},
  {"id":"mp04-def-06","ch":"mp-04","chName":"Espaces euclidiens","type":"def","q":"Définir : Famille orthonormée, base orthonormée (BON).","a":"Une famille \\((e_1, \\ldots, e_p)\\) de \\(E\\) est dite orthonormée (ou orthonormale) si : \\[\\]","hint":"Famille orthonormée, base orthonormée..."},
  {"id":"mp04-prop-03","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Coordonnées dans une BON.","a":"Si \\(\\mathcal{B} = (e_1, \\ldots, e_n)\\) est une BON de \\(E\\) et \\(x \\in E\\), alors : \\[\\]","hint":"Coordonnées dans une BON"},
  {"id":"mp04-thm-03","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Procédé d'orthonormalisation de Gram-Schmidt.","a":"Soit \\((v_1, \\ldots, v_p)\\) une famille libre de \\(E\\). Il existe une unique famille orthonormée \\((e_1, \\ldots, e_p)\\) telle que : \\n- Pour tout \\(k \\in \\{1, \\ldots, p\\}\\), \\(\\mathrm{Vect}(e_1, \\ldots, e_k) = \\mathrm{Vect}(v_1, \\ldots, v_k)\\). \\n- Pour tout \\(k\\), \\(\\langle e_k, v_k \\rangle > 0\\). Les vecteurs se construisent par récurrence : \\[\\]","hint":"Procédé d'orthonormalisation Gram-Schmidt"},
  {"id":"mp04-thm-04","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Existence de BON.","a":"Tout espace euclidien admet une base orthonormée. Plus précisément, toute famille orthonormée peut être complétée en une BON de \\(E\\).","hint":"Existence BON"},
  {"id":"mp04-def-07","ch":"mp-04","chName":"Espaces euclidiens","type":"def","q":"Définir : Matrice orthogonale.","a":"Une matrice \\(P \\in \\mathcal{M}_n(\\mathbb{R})\\) est dite orthogonale si \\(P^\\top P = I_n\\), c'est-à-dire \\(P^{-1} = P^\\top\\). On note \\(\\mathrm{O}_n(\\mathbb{R})\\) l'ensemble des matrices orthogonales.","hint":"Matrice orthogonale"},
  {"id":"mp04-prop-04","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Caractérisation des matrices orthogonales.","a":"Pour \\(P \\in \\mathcal{M}_n(\\mathbb{R})\\), les assertions suivantes sont équivalentes : \\n- \\(P\\) est orthogonale. \\n- Les colonnes de \\(P\\) forment une BON de \\(\\mathbb{R}^n\\) (pour le produit scalaire canonique). \\n- Les lignes de \\(P\\) forment une BON de \\(\\mathbb{R}^n\\). \\n- \\(P\\) est la matrice de passage entre deux BON.","hint":"Caractérisation des matrices orthogonales"},
  {"id":"mp04-thm-05","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Projection orthogonale.","a":"Soit \\(F\\) un sous-espace vectoriel de l'espace euclidien \\(E\\). Alors \\(E = F \\oplus F^\\perp\\). La projection sur \\(F\\) parallèlement à \\(F^\\perp\\) est appelée projection orthogonale sur \\(F\\), notée \\(p_F\\). Pour tout \\(x \\in E\\), \\(p_F(x)\\) est l'unique vecteur de \\(F\\) tel que \\(x - p_F(x) \\in F^\\perp\\).","hint":"Projection orthogonale"},
  {"id":"mp04-prop-05","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Expression de la projection orthogonale.","a":"Si \\((e_1, \\ldots, e_r)\\) est une BON de \\(F\\), alors pour tout \\(x \\in E\\) : \\[\\]","hint":"Expression projection orthogonale"},
  {"id":"mp04-prop-06","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Caractérisation variationnelle.","a":"Le projeté orthogonal \\(p_F(x)\\) est l'unique élément de \\(F\\) qui minimise la distance de \\(x\\) à \\(F\\) : \\[\\]","hint":"Caractérisation variationnelle"},
  {"id":"mp04-def-08","ch":"mp-04","chName":"Espaces euclidiens","type":"def","q":"Définir : Distance à un sous-espace.","a":"La distance d'un vecteur \\(x \\in E\\) à un sous-espace \\(F\\) est : \\[\\]","hint":"Distance sous-espace"},
  {"id":"mp04-thm-06","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Adjoint.","a":"Soit \\(u \\in \\mathcal{L}(E)\\). Il existe un unique endomorphisme \\(u^* \\in \\mathcal{L}(E)\\), appelé adjoint de \\(u\\), tel que : \\[\\]","hint":"Adjoint"},
  {"id":"mp04-prop-07","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Matrice de l'adjoint dans une BON.","a":"Soit \\(\\mathcal{B}\\) une BON de \\(E\\) et \\(A = \\mathrm{Mat}_\\mathcal{B}(u)\\). Alors : \\[\\]","hint":"Matrice l'adjoint dans une..."},
  {"id":"mp04-prop-08","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Propriétés de l'adjoint.","a":"Soient \\(u, v \\in \\mathcal{L}(E)\\) et \\(\\lambda \\in \\mathbb{R}\\). On a : \\n- \\((u + v)^* = u^* + v^*\\) et \\((\\lambda u)^* = \\lambda u^*\\). \\n- \\((u \\circ v)^* = v^* \\circ u^*\\). \\n- \\((u^*)^* = u\\). \\n- \\(u\\) est inversible si et seulement si \\(u^*\\) l'est, et alors \\((u^{-1})^* = (u^*)^{-1}\\).","hint":"Propriétés l'adjoint"},
  {"id":"mp04-thm-07","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Noyau et image de l'adjoint.","a":"Pour tout \\(u \\in \\mathcal{L}(E)\\) : \\[\\]","hint":"Noyau image l'adjoint"},
  {"id":"mp04-def-09","ch":"mp-04","chName":"Espaces euclidiens","type":"def","q":"Définir : Endomorphisme symétrique (autoadjoint).","a":"Un endomorphisme \\(u \\in \\mathcal{L}(E)\\) est dit symétrique (ou autoadjoint) si \\(u^* = u\\), c'est-à-dire : \\[\\]","hint":"Endomorphisme symétrique (autoadjoint)"},
  {"id":"mp04-prop-09","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Caractérisation matricielle.","a":"\\(u \\in \\mathcal{L}(E)\\) est symétrique si et seulement si sa matrice dans toute BON est symétrique (i.e. \\(A = A^\\top\\)). On note \\(\\mathcal{S}_n(\\mathbb{R})\\) l'ensemble des matrices symétriques réelles.","hint":"Caractérisation matricielle"},
  {"id":"mp04-thm-08","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Valeurs propres d'un endomorphisme symétrique.","a":"Si \\(u\\) est un endomorphisme symétrique d'un espace euclidien \\(E\\), alors toutes les valeurs propres de \\(u\\) sont réelles.","hint":"Valeurs propres d'un endomorphisme..."},
  {"id":"mp04-thm-09","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Orthogonalité des espaces propres.","a":"Soit \\(u\\) un endomorphisme symétrique de \\(E\\). Si \\(\\lambda\\) et \\(\\mu\\) sont deux valeurs propres distinctes de \\(u\\), alors les espaces propres \\(E_\\lambda\\) et \\(E_\\mu\\) sont orthogonaux : \\[\\]","hint":"Orthogonalité des espaces propres"},
  {"id":"mp04-thm-10","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : spectral.","a":"Soit \\(u\\) un endomorphisme symétrique d'un espace euclidien \\(E\\) de dimension \\(n\\). Alors : \\n- \\(u\\) est diagonalisable. \\n- Il existe une base orthonormée de \\(E\\) formée de vecteurs propres de \\(u\\). Autrement dit, il existe \\(P \\in \\mathrm{O}_n(\\mathbb{R})\\) et \\(D = \\mathrm{diag}(\\lambda_1, \\ldots, \\lambda_n)\\) avec \\(\\lambda_i \\in \\mathbb{R}\\) tels que : \\[\\]","hint":"spectral"},
  {"id":"mp04-def-10","ch":"mp-04","chName":"Espaces euclidiens","type":"def","q":"Définir : Isométrie (automorphisme orthogonal).","a":"Un endomorphisme \\(u \\in \\mathcal{L}(E)\\) est une isométrie (ou automorphisme orthogonal) si : \\[\\]","hint":"Isométrie (automorphisme orthogonal)"},
  {"id":"mp04-prop-10","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Caractérisations des isométries.","a":"Pour \\(u \\in \\mathcal{L}(E)\\), les assertions suivantes sont équivalentes : \\n- \\(u\\) est une isométrie : \\(\\forall\\, x \\in E,\\ \\|u(x)\\| = \\|x\\|\\). \\n- \\(u\\) conserve le produit scalaire : \\(\\forall\\, (x,y) \\in E^2,\\ \\langle u(x), u(y) \\rangle = \\langle x, y \\rangle\\). \\n- \\(u^* \\circ u = \\mathrm{Id}_E\\). \\n- \\(u\\) transforme toute BON en une BON. \\n- La matrice de \\(u\\) dans toute BON est orthogonale.","hint":"Caractérisations des isométries"},
  {"id":"mp04-prop-11","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Groupe orthogonal \\(\\mathrm{O}_n(\\mathbb{R})\\).","a":"L'ensemble \\(\\mathrm{O}_n(\\mathbb{R}) = \\{ M \\in \\mathrm{GL}_n(\\mathbb{R}) \\mid M^\\top M = I_n \\}\\) est un sous-groupe de \\(\\mathrm{GL}_n(\\mathbb{R})\\). Pour toute \\(M \\in \\mathrm{O}_n(\\mathbb{R})\\), \\(\\det(M) = \\pm 1\\). Le sous-ensemble \\(\\mathrm{SO}_n(\\mathbb{R}) = \\{ M \\in \\mathrm{O}_n(\\mathbb{R}) \\mid \\det(M) = 1 \\}\\) est un sous-groupe appelé groupe spécial orthogonal.","hint":"Groupe orthogonal mathrm{O}_n(mathbb{R})"},
  {"id":"mp04-prop-12","ch":"mp-04","chName":"Espaces euclidiens","type":"prop","q":"Énoncer la proposition : Valeurs propres d'une isométrie.","a":"Les seules valeurs propres possibles d'une isométrie sont \\(+1\\) et \\(-1\\).","hint":"Valeurs propres d'une isométrie"},
  {"id":"mp04-thm-11","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Classification en dimension 2.","a":"Soit \\(u\\) une isométrie d'un plan euclidien orienté \\(E\\). Dans une BON directe : Si \\(\\det(u) = 1\\), alors \\(u\\) est une rotation d'angle \\(\\theta \\in [0, 2\\pi[\\) et sa matrice est : \\[\\]","hint":"Classification dimension"},
  {"id":"mp04-thm-12","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Réduction des isométries en dimension 3.","a":"Soit \\(u\\) une isométrie d'un espace euclidien orienté \\(E\\) de dimension 3. Si \\(\\det(u) = 1\\) (rotation), alors il existe une BON directe dans laquelle la matrice de \\(u\\) est : \\[\\]","hint":"Réduction des isométries dimension"},
  {"id":"mp04-thm-13","ch":"mp-04","chName":"Espaces euclidiens","type":"thm","q":"Énoncer le théorème : Décomposition en réflexions.","a":"Toute isométrie d'un espace euclidien de dimension \\(n\\) est la composée d'au plus \\(n\\) réflexions (symétries orthogonales par rapport à des hyperplans).","hint":"Décomposition réflexions"},
  {"id":"mp05-def-01","ch":"mp-05","chName":"Endomorphismes remarquables","type":"def","q":"Définir : Endomorphisme autoadjoint (symétrique).","a":"Un endomorphisme \\(u \\in \\mathcal{L}(E)\\) est dit autoadjoint (ou symétrique dans le cas réel) si \\(u = u^*\\), c'est-à-dire : \\[\\]","hint":"Endomorphisme autoadjoint (symétrique)"},
  {"id":"mp05-prop-01","ch":"mp-05","chName":"Endomorphismes remarquables","type":"prop","q":"Énoncer la proposition : Propriétés élémentaires.","a":"Soit \\(u \\in \\mathcal{S}(E)\\). Alors : \\n- \\(\\mathcal{S}(E)\\) est un sous-espace vectoriel de \\(\\mathcal{L}(E)\\) de dimension \\(\\frac{n(n+1)}{2}\\) (cas réel). \\n- \\(\\ker(u) = \\mathrm{Im}(u)^\\perp\\) et \\(\\mathrm{Im}(u) = \\ker(u)^\\perp\\). \\n- Les sous-espaces propres de \\(u\\) sont deux à deux orthogonaux.","hint":"Propriétés élémentaires"},
  {"id":"mp05-thm-01","ch":"mp-05","chName":"Endomorphismes remarquables","type":"thm","q":"Énoncer le théorème : Cas réel.","a":"Soit \\(u \\in \\mathcal{S}(E)\\) un endomorphisme autoadjoint d'un espace euclidien \\(E\\). Alors : \\n- Toutes les valeurs propres de \\(u\\) sont réelles. \\n- Il existe une base orthonormée de \\(E\\) constituée de vecteurs propres de \\(u\\). Autrement dit, \\(u\\) est diagonalisable dans une base orthonormée, ou encore : toute matrice symétrique réelle est diagonalisable dans \\(\\mathrm{O}_n(\\mathbb{R})\\).","hint":"Cas réel"},
  {"id":"mp05-prop-02","ch":"mp-05","chName":"Endomorphismes remarquables","type":"prop","q":"Énoncer la proposition : Caractérisation par les matrices symétriques.","a":"Soit \\(A \\in \\mathcal{M}_n(\\mathbb{R})\\). Les conditions suivantes sont équivalentes : \\n- \\(A \\in \\mathcal{S}_n(\\mathbb{R})\\) (i.e. \\(A = {}^t\\!A\\)). \\n- Il existe \\(P \\in \\mathrm{O}_n(\\mathbb{R})\\) et \\(D = \\mathrm{diag}(\\lambda_1, \\ldots, \\lambda_n)\\) telles que \\(A = P D\\, {}^t\\!P\\). \\n- La forme bilinéaire associée est symétrique et la forme quadratique \\(q(x) = {}^t\\!x\\, A\\, x\\) détermine \\(A\\).","hint":"Caractérisation par les matrices..."},
  {"id":"mp05-def-02","ch":"mp-05","chName":"Endomorphismes remarquables","type":"def","q":"Définir : Endomorphisme symétrique positif.","a":"Un endomorphisme autoadjoint \\(u \\in \\mathcal{S}(E)\\) est dit : \\n- Positif si \\(\\forall\\, x \\in E,\\; \\langle u(x), x \\rangle \\geq 0\\), c'est-à-dire si toutes ses valeurs propres sont positives ou nulles. \\n- Défini positif si \\(\\forall\\, x \\neq 0,\\; \\langle u(x), x \\rangle > 0\\), c'est-à-dire si toutes ses valeurs propres sont strictement positives.","hint":"Endomorphisme symétrique positif"},
  {"id":"mp05-prop-03","ch":"mp-05","chName":"Endomorphismes remarquables","type":"prop","q":"Énoncer la proposition : Racine carrée d'un endomorphisme symétrique positif.","a":"Soit \\(u \\in \\mathcal{S}(E)\\) positif. Il existe un unique endomorphisme \\(v \\in \\mathcal{S}(E)\\) positif tel que \\(v^2 = u\\). On note \\(v = \\sqrt{u}\\) ou \\(v = u^{1/2}\\). \\[\\]","hint":"Racine carrée d'un endomorphisme..."},
  {"id":"mp05-def-03","ch":"mp-05","chName":"Endomorphismes remarquables","type":"def","q":"Définir : Endomorphisme normal.","a":"Un endomorphisme \\(u \\in \\mathcal{L}(E)\\) est dit normal s'il commute avec son adjoint : \\[\\]","hint":"Endomorphisme normal"},
  {"id":"mp05-prop-04","ch":"mp-05","chName":"Endomorphismes remarquables","type":"prop","q":"Énoncer la proposition : Propriétés des endomorphismes normaux.","a":"Soit \\(u\\) un endomorphisme normal sur \\(E\\). Alors : \\n- \\(\\ker(u) = \\ker(u^*)\\) et \\(\\mathrm{Im}(u) = \\mathrm{Im}(u^*)\\). \\n- \\(\\forall\\, x \\in E,\\; \\|u(x)\\| = \\|u^*(x)\\|\\). \\n- Si \\(\\lambda\\) est valeur propre de \\(u\\), alors \\(\\overline{\\lambda}\\) est valeur propre de \\(u^*\\) avec le même espace propre. \\n- Les sous-espaces propres de \\(u\\) sont deux à deux orthogonaux.","hint":"Propriétés des endomorphismes normaux"},
  {"id":"mp05-thm-02","ch":"mp-05","chName":"Endomorphismes remarquables","type":"thm","q":"Énoncer le théorème : Endomorphismes normaux sur \\(\\mathbb{C}\\).","a":"Soit \\(u\\) un endomorphisme normal sur \\(E\\). Alors : \\n- \\(\\ker(u) = \\ker(u^*)\\) et \\(\\mathrm{Im}(u) = \\mathrm{Im}(u^*)\\). \\n- \\(\\forall\\, x \\in E,\\; \\|u(x)\\| = \\|u^*(x)\\|\\). \\n- Si \\(\\lambda\\) est valeur propre de \\(u\\), alors \\(\\overline{\\lambda}\\) est valeur propre de \\(u^*\\) avec le même espace propre. \\n- Les sous-espaces propres de \\(u\\) sont deux à deux orthogonaux.","hint":"Endomorphismes normaux sur mathbb{C}"},
  {"id":"mp05-prop-05","ch":"mp-05","chName":"Endomorphismes remarquables","type":"prop","q":"Énoncer la proposition : Endomorphismes normaux sur \\(\\mathbb{R}\\).","a":"Soit \\(u\\) un endomorphisme normal sur \\(E\\). Alors : \\n- \\(\\ker(u) = \\ker(u^*)\\) et \\(\\mathrm{Im}(u) = \\mathrm{Im}(u^*)\\). \\n- \\(\\forall\\, x \\in E,\\; \\|u(x)\\| = \\|u^*(x)\\|\\). \\n- Si \\(\\lambda\\) est valeur propre de \\(u\\), alors \\(\\overline{\\lambda}\\) est valeur propre de \\(u^*\\) avec le même espace propre. \\n- Les sous-espaces propres de \\(u\\) sont deux à deux orthogonaux.","hint":"Endomorphismes normaux sur mathbb{R}"},
  {"id":"mp05-def-04","ch":"mp-05","chName":"Endomorphismes remarquables","type":"def","q":"Définir : Endomorphisme unitaire / orthogonal.","a":"Un endomorphisme \\(u \\in \\mathcal{L}(E)\\) est dit unitaire (cas hermitien) ou orthogonal (cas euclidien) s'il vérifie l'une des conditions équivalentes : \\n- \\(u^* \\circ u = \\mathrm{Id}_E\\) (i.e. \\(u^* = u^{-1}\\)). \\n- \\(u\\) conserve le produit scalaire : \\(\\forall\\, x, y,\\; \\langle u(x), u(y) \\rangle = \\langle x, y \\rangle\\). \\n- \\(u\\) conserve la norme : \\(\\forall\\, x,\\; \\|u(x)\\| = \\|x\\|\\) (isométrie vectorielle). \\n- \\(u\\) transforme toute BON en une BON.","hint":"Endomorphisme unitaire orthogonal"},
  {"id":"mp05-prop-06","ch":"mp-05","chName":"Endomorphismes remarquables","type":"prop","q":"Énoncer la proposition : Spectre d'un endomorphisme unitaire.","a":"Soit \\(u\\) un endomorphisme unitaire (ou orthogonal). Alors : \\n- Les valeurs propres de \\(u\\) sont de module 1 : \\(|\\lambda| = 1\\). \\n- \\(|\\det(u)| = 1\\). \\n- Les sous-espaces propres sont deux à deux orthogonaux.","hint":"Spectre d'un endomorphisme unitaire"},
  {"id":"mp05-def-05","ch":"mp-05","chName":"Endomorphismes remarquables","type":"def","q":"Définir : \\(\\mathrm{O}(E)\\) et \\(\\mathrm{SO}(E)\\).","a":"Le groupe orthogonal de \\(E\\) est \\(\\mathrm{O}(E) = \\{u \\in \\mathcal{L}(E) \\mid u^* u = \\mathrm{Id}_E\\}\\). C'est un sous-groupe de \\(\\mathrm{GL}(E)\\). Le groupe spécial orthogonal est \\(\\mathrm{SO}(E) = \\{u \\in \\mathrm{O}(E) \\mid \\det(u) = 1\\}\\), sous-groupe distingué de \\(\\mathrm{O}(E)\\) d'indice 2. Matriciellement : \\(\\mathrm{O}_n(\\mathbb{R}) = \\{M \\in \\mathrm{GL}_n(\\mathbb{R}) \\mid {}^t\\!M\\, M = I_n\\}\\) et \\(\\mathrm{SO}_n(\\mathbb{R}) = \\mathrm{O}_n(\\mathbb{R}) \\cap \\mathrm{SL}_n(\\mathbb{R})\\).","hint":"mathrm{O}(E) mathrm{SO}(E)"},
  {"id":"mp05-thm-03","ch":"mp-05","chName":"Endomorphismes remarquables","type":"thm","q":"Énoncer le théorème : Structure des isométries en dimension 2.","a":"Soit \\(E\\) un plan euclidien orienté. \\n- Rotations : \\(\\mathrm{SO}(E) = \\{r_\\theta \\mid \\theta \\in \\mathbb{R}\\}\\). Dans toute BON directe, la matrice de \\(r_\\theta\\) est \\(\\begin{pmatrix} \\cos\\theta & -\\sin\\theta \\\\ \\sin\\theta & \\cos\\theta \\end{pmatrix}\\). \\n- Réflexions : les éléments de \\(\\mathrm{O}(E) \\setminus \\mathrm{SO}(E)\\) sont les réflexions (symétries orthogonales par rapport à une droite), de déterminant \\(-1\\).","hint":"Structure des isométries dimension"},
  {"id":"mp05-thm-04","ch":"mp-05","chName":"Endomorphismes remarquables","type":"thm","q":"Énoncer le théorème : Structure des isométries en dimension 3.","a":"Soit \\(u \\in \\mathrm{O}(E)\\) avec \\(\\dim(E) = 3\\). \\n- Si \\(\\det(u) = 1\\) : \\(u\\) est une rotation d'axe \\(\\ker(u - \\mathrm{Id})\\) (droite) et d'angle \\(\\theta\\), avec \\(\\mathrm{tr}(u) = 1 + 2\\cos\\theta\\). \\n- Si \\(\\det(u) = -1\\) : soit \\(u = -\\mathrm{Id}\\) (symétrie centrale), soit \\(u\\) est le composé d'une rotation d'axe \\(D\\) et de la réflexion par rapport au plan \\(D^\\perp\\).","hint":"Structure des isométries dimension"},
  {"id":"mp05-prop-07","ch":"mp-05","chName":"Endomorphismes remarquables","type":"prop","q":"Énoncer la proposition : Réduction des isométries en dimension quelconque.","a":"Soit \\(u \\in \\mathrm{O}(E)\\). Il existe une base orthonormée de \\(E\\) dans laquelle la matrice de \\(u\\) est diagonale par blocs : \\[\\]","hint":"Réduction des isométries dimension..."},
  {"id":"mp05-def-06","ch":"mp-05","chName":"Endomorphismes remarquables","type":"def","q":"Définir : Endomorphisme antisymétrique (anti-autoadjoint).","a":"Un endomorphisme \\(u \\in \\mathcal{L}(E)\\) est dit antisymétrique (ou anti-autoadjoint) si \\(u^* = -u\\), c'est-à-dire : \\[\\]","hint":"Endomorphisme antisymétrique (anti-autoadjoint)"},
  {"id":"mp05-prop-08","ch":"mp-05","chName":"Endomorphismes remarquables","type":"prop","q":"Énoncer la proposition : Propriétés spectrales.","a":"Soit \\(u \\in \\mathcal{A}(E)\\) un endomorphisme antisymétrique d'un espace euclidien \\(E\\). Alors : \\n- Le spectre complexe de \\(u\\) est purement imaginaire : \\(\\mathrm{Sp}_{\\mathbb{C}}(u) \\subset i\\mathbb{R}\\). \\n- En particulier, \\(0\\) est la seule valeur propre réelle possible. \\n- Si \\(n = \\dim(E)\\) est impair, alors \\(u\\) n'est pas inversible (car \\(0 \\in \\mathrm{Sp}(u)\\)). \\n- \\(\\det(u) \\geq 0\\), avec égalité si et seulement si \\(u\\) est non inversible.","hint":"Propriétés spectrales"},
  {"id":"mp05-prop-09","ch":"mp-05","chName":"Endomorphismes remarquables","type":"prop","q":"Énoncer la proposition : Réduction des endomorphismes antisymétriques.","a":"Soit \\(u \\in \\mathcal{A}(E)\\). Il existe une base orthonormée de \\(E\\) dans laquelle la matrice de \\(u\\) est de la forme : \\[\\]","hint":"Réduction des endomorphismes antisymétriques"},
  {"id":"mp05-thm-05","ch":"mp-05","chName":"Endomorphismes remarquables","type":"thm","q":"Énoncer le théorème : Exponentielle d'un endomorphisme antisymétrique.","a":"Soit \\(u \\in \\mathcal{A}(E)\\). Alors \\(\\exp(u) \\in \\mathrm{SO}(E)\\). De plus, l'application : \\[\\]","hint":"Exponentielle d'un endomorphisme antisymétrique"},
  {"id":"mp05-thm-06","ch":"mp-05","chName":"Endomorphismes remarquables","type":"thm","q":"Énoncer le théorème : Décomposition polaire.","a":"Soit \\(A \\in \\mathrm{GL}_n(\\mathbb{R})\\). Il existe un unique couple \\((O, S) \\in \\mathrm{O}_n(\\mathbb{R}) \\times \\mathcal{S}_n^{++}(\\mathbb{R})\\) tel que : \\[\\]","hint":"Décomposition polaire"},
  {"id":"mp05-prop-10","ch":"mp-05","chName":"Endomorphismes remarquables","type":"prop","q":"Énoncer la proposition : Extension aux matrices non inversibles.","a":"Soit \\(A \\in \\mathcal{M}_n(\\mathbb{R})\\) quelconque (pas nécessairement inversible). Alors il existe \\(O \\in \\mathrm{O}_n(\\mathbb{R})\\) et \\(S \\in \\mathcal{S}_n^+(\\mathbb{R})\\) tels que \\(A = O S\\). La partie symétrique positive \\(S = \\sqrt{{}^t\\!A\\, A}\\) est unique, mais \\(O\\) n'est plus nécessairement unique si \\(A\\) est singulière.","hint":"Extension aux matrices non..."},
  {"id":"mp05-def-07","ch":"mp-05","chName":"Endomorphismes remarquables","type":"def","q":"Définir : Valeurs singulières.","a":"Les valeurs singulières de \\(A \\in \\mathcal{M}_n(\\mathbb{R})\\) sont les valeurs propres de \\(S = \\sqrt{{}^t\\!A\\, A}\\), c'est-à-dire les racines carrées des valeurs propres de \\({}^t\\!A\\, A\\). On les note \\(\\sigma_1 \\geq \\sigma_2 \\geq \\cdots \\geq \\sigma_n \\geq 0\\). Ce sont aussi les longueurs des demi-axes de l'image de la sphère unité par \\(A\\). On a \\(\\|A\\| = \\sigma_1\\) (norme d'opérateur) et \\(|\\det(A)| = \\prod \\sigma_i\\).","hint":"Valeurs singulières"},
  {"id":"mp05-thm-07","ch":"mp-05","chName":"Endomorphismes remarquables","type":"thm","q":"Énoncer le théorème : Décomposition de Schur.","a":"Soit \\(A \\in \\mathcal{M}_n(\\mathbb{C})\\). Il existe une matrice unitaire \\(U \\in \\mathcal{U}_n(\\mathbb{C})\\) et une matrice triangulaire supérieure \\(T\\) telles que : \\[\\]","hint":"Décomposition Schur"},
  {"id":"mp05-thm-08","ch":"mp-05","chName":"Endomorphismes remarquables","type":"thm","q":"Énoncer le théorème : Inégalité de Hadamard.","a":"Soit \\(A = (c_1 \\mid c_2 \\mid \\cdots \\mid c_n) \\in \\mathcal{M}_n(\\mathbb{R})\\) dont les colonnes sont \\(c_1, \\ldots, c_n \\in \\mathbb{R}^n\\). Alors : \\[\\]","hint":"Inégalité Hadamard"},
  {"id":"mp05-def-08","ch":"mp-05","chName":"Endomorphismes remarquables","type":"def","q":"Définir : Quotient de Rayleigh.","a":"Soit \\(A \\in \\mathcal{S}_n(\\mathbb{R})\\). Le quotient de Rayleigh de \\(A\\) est la fonction : \\[\\]","hint":"Quotient Rayleigh"},
  {"id":"mp05-thm-09","ch":"mp-05","chName":"Endomorphismes remarquables","type":"thm","q":"Énoncer le théorème : Min-max de Courant-Fischer.","a":"Soit \\(A \\in \\mathcal{S}_n(\\mathbb{R})\\) de valeurs propres \\(\\lambda_1 \\leq \\lambda_2 \\leq \\cdots \\leq \\lambda_n\\). Alors : \\[\\]","hint":"Min-max Courant-Fischer"},
  {"id":"mp05-prop-11","ch":"mp-05","chName":"Endomorphismes remarquables","type":"prop","q":"Énoncer la proposition : Applications du quotient de Rayleigh.","a":"Le quotient de Rayleigh permet de : \\n- Encadrer les valeurs propres : pour tout \\(x \\neq 0\\), \\(\\lambda_1 \\leq R_A(x) \\leq \\lambda_n\\). Toute estimation de \\(R_A\\) donne un encadrement des valeurs propres extrêmes. \\n- Caractériser la positivité : \\(A \\in \\mathcal{S}_n^+(\\mathbb{R})\\) si et seulement si \\(R_A(x) \\geq 0\\) pour tout \\(x\\). \\n- Étudier la monotonie : si \\(A \\preceq B\\) (au sens de Loewner, i.","hint":"Applications quotient Rayleigh"},
  {"id":"mp06-def-01","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Norme.","a":"Une norme sur \\(E\\) est une application \\(N : E \\to \\mathbb{R}^+\\) vérifiant : \\n- Séparation : \\(N(x) = 0 \\iff x = 0_E\\). \\n- Homogénéité : \\(\\forall\\, \\lambda \\in \\mathbb{K},\\; \\forall\\, x \\in E,\\; N(\\lambda x) = |\\lambda|\\, N(x)\\). \\n- Inégalité triangulaire : \\(\\forall\\, x, y \\in E,\\; N(x + y) \\leq N(x) + N(y)\\). Le couple \\((E, N)\\) est alors appelé espace vectoriel normé (EVN). On note souvent \\(\\|x\\|\\) au lieu de \\(N(x)\\).","hint":"Norme"},
  {"id":"mp06-prop-01","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"prop","q":"Énoncer la proposition : Inégalité triangulaire inverse.","a":"Pour tout \\(x, y \\in E\\) : \\[\\]","hint":"Inégalité triangulaire inverse"},
  {"id":"mp06-def-02","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Distance associée, boules.","a":"Toute norme \\(\\|\\cdot\\|\\) sur \\(E\\) induit une distance \\(d(x, y) = \\|x - y\\|\\). On définit alors : \\n- Boule ouverte : \\(B(a, r) = \\{x \\in E \\mid \\|x - a\\| < r\\}\\). \\n- Boule fermée : \\(\\overline{B}(a, r) = \\{x \\in E \\mid \\|x - a\\| \\leq r\\}\\). \\n- Sphère : \\(S(a, r) = \\{x \\in E \\mid \\|x - a\\| = r\\}\\). où \\(a \\in E\\) et \\(r > 0\\).","hint":"Distance associée, boules"},
  {"id":"mp06-def-03","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Normes équivalentes.","a":"Deux normes \\(N_1\\) et \\(N_2\\) sur \\(E\\) sont dites équivalentes s'il existe des constantes \\(\\alpha, \\beta > 0\\) telles que : \\[\\]","hint":"Normes équivalentes"},
  {"id":"mp06-prop-02","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"prop","q":"Énoncer la proposition : Normes équivalentes et topologie.","a":"Deux normes équivalentes définissent les mêmes ouverts, les mêmes fermés, les mêmes suites convergentes et les mêmes suites de Cauchy. Autrement dit, elles définissent la même topologie.","hint":"Normes équivalentes topologie"},
  {"id":"mp06-thm-01","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"thm","q":"Énoncer le théorème : Équivalence des normes en dimension finie.","a":"Sur un espace vectoriel de dimension finie, toutes les normes sont équivalentes.","hint":"Équivalence des normes dimension..."},
  {"id":"mp06-def-04","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Ouvert.","a":"Une partie \\(U \\subset E\\) est dite ouverte si pour tout \\(a \\in U\\), il existe \\(r > 0\\) tel que \\(B(a, r) \\subset U\\). Autrement dit, tout point de \\(U\\) est « entouré » par une boule ouverte contenue dans \\(U\\).","hint":"Ouvert"},
  {"id":"mp06-def-05","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Fermé.","a":"Une partie \\(F \\subset E\\) est dite fermée si son complémentaire \\(E \\setminus F\\) est ouvert. De manière équivalente, \\(F\\) est fermée si et seulement si toute suite d'éléments de \\(F\\) qui converge dans \\(E\\) a sa limite dans \\(F\\).","hint":"Fermé"},
  {"id":"mp06-prop-03","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"prop","q":"Énoncer la proposition : Propriétés des ouverts et fermés.","a":"\\n- \\(\\emptyset\\) et \\(E\\) sont à la fois ouverts et fermés. \\n- Toute union (même infinie) d'ouverts est un ouvert. \\n- Toute intersection finie d'ouverts est un ouvert. \\n- Toute intersection (même infinie) de fermés est un fermé. \\n- Toute union finie de fermés est un fermé.","hint":"Propriétés des ouverts fermés"},
  {"id":"mp06-def-06","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Intérieur, adhérence, frontière.","a":"Soit \\(A \\subset E\\). \\n- L'intérieur de \\(A\\), noté \\(\\mathring{A}\\), est le plus grand ouvert contenu dans \\(A\\). Un point \\(a \\in \\mathring{A}\\) ssi \\(\\exists\\, r > 0,\\; B(a, r) \\subset A\\). \\n- L'adhérence de \\(A\\), notée \\(\\overline{A}\\), est le plus petit fermé contenant \\(A\\). Un point \\(a \\in \\overline{A}\\) ssi toute boule \\(B(a, r)\\) rencontre \\(A\\). \\n- La frontière de \\(A\\) est \\(\\partial A = \\overline{A} \\setminus \\mathring{A}\\).","hint":"Intérieur, adhérence, frontière"},
  {"id":"mp06-prop-04","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"prop","q":"Énoncer la proposition : Caractérisation séquentielle de l'adhérence.","a":"Un point \\(a \\in \\overline{A}\\) si et seulement s'il existe une suite \\((a_n)\\) d'éléments de \\(A\\) telle que \\(a_n \\to a\\).","hint":"Caractérisation séquentielle l'adhérence"},
  {"id":"mp06-def-07","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Partie dense.","a":"Une partie \\(A \\subset E\\) est dite dense dans \\(E\\) si \\(\\overline{A} = E\\), c'est-à-dire si tout élément de \\(E\\) est limite d'une suite d'éléments de \\(A\\).","hint":"Partie dense"},
  {"id":"mp06-def-08","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Convergence.","a":"Soit \\((x_n)\\) une suite d'éléments de \\((E, \\|\\cdot\\|)\\). On dit que \\((x_n)\\) converge vers \\(\\ell \\in E\\) si : \\[\\]","hint":"Convergence"},
  {"id":"mp06-prop-05","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"prop","q":"Énoncer la proposition : Convergence par coordonnées.","a":"Si \\(E = \\mathbb{K}^n\\) muni d'une norme quelconque, une suite \\((x_k)_{k \\geq 0}\\) converge si et seulement si chaque suite de coordonnées converge. Plus précisément, en notant \\(x_k = (x_k^{(1)}, \\ldots, x_k^{(n)})\\) : \\[\\]","hint":"Convergence par coordonnées"},
  {"id":"mp06-def-09","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Suite de Cauchy.","a":"Une suite \\((x_n)\\) de \\(E\\) est dite de Cauchy si : \\[\\]","hint":"Suite Cauchy"},
  {"id":"mp06-prop-06","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"prop","q":"Énoncer la proposition : Suite convergente implique Cauchy.","a":"Toute suite convergente est de Cauchy. La réciproque est fausse en général.","hint":"Suite convergente implique Cauchy"},
  {"id":"mp06-def-10","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Espace complet, espace de Banach.","a":"Un EVN \\((E, \\|\\cdot\\|)\\) est dit complet si toute suite de Cauchy de \\(E\\) converge dans \\(E\\). Un espace vectoriel normé complet est appelé espace de Banach.","hint":"Espace complet, espace Banach"},
  {"id":"mp06-thm-02","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"thm","q":"Énoncer le théorème : Complétude en dimension finie.","a":"Tout espace vectoriel normé de dimension finie est complet (c'est un espace de Banach).","hint":"Complétude dimension finie"},
  {"id":"mp06-prop-07","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"prop","q":"Énoncer la proposition : Sous-espace fermé d'un Banach.","a":"Un sous-espace vectoriel \\(F\\) d'un espace de Banach \\(E\\) est complet si et seulement s'il est fermé dans \\(E\\). En dimension finie, tout sous-espace vectoriel est fermé.","hint":"Sous-espace fermé d'un Banach"},
  {"id":"mp06-def-11","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Partie compacte (séquentielle).","a":"Une partie \\(K \\subset E\\) est dite (séquentiellement) compacte si de toute suite d'éléments de \\(K\\), on peut extraire une sous-suite qui converge vers un élément de \\(K\\).","hint":"Partie compacte (séquentielle)"},
  {"id":"mp06-prop-08","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"prop","q":"Énoncer la proposition : Propriétés élémentaires.","a":"\\n- Toute partie compacte est bornée et fermée. \\n- Toute partie fermée d'un compact est compacte. \\n- L'image d'un compact par une application continue est compacte.","hint":"Propriétés élémentaires"},
  {"id":"mp06-thm-03","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"thm","q":"Énoncer le théorème : de Bolzano-Weierstrass.","a":"Dans \\(\\mathbb{R}^n\\) (ou plus généralement dans tout EVN de dimension finie), toute suite bornée admet une sous-suite convergente.","hint":"Bolzano-Weierstrass"},
  {"id":"mp06-thm-04","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"thm","q":"Énoncer le théorème : de Heine (caractérisation en dimension finie).","a":"Dans un espace vectoriel normé de dimension finie, une partie \\(K\\) est compacte si et seulement si elle est fermée et bornée.","hint":"Heine (caractérisation dimension finie)"},
  {"id":"mp06-thm-05","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"thm","q":"Énoncer le théorème : des bornes atteintes.","a":"Toute fonction continue à valeurs réelles sur un compact non vide est bornée et atteint ses bornes.","hint":"des bornes atteintes"},
  {"id":"mp06-def-12","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Continuité séquentielle.","a":"Soient \\((E, \\|\\cdot\\|_E)\\) et \\((F, \\|\\cdot\\|_F)\\) deux EVN. Une application \\(f : E \\to F\\) est continue en \\(a \\in E\\) si pour toute suite \\((x_n)\\) convergent vers \\(a\\) : \\[\\]","hint":"Continuité séquentielle"},
  {"id":"mp06-def-13","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Continuité \\(\\varepsilon\\)-\\(\\delta\\).","a":"De manière équivalente, \\(f\\) est continue en \\(a\\) si : \\[\\]","hint":"Continuité varepsilon-delta"},
  {"id":"mp06-def-14","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Lipschitzienne.","a":"Une application \\(f : E \\to F\\) est dite lipschitzienne (de rapport \\(k \\geq 0\\)) si : \\[\\]","hint":"Lipschitzienne"},
  {"id":"mp06-prop-09","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"prop","q":"Énoncer la proposition : Caractérisation de la continuité.","a":"Soit \\(f : E \\to F\\) une application linéaire entre deux EVN. Les assertions suivantes sont équivalentes : \\n- \\(f\\) est continue (sur \\(E\\)). \\n- \\(f\\) est continue en \\(0_E\\). \\n- \\(f\\) est lipschitzienne. \\n- \\(f\\) est bornée sur la boule unité : \\(\\exists\\, C \\geq 0,\\; \\forall\\, x \\in E,\\; \\|f(x)\\|_F \\leq C\\, \\|x\\|_E\\).","hint":"Caractérisation continuité"},
  {"id":"mp06-thm-06","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"thm","q":"Énoncer le théorème : Continuité en dimension finie.","a":"Toute application linéaire définie sur un espace vectoriel normé de dimension finie est continue.","hint":"Continuité dimension finie"},
  {"id":"mp06-def-15","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"def","q":"Définir : Norme subordonnée (norme d'opérateur).","a":"Soit \\(f : E \\to F\\) une application linéaire continue. On définit la norme d'opérateur (ou norme subordonnée) de \\(f\\) par : \\[\\]","hint":"Norme subordonnée (norme d'opérateur)"},
  {"id":"mp06-prop-10","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"prop","q":"Énoncer la proposition : Espace \\(\\mathcal{L}_c(E, F)\\).","a":"Un EVN \\((E, \\|\\cdot\\|)\\) est dit complet si toute suite de Cauchy de \\(E\\) converge dans \\(E\\). Un espace vectoriel normé complet est appelé espace de Banach.","hint":"Espace mathcal{L}_c(E,"},
  {"id":"mp06-prop-11","ch":"mp-06","chName":"Topologie des espaces vectoriels normés","type":"prop","q":"Énoncer la proposition : Sous-multiplicativité.","a":"Si \\(f \\in \\mathcal{L}_c(E, F)\\) et \\(g \\in \\mathcal{L}_c(F, G)\\), alors : \\[\\]","hint":"Sous-multiplicativité"},
  {"id":"mp07-def-01","ch":"mp-07","chName":"Suites et séries de fonctions","type":"def","q":"Définir : Convergence simple.","a":"La suite \\((f_n)\\) converge simplement vers \\(f : A \\to \\mathbb{R}\\) si : \\[\\]","hint":"Convergence simple"},
  {"id":"mp07-def-02","ch":"mp-07","chName":"Suites et séries de fonctions","type":"def","q":"Définir : Convergence uniforme.","a":"La suite \\((f_n)\\) converge uniformément vers \\(f : A \\to \\mathbb{R}\\) si : \\[\\]","hint":"Convergence uniforme"},
  {"id":"mp07-prop-01","ch":"mp-07","chName":"Suites et séries de fonctions","type":"prop","q":"Énoncer la proposition : Critère de non-convergence uniforme.","a":"Si l'on peut trouver une suite \\((x_n)\\) d'éléments de \\(A\\) telle que \\(f_n(x_n) - f(x_n) \\not\\to 0\\), alors la convergence n'est pas uniforme.","hint":"Critère non-convergence uniforme"},
  {"id":"mp07-thm-01","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : La CVU conserve la continuité.","a":"Si les fonctions \\(f_n : A \\to \\mathbb{R}\\) sont continues et si \\(f_n \\xrightarrow{\\text{CVU}} f\\) sur \\(A\\), alors la fonction limite \\(f\\) est continue sur \\(A\\).","hint":"CVU conserve continuité"},
  {"id":"mp07-prop-02","ch":"mp-07","chName":"Suites et séries de fonctions","type":"prop","q":"Énoncer la proposition : La CVU conserve la bornitude.","a":"Si les \\(f_n\\) sont bornées sur \\(A\\) et si \\(f_n \\xrightarrow{\\text{CVU}} f\\), alors \\(f\\) est bornée sur \\(A\\).","hint":"CVU conserve bornitude"},
  {"id":"mp07-thm-02","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : Interversion limite-intégrale (CVU sur un segment).","a":"Soient \\(f_n : [a, b] \\to \\mathbb{R}\\) (ou \\(\\mathbb{C}\\)) des fonctions continues par morceaux. Si \\(f_n \\xrightarrow{\\text{CVU}} f\\) sur \\([a, b]\\), alors \\(f\\) est continue par morceaux et : \\[\\]","hint":"Interversion limite-intégrale (CVU sur..."},
  {"id":"mp07-thm-03","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : Interversion limite-dérivée.","a":"Soient \\(f_n : I \\to \\mathbb{R}\\) des fonctions de classe \\(\\mathcal{C}^1\\) sur un intervalle \\(I\\). On suppose : \\n- Il existe \\(x_0 \\in I\\) tel que \\((f_n(x_0))\\) converge. \\n- La suite \\((f_n')\\) converge uniformément vers une fonction \\(g\\) sur \\(I\\). Alors \\((f_n)\\) converge uniformément sur tout segment de \\(I\\) vers une fonction \\(f\\) de classe \\(\\mathcal{C}^1\\), et \\(f' = g\\). Autrement dit : \\[\\]","hint":"Interversion limite-dérivée"},
  {"id":"mp07-thm-04","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : Convergence dominée (version séries, admis).","a":"Soit \\((f_n)\\) une suite de fonctions continues par morceaux sur un intervalle \\(I\\). Si \\(f_n \\to f\\) simplement et s'il existe \\(\\varphi : I \\to \\mathbb{R}_+\\) intégrable sur \\(I\\) telle que \\(|f_n(t)| \\leqslant \\varphi(t)\\) pour tout \\(n\\) et tout \\(t \\in I\\), alors \\(f\\) est intégrable sur \\(I\\) et : \\[\\]","hint":"Convergence dominée (version séries,..."},
  {"id":"mp07-def-03","ch":"mp-07","chName":"Suites et séries de fonctions","type":"def","q":"Définir : Convergence simple, uniforme, normale d'une série de fonctions.","a":"Soit \\(\\sum f_n\\) une série de fonctions de \\(A\\) dans \\(\\mathbb{R}\\). \\n- Convergence simple : pour tout \\(x \\in A\\), la série \\(\\sum f_n(x)\\) converge. \\n- Convergence uniforme : la suite des sommes partielles \\(S_N = \\sum_{n=0}^N f_n\\) converge uniformément sur \\(A\\). \\n- Convergence normale : la série \\(\\sum \\|f_n\\|_\\infty\\) converge, où \\(\\|f_n\\|_\\infty = \\sup_{x \\in A} |f_n(x)|\\).","hint":"Convergence simple, uniforme, normale..."},
  {"id":"mp07-thm-05","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : Implications entre les modes de convergence.","a":"On a les implications suivantes : \\[\\]","hint":"Implications entre les modes..."},
  {"id":"mp07-thm-06","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : Interversion somme-intégrale.","a":"Soient \\(f_n : [a, b] \\to \\mathbb{R}\\) continues par morceaux. Si la série \\(\\sum f_n\\) converge uniformément sur \\([a, b]\\), alors : \\[\\]","hint":"Interversion somme-intégrale"},
  {"id":"mp07-thm-07","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : Interversion somme-dérivée.","a":"Soient \\(f_n : I \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^1\\) sur un intervalle \\(I\\). Si : \\n- Il existe \\(x_0 \\in I\\) tel que \\(\\sum f_n(x_0)\\) converge. \\n- La série \\(\\sum f_n'\\) converge uniformément sur tout segment de \\(I\\). Alors \\(\\sum f_n\\) converge uniformément sur tout segment de \\(I\\), sa somme \\(S\\) est de classe \\(\\mathcal{C}^1\\), et : \\[\\]","hint":"Interversion somme-dérivée"},
  {"id":"mp07-thm-08","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : Théorème de Weierstrass.","a":"Toute fonction continue \\(f : [a, b] \\to \\mathbb{R}\\) est limite uniforme d'une suite de polynômes. Autrement dit, l'espace \\(\\mathbb{R}[X]\\) est dense dans \\((\\mathcal{C}([a, b], \\mathbb{R}),\\, \\|\\cdot\\|_\\infty)\\).","hint":"Théorème Weierstrass"},
  {"id":"mp07-def-04","ch":"mp-07","chName":"Suites et séries de fonctions","type":"def","q":"Définir : Polynômes de Bernstein.","a":"Pour \\(f : [0, 1] \\to \\mathbb{R}\\) continue et \\(n \\in \\mathbb{N}^*\\), le \\(n\\)-ième polynôme de Bernstein de \\(f\\) est : \\[\\]","hint":"Polynômes Bernstein"},
  {"id":"mp07-thm-09","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : Convergence des polynômes de Bernstein.","a":"Pour toute fonction continue \\(f : [0, 1] \\to \\mathbb{R}\\), la suite \\((B_n(f))\\) converge uniformément vers \\(f\\) sur \\([0, 1]\\).","hint":"Convergence des polynômes Bernstein"},
  {"id":"mp07-prop-03","ch":"mp-07","chName":"Suites et séries de fonctions","type":"prop","q":"Énoncer la proposition : Lemme de Weierstrass trigonométrique.","a":"Toute fonction continue \\(2\\pi\\)-périodique est limite uniforme de polynômes trigonométriques.","hint":"Lemme Weierstrass trigonométrique"},
  {"id":"mp07-def-05","ch":"mp-07","chName":"Suites et séries de fonctions","type":"def","q":"Définir : Rayon de convergence.","a":"Le rayon de convergence de la série entière \\(\\sum a_n z^n\\) est : \\[\\]","hint":"Rayon convergence"},
  {"id":"mp07-prop-04","ch":"mp-07","chName":"Suites et séries de fonctions","type":"prop","q":"Énoncer la proposition : Lemme d'Abel.","a":"Si \\((a_n r_0^n)\\) est bornée pour un certain \\(r_0 > 0\\), alors \\(\\sum a_n z^n\\) converge absolument pour tout \\(|z|","hint":"Lemme d'Abel"},
  {"id":"mp07-thm-10","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : Règle de d'Alembert pour le rayon.","a":"Si \\(a_n \\neq 0\\) à partir d'un certain rang et si \\(\\frac{|a_{n+1}|}{|a_n|} \\to \\ell \\in [0, +\\infty]\\), alors \\(R = \\frac{1}{\\ell}\\) (avec la convention \\(\\frac{1}{0} = +\\infty\\) et \\(\\frac{1}{+\\infty} = 0\\)).","hint":"Règle d'Alembert pour rayon"},
  {"id":"mp07-thm-11","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : Formule de Hadamard.","a":"Le rayon de convergence est donné par : \\[\\]","hint":"Formule Hadamard"},
  {"id":"mp07-prop-05","ch":"mp-07","chName":"Suites et séries de fonctions","type":"prop","q":"Énoncer la proposition : Convergence normale sur tout compact.","a":"La série entière \\(\\sum a_n x^n\\) converge normalement (donc uniformément) sur tout segment \\([-r, r]\\) avec \\(0","hint":"Convergence normale sur tout..."},
  {"id":"mp07-thm-12","ch":"mp-07","chName":"Suites et séries de fonctions","type":"thm","q":"Énoncer le théorème : Dérivation terme à terme des séries entières.","a":"La série entière \\(\\sum a_n x^n\\) et la série dérivée \\(\\sum n a_n x^{n-1}\\) ont le même rayon de convergence \\(R\\). La somme \\(S(x) = \\sum_{n=0}^{+\\infty} a_n x^n\\) est de classe \\(\\mathcal{C}^\\infty\\) sur \\(]-R, R[\\) et : \\[\\]","hint":"Dérivation terme terme des..."},
  {"id":"mp07-prop-06","ch":"mp-07","chName":"Suites et séries de fonctions","type":"prop","q":"Énoncer la proposition : Intégration terme à terme.","a":"Soit \\(S(x) = \\sum_{n=0}^{+\\infty} a_n x^n\\) de rayon \\(R > 0\\). Alors pour tout \\(x \\in ]-R, R[\\) : \\[\\]","hint":"Intégration terme terme"},
  {"id":"mp07-prop-07","ch":"mp-07","chName":"Suites et séries de fonctions","type":"prop","q":"Énoncer la proposition : Développements en séries entières usuels.","a":"Les développements suivants sont valables sur les intervalles indiqués : \\[\\]","hint":"Développements séries entières usuels"},
  {"id":"mp07-def-06","ch":"mp-07","chName":"Suites et séries de fonctions","type":"def","q":"Définir : Exponentielle de matrices.","a":"Pour toute matrice \\(A \\in \\mathcal{M}_n(\\mathbb{R})\\) (ou \\(\\mathcal{M}_n(\\mathbb{C})\\)), on définit : \\[\\]","hint":"Exponentielle matrices"},
  {"id":"mp07-prop-08","ch":"mp-07","chName":"Suites et séries de fonctions","type":"prop","q":"Énoncer la proposition : Propriétés de l'exponentielle de matrices.","a":"Soient \\(A, B \\in \\mathcal{M}_n(\\mathbb{K})\\). \\n- \\(\\exp(0) = I_n\\). \\n- Si \\(AB = BA\\), alors \\(\\exp(A + B) = \\exp(A)\\exp(B)\\). \\n- \\(\\exp(A)\\) est inversible et \\(\\exp(A)^{-1} = \\exp(-A)\\). \\n- Si \\(A = P D P^{-1}\\), alors \\(\\exp(A) = P \\exp(D) P^{-1}\\). \\n- \\(\\det(\\exp(A)) = e^{\\operatorname{tr}(A)}\\).","hint":"Propriétés l'exponentielle matrices"},
  {"id":"mp08-def-01","ch":"mp-08","chName":"Séries entières avancées","type":"def","q":"Définir : Série entière.","a":"Une série entière est une série de fonctions de la forme \\(\\sum_{n \\geq 0} a_n z^n\\) où \\((a_n)_{n \\in \\mathbb{N}} \\subset \\mathbb{C}\\) est la suite des coefficients. Le rayon de convergence est : \\[\\]","hint":"Série entière"},
  {"id":"mp08-lem-01","ch":"mp-08","chName":"Séries entières avancées","type":"lem","q":"Énoncer le lemme : d'Abel.","a":"Si la suite \\((a_n r_0^n)\\) est bornée pour un certain \\(r_0 > 0\\), alors pour tout \\(r \\in [0, r_0[\\), la série \\(\\sum a_n z^n\\) converge absolument et uniformément sur le disque fermé \\(\\overline{D}(0, r)\\). En particulier : \\n- Si \\(|z| < R\\), la série \\(\\sum a_n z^n\\) converge absolument. \\n- Si \\(|z| > R\\), le terme général \\(a_n z^n\\) n'est pas borné, donc la série diverge grossièrement.","hint":"d'Abel"},
  {"id":"mp08-prop-01","ch":"mp-08","chName":"Séries entières avancées","type":"prop","q":"Énoncer la proposition : Convergence normale sur les disques fermés.","a":"Soit \\(\\sum a_n z^n\\) une série entière de rayon \\(R > 0\\). Pour tout \\(r \\in [0, R[\\), la série converge normalement sur \\(\\overline{D}(0, r)\\). On a en particulier : \\[\\]","hint":"Convergence normale sur les..."},
  {"id":"mp08-thm-01","ch":"mp-08","chName":"Séries entières avancées","type":"thm","q":"Énoncer le théorème : Règle de d'Alembert.","a":"Si \\(a_n \\neq 0\\) pour \\(n\\) assez grand et si la limite existe : \\[\\]","hint":"Règle d'Alembert"},
  {"id":"mp08-thm-02","ch":"mp-08","chName":"Séries entières avancées","type":"thm","q":"Énoncer le théorème : Règle de Hadamard.","a":"Le rayon de convergence de \\(\\sum a_n z^n\\) est donné par la formule : \\[\\]","hint":"Règle Hadamard"},
  {"id":"mp08-thm-03","ch":"mp-08","chName":"Séries entières avancées","type":"thm","q":"Énoncer le théorème : Continuité de la somme.","a":"Soit \\(\\sum a_n x^n\\) une série entière de rayon \\(R > 0\\). La fonction somme \\(S : x \\mapsto \\sum_{n=0}^{+\\infty} a_n x^n\\) est continue sur \\(]-R, R[\\).","hint":"Continuité somme"},
  {"id":"mp08-thm-04","ch":"mp-08","chName":"Séries entières avancées","type":"thm","q":"Énoncer le théorème : Classe \\(\\mathcal{C}^\\infty\\) et dérivation terme à terme.","a":"Soit \\(\\sum a_n x^n\\) une série entière de rayon \\(R > 0\\). Alors : \\n- La série dérivée \\(\\sum n a_n x^{n-1}\\) a le même rayon de convergence \\(R\\). \\n- La somme \\(S\\) est de classe \\(\\mathcal{C}^\\infty\\) sur \\(]-R, R[\\) et pour tout \\(k \\in \\mathbb{N}\\) : \\[\\]","hint":"Classe mathcal{C}^infty dérivation terme..."},
  {"id":"mp08-thm-05","ch":"mp-08","chName":"Séries entières avancées","type":"thm","q":"Énoncer le théorème : Intégration terme à terme.","a":"Soit \\(\\sum a_n x^n\\) de rayon \\(R > 0\\). Pour tout \\(x \\in ]-R, R[\\) : \\[\\]","hint":"Intégration terme terme"},
  {"id":"mp08-prop-02","ch":"mp-08","chName":"Séries entières avancées","type":"prop","q":"Énoncer la proposition : Unicité des coefficients.","a":"Si deux séries entières \\(\\sum a_n x^n\\) et \\(\\sum b_n x^n\\) ont la même somme au voisinage de \\(0\\), alors \\(a_n = b_n\\) pour tout \\(n\\). Autrement dit, le développement en série entière d'une fonction est unique.","hint":"Unicité des coefficients"},
  {"id":"mp08-def-02","ch":"mp-08","chName":"Séries entières avancées","type":"def","q":"Définir : Développement en série entière.","a":"On dit qu'une fonction \\(f\\) admet un développement en série entière (DSE) au voisinage de \\(0\\) s'il existe \\(r > 0\\) et une suite \\((a_n)\\) tels que : \\[\\]","hint":"Développement série entière"},
  {"id":"mp08-thm-06","ch":"mp-08","chName":"Séries entières avancées","type":"thm","q":"Énoncer le théorème : DSE classiques.","a":"Les développements suivants sont valables sur les domaines indiqués : \\[\\]","hint":"DSE classiques"},
  {"id":"mp08-thm-07","ch":"mp-08","chName":"Séries entières avancées","type":"thm","q":"Énoncer le théorème : Développement du binôme généralisé.","a":"Pour tout \\(\\alpha \\in \\mathbb{R}\\) et \\(|x| < 1\\) : \\[\\]","hint":"Développement binôme généralisé"},
  {"id":"mp08-prop-03","ch":"mp-08","chName":"Séries entières avancées","type":"prop","q":"Énoncer la proposition : Produit de Cauchy de séries entières.","a":"Soient \\(f(x) = \\sum a_n x^n\\) de rayon \\(R_a\\) et \\(g(x) = \\sum b_n x^n\\) de rayon \\(R_b\\). Alors pour \\(|x| < \\min(R_a, R_b)\\) : \\[\\]","hint":"Produit Cauchy séries entières"},
  {"id":"mp08-prop-04","ch":"mp-08","chName":"Séries entières avancées","type":"prop","q":"Énoncer la proposition : Composition de séries entières.","a":"Si \\(f(x) = \\sum a_n x^n\\) a un rayon \\(R > 0\\) et \\(g(x) = \\sum b_n x^n\\) avec \\(g(0) = 0\\) et \\(|g(x)| < R\\) pour \\(|x| < r\\), alors \\(f \\circ g\\) admet un DSE sur \\(]-r, r[\\).","hint":"Composition séries entières"},
  {"id":"mp08-def-03","ch":"mp-08","chName":"Séries entières avancées","type":"def","q":"Définir : Fonction analytique.","a":"Soit \\(I\\) un intervalle ouvert de \\(\\mathbb{R}\\). Une fonction \\(f : I \\to \\mathbb{R}\\) (ou \\(\\mathbb{C}\\)) est dite analytique sur \\(I\\) si pour tout \\(x_0 \\in I\\), il existe \\(r > 0\\) et une suite \\((a_n)\\) tels que : \\[\\]","hint":"Fonction analytique"},
  {"id":"mp08-prop-05","ch":"mp-08","chName":"Séries entières avancées","type":"prop","q":"Énoncer la proposition : Propriétés des fonctions analytiques.","a":"Soient \\(f, g\\) analytiques sur \\(I\\). Alors : \\n- \\(f + g\\), \\(fg\\), \\(f/g\\) (si \\(g \\neq 0\\)) sont analytiques sur \\(I\\). \\n- \\(f'\\) est analytique sur \\(I\\). \\n- Si \\(f\\) est analytique sur \\(I\\) et \\(g\\) analytique sur \\(J \\supset f(I)\\), alors \\(g \\circ f\\) est analytique sur \\(I\\). \\n- Toute somme de série entière est analytique sur son intervalle ouvert de convergence.","hint":"Propriétés des fonctions analytiques"},
  {"id":"mp08-thm-08","ch":"mp-08","chName":"Séries entières avancées","type":"thm","q":"Énoncer le théorème : Critère de développabilité.","a":"Soit \\(f \\in \\mathcal{C}^\\infty(I)\\). La fonction \\(f\\) est développable en série entière en \\(x_0 \\in I\\) si et seulement si le reste de Taylor-Lagrange (ou Taylor avec reste intégral) tend vers \\(0\\) : \\[\\]","hint":"Critère développabilité"},
  {"id":"mp08-prop-06","ch":"mp-08","chName":"Séries entières avancées","type":"prop","q":"Énoncer la proposition : Méthode des coefficients indéterminés.","a":"Pour résoudre une équation différentielle linéaire à coefficients polynomiaux, on cherche la solution sous forme de série entière \\(y(x) = \\sum a_n x^n\\). On substitue dans l'équation, puis on identifie les coefficients pour obtenir une relation de récurrence sur les \\((a_n)\\).","hint":"Méthode des coefficients indéterminés"},
  {"id":"mp08-def-04","ch":"mp-08","chName":"Séries entières avancées","type":"def","q":"Définir : Série génératrice.","a":"Soit \\((u_n)_{n \\geq 0}\\) une suite à valeurs dans \\(\\mathbb{C}\\). La série génératrice (ordinaire) de \\((u_n)\\) est la série entière : \\[\\]","hint":"Série génératrice"},
  {"id":"mp08-prop-07","ch":"mp-08","chName":"Séries entières avancées","type":"prop","q":"Énoncer la proposition : Récurrences linéaires et fractions rationnelles.","a":"Soit \\((u_n)\\) une suite vérifiant une récurrence linéaire d'ordre \\(p\\) à coefficients constants : \\[\\]","hint":"Récurrences linéaires fractions rationnelles"},
  {"id":"mp08-prop-08","ch":"mp-08","chName":"Séries entières avancées","type":"prop","q":"Énoncer la proposition : Convergence dans le plan complexe.","a":"Soit \\(\\sum a_n z^n\\) une série entière de rayon \\(R > 0\\). Le domaine de convergence absolue est le disque ouvert \\(D(0, R) \\subset \\mathbb{C}\\). La somme \\(S(z) = \\sum a_n z^n\\) est continue sur \\(D(0, R)\\) et holomorphe (dérivable au sens complexe) : \\[\\]","hint":"Convergence dans plan complexe"},
  {"id":"mp08-thm-09","ch":"mp-08","chName":"Séries entières avancées","type":"thm","q":"Énoncer le théorème : d'Abel radial.","a":"Soit \\(\\sum a_n z^n\\) de rayon \\(R = 1\\). Si la série numérique \\(\\sum a_n\\) converge vers \\(S\\), alors : \\[\\]","hint":"d'Abel radial"},
  {"id":"mp08-prop-09","ch":"mp-08","chName":"Séries entières avancées","type":"prop","q":"Énoncer la proposition : Techniques classiques.","a":"Pour calculer la somme d'une série de la forme \\(\\sum f(n) x^n\\) ou \\(\\sum f(n)\\), on dispose des méthodes suivantes : \\n- Dérivation/intégration : si \\(f(n)\\) contient un facteur polynomial en \\(n\\), dériver ou intégrer un DSE connu pour le faire apparaître. \\n- Décomposition en éléments simples : si \\(f(n)\\) est une fraction rationnelle en \\(n\\), décomposer puis sommer chaque terme.","hint":"Techniques classiques"},
  {"id":"mp09-def-01","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Distance.","a":"Soit \\(E\\) un ensemble. Une distance sur \\(E\\) est une application \\(d : E \\times E \\to \\mathbb{R}^+\\) vérifiant, pour tous \\(x, y, z \\in E\\) : \\n- Séparation : \\(d(x, y) = 0 \\iff x = y\\). \\n- Symétrie : \\(d(x, y) = d(y, x)\\). \\n- Inégalité triangulaire : \\(d(x, z) \\leqslant d(x, y) + d(y, z)\\). Le couple \\((E, d)\\) est appelé espace métrique.","hint":"Distance"},
  {"id":"mp09-def-02","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Boules ouvertes et fermées.","a":"Soit \\((E, d)\\) un espace métrique, \\(a \\in E\\) et \\(r > 0\\). \\n- La boule ouverte de centre \\(a\\) et de rayon \\(r\\) est \\(B(a, r) = \\{x \\in E \\mid d(x, a) < r\\}\\). \\n- La boule fermée de centre \\(a\\) et de rayon \\(r\\) est \\(\\bar{B}(a, r) = \\{x \\in E \\mid d(x, a) \\leqslant r\\}\\). \\n- La sphère de centre \\(a\\) et de rayon \\(r\\) est \\(S(a, r) = \\{x \\in E \\mid d(x, a) = r\\}\\).","hint":"Boules ouvertes fermées"},
  {"id":"mp09-def-03","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Ouvert.","a":"Une partie \\(U \\subset E\\) est dite ouverte si pour tout \\(x \\in U\\), il existe \\(r > 0\\) tel que \\(B(x, r) \\subset U\\). Autrement dit, tout point de \\(U\\) est intérieur à \\(U\\).","hint":"Ouvert"},
  {"id":"mp09-def-04","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Fermé.","a":"Une partie \\(F \\subset E\\) est dite fermée si son complémentaire \\(E \\setminus F\\) est ouvert. De manière équivalente, \\(F\\) est fermée si et seulement si toute suite d'éléments de \\(F\\) qui converge dans \\(E\\) a sa limite dans \\(F\\) (caractérisation séquentielle).","hint":"Fermé"},
  {"id":"mp09-prop-01","ch":"mp-09","chName":"Espaces métriques complets","type":"prop","q":"Énoncer la proposition : Propriétés des ouverts et fermés.","a":"\\n- \\(\\emptyset\\) et \\(E\\) sont à la fois ouverts et fermés. \\n- Toute réunion (quelconque) d'ouverts est un ouvert. \\n- Toute intersection finie d'ouverts est un ouvert. \\n- Toute intersection (quelconque) de fermés est un fermé. \\n- Toute réunion finie de fermés est un fermé. \\n- Toute boule ouverte est un ouvert ; toute boule fermée est un fermé.","hint":"Propriétés des ouverts fermés"},
  {"id":"mp09-def-05","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Topologie induite (ou trace).","a":"Soit \\((E, d)\\) un espace métrique et \\(A \\subset E\\). La distance induite sur \\(A\\) est la restriction \\(d_A = d|_{A \\times A}\\). L'espace \\((A, d_A)\\) est un espace métrique. Les ouverts de \\(A\\) pour la topologie induite sont les ensembles de la forme \\(U \\cap A\\), où \\(U\\) est un ouvert de \\(E\\).","hint":"Topologie induite (ou trace)"},
  {"id":"mp09-def-06","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Suite de Cauchy.","a":"Soit \\((E, d)\\) un espace métrique. Une suite \\((x_n)_{n \\in \\mathbb{N}}\\) d'éléments de \\(E\\) est dite de Cauchy si : \\[\\]","hint":"Suite Cauchy"},
  {"id":"mp09-prop-02","ch":"mp-09","chName":"Espaces métriques complets","type":"prop","q":"Énoncer la proposition : Toute suite convergente est de Cauchy.","a":"Si \\((x_n)\\) converge vers \\(\\ell \\in E\\), alors \\((x_n)\\) est de Cauchy.","hint":"Toute suite convergente est..."},
  {"id":"mp09-def-07","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Espace complet.","a":"Un espace métrique \\((E, d)\\) est dit complet si toute suite de Cauchy d'éléments de \\(E\\) converge dans \\(E\\).","hint":"Espace complet"},
  {"id":"mp09-prop-03","ch":"mp-09","chName":"Espaces métriques complets","type":"prop","q":"Énoncer la proposition : Complétude de l'espace des fonctions bornées.","a":"Soit \\(A\\) un ensemble non vide et \\((F, \\|\\cdot\\|)\\) un espace de Banach. Alors l'espace \\(\\mathcal{B}(A, F)\\) des fonctions bornées de \\(A\\) dans \\(F\\), muni de la norme \\(\\|f\\|_\\infty = \\sup_{x \\in A} \\|f(x)\\|\\), est complet.","hint":"Complétude l'espace des fonctions..."},
  {"id":"mp09-prop-04","ch":"mp-09","chName":"Espaces métriques complets","type":"prop","q":"Énoncer la proposition : Fermé d'un espace complet.","a":"Soit \\((E, d)\\) un espace métrique complet et \\(F \\subset E\\). Alors \\(F\\) est complet (pour la distance induite) si et seulement si \\(F\\) est fermé dans \\(E\\).","hint":"Fermé d'un espace complet"},
  {"id":"mp09-def-08","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Application contractante.","a":"Soit \\((E, d)\\) un espace métrique. Une application \\(f : E \\to E\\) est dite contractante (ou est une contraction) s'il existe une constante \\(k \\in [0, 1[\\) telle que : \\[\\]","hint":"Application contractante"},
  {"id":"mp09-thm-01","ch":"mp-09","chName":"Espaces métriques complets","type":"thm","q":"Énoncer le théorème : Point fixe de Banach (Picard).","a":"Soit \\((E, d)\\) un espace métrique complet non vide et \\(f : E \\to E\\) une application contractante de rapport \\(k \\in [0, 1[\\). Alors : \\n- \\(f\\) admet un unique point fixe \\(\\ell \\in E\\) (i.e. \\(f(\\ell) = \\ell\\)). \\n- Pour tout \\(x_0 \\in E\\), la suite définie par \\(x_{n+1} = f(x_n)\\) converge vers \\(\\ell\\).","hint":"Point fixe Banach (Picard)"},
  {"id":"mp09-prop-05","ch":"mp-09","chName":"Espaces métriques complets","type":"prop","q":"Énoncer la proposition : Estimations d'erreur.","a":"Sous les hypothèses du théorème de Banach, on dispose des estimations suivantes : \\n- Estimation a priori : \\(\\displaystyle d(x_n, \\ell) \\leqslant \\frac{k^n}{1 - k}\\, d(x_1, x_0)\\). \\n- Estimation a posteriori : \\(\\displaystyle d(x_n, \\ell) \\leqslant \\frac{k}{1 - k}\\, d(x_n, x_{n-1})\\). La convergence est donc au moins géométrique de raison \\(k\\).","hint":"Estimations d'erreur"},
  {"id":"mp09-def-09","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Espace de Banach.","a":"Un espace vectoriel normé \\((E, \\|\\cdot\\|)\\) est un espace de Banach s'il est complet pour la distance \\(d(x, y) = \\|x - y\\|\\) induite par la norme.","hint":"Espace Banach"},
  {"id":"mp09-def-10","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Série absolument convergente.","a":"Soit \\((E, \\|\\cdot\\|)\\) un espace vectoriel normé et \\((u_n)\\) une suite d'éléments de \\(E\\). La série \\(\\sum u_n\\) est dite absolument convergente si la série numérique \\(\\sum \\|u_n\\|\\) converge.","hint":"Série absolument convergente"},
  {"id":"mp09-thm-02","ch":"mp-09","chName":"Espaces métriques complets","type":"thm","q":"Énoncer le théorème : Caractérisation des espaces de Banach.","a":"Un espace vectoriel normé \\((E, \\|\\cdot\\|)\\) est un espace de Banach si et seulement si toute série absolument convergente est convergente.","hint":"Caractérisation des espaces Banach"},
  {"id":"mp09-prop-06","ch":"mp-09","chName":"Espaces métriques complets","type":"prop","q":"Énoncer la proposition : Convergence normale dans un Banach.","a":"Soit \\(A\\) un ensemble et \\((f_n)\\) une suite de fonctions bornées de \\(A\\) dans un espace de Banach \\(F\\). Si \\(\\sum \\|f_n\\|_\\infty\\) converge (convergence normale), alors \\(\\sum f_n\\) converge uniformément et absolument sur \\(A\\).","hint":"Convergence normale dans Banach"},
  {"id":"mp09-def-11","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Partie dense.","a":"Soit \\((E, d)\\) un espace métrique. Une partie \\(A \\subset E\\) est dite dense dans \\(E\\) si pour tout \\(x \\in E\\) et tout \\(\\varepsilon > 0\\), il existe \\(a \\in A\\) tel que \\(d(x, a) De manière équivalente : \\(A\\) est dense si et seulement si \\(\\overline{A} = E\\) (l'adhérence de \\(A\\) est \\(E\\) tout entier), ou encore si tout ouvert non vide de \\(E\\) rencontre \\(A\\).","hint":"Partie dense"},
  {"id":"mp09-prop-07","ch":"mp-09","chName":"Espaces métriques complets","type":"prop","q":"Énoncer la proposition : Caractérisation séquentielle de la densité.","a":"La partie \\(A\\) est dense dans \\(E\\) si et seulement si pour tout \\(x \\in E\\), il existe une suite \\((a_n)\\) d'éléments de \\(A\\) telle que \\(a_n \\to x\\).","hint":"Caractérisation séquentielle densité"},
  {"id":"mp09-thm-03","ch":"mp-09","chName":"Espaces métriques complets","type":"thm","q":"Énoncer le théorème : Weierstrass (admis).","a":"L'ensemble \\(\\mathbb{R}[X]\\) des fonctions polynomiales est dense dans \\(\\big(\\mathcal{C}([a,b], \\mathbb{R}), \\|\\cdot\\|_\\infty\\big)\\). Autrement dit, pour toute fonction \\(f\\) continue sur \\([a,b]\\) et tout \\(\\varepsilon > 0\\), il existe un polynôme \\(P\\) tel que : \\[\\]","hint":"Weierstrass (admis)"},
  {"id":"mp09-prop-08","ch":"mp-09","chName":"Espaces métriques complets","type":"prop","q":"Énoncer la proposition : Densité des fonctions trigonométriques.","a":"L'ensemble des polynômes trigonométriques \\(\\sum_{k=-N}^{N} c_k e^{ikt}\\) est dense dans l'espace \\(\\big(\\mathcal{C}_{2\\pi}(\\mathbb{R}, \\mathbb{C}), \\|\\cdot\\|_\\infty\\big)\\) des fonctions continues \\(2\\pi\\)-périodiques.","hint":"Densité des fonctions trigonométriques"},
  {"id":"mp09-def-12","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Arc (chemin).","a":"Soit \\((E, d)\\) un espace métrique. Un arc (ou chemin) de \\(a\\) à \\(b\\) dans \\(E\\) est une application continue \\(\\gamma : [0, 1] \\to E\\) telle que \\(\\gamma(0) = a\\) et \\(\\gamma(1) = b\\).","hint":"Arc (chemin)"},
  {"id":"mp09-def-13","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Connexe par arcs.","a":"Une partie \\(A\\) d'un espace métrique \\(E\\) est dite connexe par arcs si pour tous \\(a, b \\in A\\), il existe un arc de \\(a\\) à \\(b\\) contenu dans \\(A\\) (i.e. \\(\\gamma([0,1]) \\subset A\\)).","hint":"Connexe par arcs"},
  {"id":"mp09-def-14","ch":"mp-09","chName":"Espaces métriques complets","type":"def","q":"Définir : Partie convexe.","a":"Soit \\(E\\) un espace vectoriel (réel). Une partie \\(C \\subset E\\) est dite convexe si pour tous \\(x, y \\in C\\) et tout \\(t \\in [0, 1]\\) : \\[\\]","hint":"Partie convexe"},
  {"id":"mp09-prop-09","ch":"mp-09","chName":"Espaces métriques complets","type":"prop","q":"Énoncer la proposition : Convexe implique connexe par arcs.","a":"Toute partie convexe d'un espace vectoriel normé est connexe par arcs.","hint":"Convexe implique connexe par..."},
  {"id":"mp09-thm-04","ch":"mp-09","chName":"Espaces métriques complets","type":"thm","q":"Énoncer le théorème : Composantes connexes par arcs de \\(\\mathrm{GL}_n(\\mathbb{R})\\).","a":"Le groupe linéaire \\(\\mathrm{GL}_n(\\mathbb{R})\\) possède exactement deux composantes connexes par arcs : \\n- \\(\\mathrm{GL}_n^+(\\mathbb{R}) = \\{M \\in \\mathrm{GL}_n(\\mathbb{R}) \\mid \\det(M) > 0\\}\\) \\n- \\(\\mathrm{GL}_n^-(\\mathbb{R}) = \\{M \\in \\mathrm{GL}_n(\\mathbb{R}) \\mid \\det(M) < 0\\}\\)","hint":"Composantes connexes par arcs..."},
  {"id":"mp09-prop-10","ch":"mp-09","chName":"Espaces métriques complets","type":"prop","q":"Énoncer la proposition : Image continue d'un connexe par arcs.","a":"L'image d'une partie connexe par arcs par une application continue est connexe par arcs. En particulier, si \\(f : A \\to \\mathbb{R}\\) est continue et \\(A\\) est connexe par arcs, alors \\(f(A)\\) est un intervalle de \\(\\mathbb{R}\\).","hint":"Image continue d'un connexe..."},
  {"id":"mp10-def-01","ch":"mp-10","chName":"Integration sur un segment","type":"def","q":"Définir : Subdivision.","a":"Soit \\([a, b]\\) un segment de \\(\\mathbb{R}\\) avec \\(a < b\\). Une subdivision de \\([a, b]\\) est une famille finie \\(\\sigma = (x_0, x_1, \\ldots, x_n)\\) telle que : \\[\\]","hint":"Subdivision"},
  {"id":"mp10-def-02","ch":"mp-10","chName":"Integration sur un segment","type":"def","q":"Définir : Fonction en escalier.","a":"Soit \\(f : [a, b] \\to \\mathbb{R}\\) (ou \\(\\mathbb{C}\\)). On dit que \\(f\\) est une fonction en escalier s'il existe une subdivision \\(\\sigma = (x_0, \\ldots, x_n)\\) de \\([a, b]\\) telle que \\(f\\) est constante sur chaque intervalle ouvert \\(]x_{i-1}, x_i[\\), pour \\(i \\in \\{1, \\ldots, n\\}\\). On note \\(\\mathcal{E}([a,b], \\mathbb{R})\\) l'ensemble des fonctions en escalier sur \\([a, b]\\). C'est un sous-espace vectoriel de \\(\\mathbb{R}^{[a,b]}\\).","hint":"Fonction escalier"},
  {"id":"mp10-def-03","ch":"mp-10","chName":"Integration sur un segment","type":"def","q":"Définir : Integrale d'une fonction en escalier.","a":"Soit \\(f \\in \\mathcal{E}([a,b], \\mathbb{R})\\) et \\(\\sigma = (x_0, \\ldots, x_n)\\) une subdivision adaptee a \\(f\\), avec \\(f = c_i\\) sur \\(]x_{i-1}, x_i[\\). On definit l'integrale de \\(f\\) par : \\[\\]","hint":"Integrale d'une fonction escalier"},
  {"id":"mp10-prop-01","ch":"mp-10","chName":"Integration sur un segment","type":"prop","q":"Énoncer la proposition : Proprietes de l'integrale des fonctions en escalier.","a":"L'application \\(f \\mapsto \\int_a^b f(t)\\, \\mathrm{d}t\\) definie sur \\(\\mathcal{E}([a,b], \\mathbb{R})\\) verifie : \\n- Linearite : pour tous \\(f, g \\in \\mathcal{E}([a,b])\\) et \\(\\lambda, \\mu \\in \\mathbb{R}\\), \\(\\int_a^b (\\lambda f + \\mu g) = \\lambda \\int_a^b f + \\mu \\int_a^b g\\). \\n- Positivite : si \\(f \\geq 0\\) sur \\([a,b]\\), alors \\(\\int_a^b f \\geq 0\\).","hint":"Proprietes l'integrale des fonctions..."},
  {"id":"mp10-def-04","ch":"mp-10","chName":"Integration sur un segment","type":"def","q":"Définir : Fonction continue par morceaux.","a":"Une fonction \\(f : [a, b] \\to \\mathbb{R}\\) est dite continue par morceaux s'il existe une subdivision \\(\\sigma = (x_0, \\ldots, x_n)\\) de \\([a, b]\\) telle que : \\n- Pour tout \\(i \\in \\{1, \\ldots, n\\}\\), la restriction \\(f|_{]x_{i-1}, x_i[}\\) est continue. \\n- Pour tout \\(i \\in \\{1, \\ldots, n\\}\\), \\(f\\) admet une limite finie a droite en \\(x_{i-1}\\) et une limite finie a gauche en \\(x_i\\).","hint":"Fonction continue par morceaux"},
  {"id":"mp10-thm-01","ch":"mp-10","chName":"Integration sur un segment","type":"thm","q":"Énoncer le théorème : Approximation par des fonctions en escalier.","a":"Soit \\(f : [a,b] \\to \\mathbb{R}\\) continue par morceaux. Pour tout \\(\\varepsilon > 0\\), il existe des fonctions en escalier \\(\\varphi^-\\) et \\(\\varphi^+\\) telles que : \\[\\]","hint":"Approximation par des fonctions..."},
  {"id":"mp10-def-05","ch":"mp-10","chName":"Integration sur un segment","type":"def","q":"Définir : Integrale d'une fonction continue par morceaux.","a":"Soit \\(f \\in \\mathcal{CM}([a,b], \\mathbb{R})\\). On definit l'integrale de \\(f\\) sur \\([a,b]\\) par : \\[\\]","hint":"Integrale d'une fonction continue..."},
  {"id":"mp10-prop-02","ch":"mp-10","chName":"Integration sur un segment","type":"prop","q":"Énoncer la proposition : Proprietes de l'integrale.","a":"L'integrale sur \\(\\mathcal{CM}([a,b], \\mathbb{R})\\) herite de toutes les proprietes de l'integrale des fonctions en escalier : linearite, positivite, croissance, relation de Chasles, inegalite triangulaire. De plus : \\n- Si \\(f\\) est continue et positive sur \\([a,b]\\) et \\(\\int_a^b f = 0\\), alors \\(f = 0\\) sur \\([a,b]\\). \\n- \\(\\left|\\int_a^b f(t)\\, \\mathrm{d}t\\right| \\leq (b-a)\\, \\|f\\|_\\infty\\).","hint":"Proprietes l'integrale"},
  {"id":"mp10-def-06","ch":"mp-10","chName":"Integration sur un segment","type":"def","q":"Définir : Sommes de Riemann.","a":"Soit \\(f : [a, b] \\to \\mathbb{R}\\) continue par morceaux et \\(\\sigma = (x_0, \\ldots, x_n)\\) une subdivision de \\([a, b]\\). En choisissant des points \\(\\xi_i \\in [x_{i-1}, x_i]\\), la somme de Riemann associee est : \\[\\]","hint":"Sommes Riemann"},
  {"id":"mp10-thm-02","ch":"mp-10","chName":"Integration sur un segment","type":"thm","q":"Énoncer le théorème : Convergence des sommes de Riemann.","a":"Soit \\(f : [a,b] \\to \\mathbb{R}\\) continue par morceaux. Lorsque le pas \\(\\delta(\\sigma) \\to 0\\), les sommes de Riemann convergent vers l'integrale, uniformement en le choix des points intermediaires : \\[\\]","hint":"Convergence des sommes Riemann"},
  {"id":"mp10-prop-03","ch":"mp-10","chName":"Integration sur un segment","type":"prop","q":"Énoncer la proposition : Sommes de Riemann regulieres.","a":"Soit \\(f : [a, b] \\to \\mathbb{R}\\) continue par morceaux. Pour la subdivision reguliere a \\(n\\) pas egaux, on a : \\[\\]","hint":"Sommes Riemann regulieres"},
  {"id":"mp10-prop-04","ch":"mp-10","chName":"Integration sur un segment","type":"prop","q":"Énoncer la proposition : Proprietes fondamentales.","a":"Soit \\(f, g \\in \\mathcal{CM}([a,b], \\mathbb{R})\\). L'integrale verifie : \\n- Linearite : \\(\\int_a^b (\\alpha f + \\beta g) = \\alpha \\int_a^b f + \\beta \\int_a^b g\\) pour tous \\(\\alpha, \\beta \\in \\mathbb{R}\\). \\n- Croissance : si \\(f \\leq g\\) sur \\([a,b]\\), alors \\(\\int_a^b f \\leq \\int_a^b g\\). \\n- Inegalite triangulaire : \\(\\left|\\int_a^b f(t)\\, \\mathrm{d}t\\right| \\leq \\int_a^b |f(t)|\\, \\mathrm{d}t\\).","hint":"Proprietes fondamentales"},
  {"id":"mp10-def-07","ch":"mp-10","chName":"Integration sur un segment","type":"def","q":"Définir : Primitive.","a":"Soit \\(f : I \\to \\mathbb{R}\\) definie sur un intervalle \\(I\\). Une primitive de \\(f\\) sur \\(I\\) est une fonction \\(F : I \\to \\mathbb{R}\\) derivable telle que \\(F' = f\\) sur \\(I\\). Si \\(F\\) est une primitive de \\(f\\), alors les primitives de \\(f\\) sont exactement les fonctions \\(F + C\\) avec \\(C \\in \\mathbb{R}\\).","hint":"Primitive"},
  {"id":"mp10-thm-03","ch":"mp-10","chName":"Integration sur un segment","type":"thm","q":"Énoncer le théorème : Theoreme fondamental de l'analyse.","a":"Soit \\(f : [a, b] \\to \\mathbb{R}\\) continue. La fonction \\(F\\) definie par : \\[\\]","hint":"Theoreme fondamental l'analyse"},
  {"id":"mp10-prop-05","ch":"mp-10","chName":"Integration sur un segment","type":"prop","q":"Énoncer la proposition : Evaluation aux bornes.","a":"Soit \\(f : [a,b] \\to \\mathbb{R}\\) continue et \\(F\\) une primitive de \\(f\\). Alors : \\[\\]","hint":"Evaluation aux bornes"},
  {"id":"mp10-thm-04","ch":"mp-10","chName":"Integration sur un segment","type":"thm","q":"Énoncer le théorème : Integration par parties.","a":"Soient \\(u, v : [a, b] \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^1\\). Alors : \\[\\]","hint":"Integration par parties"},
  {"id":"mp10-thm-05","ch":"mp-10","chName":"Integration sur un segment","type":"thm","q":"Énoncer le théorème : Changement de variable.","a":"Soit \\(\\varphi : [\\alpha, \\beta] \\to [a, b]\\) de classe \\(\\mathcal{C}^1\\) et \\(f : [a, b] \\to \\mathbb{R}\\) continue. Alors : \\[\\]","hint":"Changement variable"},
  {"id":"mp10-thm-06","ch":"mp-10","chName":"Integration sur un segment","type":"thm","q":"Énoncer le théorème : Formule de Taylor avec reste integral.","a":"Soit \\(f : [a, b] \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^{n+1}\\). Pour tout \\(x \\in [a, b]\\) : \\[\\]","hint":"Formule Taylor avec reste..."},
  {"id":"mp10-thm-07","ch":"mp-10","chName":"Integration sur un segment","type":"thm","q":"Énoncer le théorème : Inegalite de Taylor-Lagrange.","a":"Soit \\(f : [a, b] \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^{n+1}\\). Pour tout \\(x \\in [a, b]\\) : \\[\\]","hint":"Inegalite Taylor-Lagrange"},
  {"id":"mp10-prop-06","ch":"mp-10","chName":"Integration sur un segment","type":"prop","q":"Énoncer la proposition : Formule de Taylor-Young.","a":"Soit \\(f : I \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^n\\) au voisinage de \\(a\\). Alors : \\[\\]","hint":"Formule Taylor-Young"},
  {"id":"mp10-thm-08","ch":"mp-10","chName":"Integration sur un segment","type":"thm","q":"Énoncer le théorème : Interversion limite-integrale (convergence uniforme).","a":"Soit \\((f_n)\\) une suite de fonctions continues par morceaux sur \\([a, b]\\) convergeant uniformement vers \\(f : [a,b] \\to \\mathbb{R}\\). Alors \\(f\\) est continue par morceaux et : \\[\\]","hint":"Interversion limite-integrale (convergence uniforme)"},
  {"id":"mp10-thm-09","ch":"mp-10","chName":"Integration sur un segment","type":"thm","q":"Énoncer le théorème : Integration terme a terme des series de fonctions.","a":"Soit \\((u_n)\\) une suite de fonctions continues par morceaux sur \\([a, b]\\). Si la serie \\(\\sum u_n\\) converge uniformement sur \\([a,b]\\), alors : \\[\\]","hint":"Integration terme terme des..."},
  {"id":"mp10-prop-07","ch":"mp-10","chName":"Integration sur un segment","type":"prop","q":"Énoncer la proposition : Derivation sous le signe integral.","a":"Soit \\(f : [a,b] \\times J \\to \\mathbb{R}\\) ou \\(J\\) est un intervalle ouvert. On suppose que : \\n- Pour tout \\(x \\in J\\), \\(t \\mapsto f(t, x)\\) est continue par morceaux sur \\([a,b]\\). \\n- Pour presque tout \\(t \\in [a,b]\\), \\(x \\mapsto f(t, x)\\) est derivable sur \\(J\\), de derivee partielle \\(\\frac{\\partial f}{\\partial x}(t, x)\\). \\n- La fonction \\(\\frac{\\partial f}{\\partial x}\\) est continue sur \\([a,b] \\times J\\).","hint":"Derivation sous signe integral"},
  {"id":"mp11-def-01","ch":"mp-11","chName":"Intégrales généralisées","type":"def","q":"Définir : Intégrale impropre en \\(+\\infty\\).","a":"Soit \\(f : [a, +\\infty[ \\to \\mathbb{R}\\) (ou \\(\\mathbb{C}\\)) continue par morceaux. On dit que l'intégrale impropre \\(\\displaystyle\\int_a^{+\\infty} f(t)\\,\\mathrm{d}t\\) converge si la limite suivante existe et est finie : \\[\\]","hint":"Intégrale impropre +infty"},
  {"id":"mp11-def-02","ch":"mp-11","chName":"Intégrales généralisées","type":"def","q":"Définir : Intégrale impropre en une borne finie.","a":"Soit \\(f : ]a, b] \\to \\mathbb{R}\\) continue par morceaux, non bornée au voisinage de \\(a\\). On dit que \\(\\displaystyle\\int_a^{b} f(t)\\,\\mathrm{d}t\\) converge si la limite suivante existe et est finie : \\[\\]","hint":"Intégrale impropre une borne..."},
  {"id":"mp11-def-03","ch":"mp-11","chName":"Intégrales généralisées","type":"def","q":"Définir : Intégrale doublement impropre.","a":"Si \\(f : ]a, b[ \\to \\mathbb{R}\\) présente des singularités aux deux bornes (ou si l'intervalle est \\(\\mathbb{R}\\) entier), on choisit \\(c \\in ]a, b[\\) et on pose : \\[\\]","hint":"Intégrale doublement impropre"},
  {"id":"mp11-prop-01","ch":"mp-11","chName":"Intégrales généralisées","type":"prop","q":"Énoncer la proposition : Relation de Chasles.","a":"Soit \\(f : I \\to \\mathbb{R}\\) continue par morceaux et \\(c \\in I\\). L'intégrale \\(\\displaystyle\\int_I f(t)\\,\\mathrm{d}t\\) converge si et seulement si \\(\\displaystyle\\int_{\\inf I}^{c} f(t)\\,\\mathrm{d}t\\) et \\(\\displaystyle\\int_{c}^{\\sup I} f(t)\\,\\mathrm{d}t\\) convergent toutes deux, et dans ce cas : \\[\\]","hint":"Relation Chasles"},
  {"id":"mp11-prop-02","ch":"mp-11","chName":"Intégrales généralisées","type":"prop","q":"Énoncer la proposition : Linéarité.","a":"Si \\(\\displaystyle\\int_a^{+\\infty} f(t)\\,\\mathrm{d}t\\) et \\(\\displaystyle\\int_a^{+\\infty} g(t)\\,\\mathrm{d}t\\) convergent, alors pour tous \\(\\lambda, \\mu \\in \\mathbb{R}\\), \\[\\]","hint":"Linéarité"},
  {"id":"mp11-prop-03","ch":"mp-11","chName":"Intégrales généralisées","type":"prop","q":"Énoncer la proposition : Condition nécessaire de convergence.","a":"Si \\(f\\) est continue sur \\([a, +\\infty[\\) et si \\(\\displaystyle\\int_a^{+\\infty} f(t)\\,\\mathrm{d}t\\) converge, alors la fonction \\(F : x \\mapsto \\displaystyle\\int_a^{x} f(t)\\,\\mathrm{d}t\\) admet une limite finie en \\(+\\infty\\). En revanche, on n'a pas nécessairement \\(f(t) \\to 0\\) quand \\(t \\to +\\infty\\).","hint":"Condition nécessaire convergence"},
  {"id":"mp11-def-04","ch":"mp-11","chName":"Intégrales généralisées","type":"def","q":"Définir : Convergence absolue.","a":"Soit \\(f : [a, +\\infty[ \\to \\mathbb{R}\\) (ou \\(\\mathbb{C}\\)) continue par morceaux. On dit que l'intégrale \\(\\displaystyle\\int_a^{+\\infty} f(t)\\,\\mathrm{d}t\\) converge absolument si l'intégrale \\(\\displaystyle\\int_a^{+\\infty} |f(t)|\\,\\mathrm{d}t\\) converge.","hint":"Convergence absolue"},
  {"id":"mp11-thm-01","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Convergence absolue implique convergence.","a":"Si \\(\\displaystyle\\int_a^{+\\infty} f(t)\\,\\mathrm{d}t\\) converge absolument, alors elle converge, et : \\[\\]","hint":"Convergence absolue implique convergence"},
  {"id":"mp11-def-05","ch":"mp-11","chName":"Intégrales généralisées","type":"def","q":"Définir : Fonction intégrable.","a":"On dit que \\(f\\) est intégrable sur \\([a, +\\infty[\\) (au sens des intégrales généralisées) si \\(\\displaystyle\\int_a^{+\\infty} f(t)\\,\\mathrm{d}t\\) converge absolument. On note parfois \\(f \\in L^1([a, +\\infty[)\\).","hint":"Fonction intégrable"},
  {"id":"mp11-thm-02","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Comparaison directe.","a":"Soient \\(f, g : [a, +\\infty[ \\to \\mathbb{R}\\) continues par morceaux avec \\(0 \\leqslant f(t) \\leqslant g(t)\\) pour tout \\(t \\geqslant a\\). Alors : \\n- Si \\(\\displaystyle\\int_a^{+\\infty} g(t)\\,\\mathrm{d}t\\) converge, alors \\(\\displaystyle\\int_a^{+\\infty} f(t)\\,\\mathrm{d}t\\) converge et \\(\\displaystyle\\int_a^{+\\infty} f \\leqslant \\int_a^{+\\infty} g\\). \\n- Si \\(\\displaystyle\\int_a^{+\\infty} f(t)\\,\\mathrm{d}t\\) diverge, alors \\(\\displaystyle\\int_a^{+\\infty} g(t)\\,\\mathrm{d}t\\) diverge.","hint":"Comparaison directe"},
  {"id":"mp11-thm-03","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Comparaison par équivalent.","a":"Soient \\(f, g : [a, +\\infty[ \\to \\mathbb{R}_+\\) continues par morceaux. Si \\(f(t) \\sim g(t)\\) quand \\(t \\to +\\infty\\), alors les intégrales \\(\\displaystyle\\int_a^{+\\infty} f\\) et \\(\\displaystyle\\int_a^{+\\infty} g\\) sont de même nature (toutes deux convergentes ou toutes deux divergentes).","hint":"Comparaison par équivalent"},
  {"id":"mp11-thm-04","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Comparaison par domination (grand O).","a":"Soient \\(f, g : [a, +\\infty[ \\to \\mathbb{R}\\) continues par morceaux. Si \\(f(t) = O(g(t))\\) quand \\(t \\to +\\infty\\) et si \\(\\displaystyle\\int_a^{+\\infty} |g(t)|\\,\\mathrm{d}t\\) converge, alors \\(\\displaystyle\\int_a^{+\\infty} f(t)\\,\\mathrm{d}t\\) converge absolument.","hint":"Comparaison par domination (grand"},
  {"id":"mp11-thm-05","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Critère d'Abel.","a":"Soient \\(f, g : [a, +\\infty[ \\to \\mathbb{R}\\) telles que : \\n- \\(f\\) est de classe \\(\\mathcal{C}^1\\), monotone, et \\(f(t) \\to 0\\) quand \\(t \\to +\\infty\\) \\n- \\(g\\) est continue par morceaux et la fonction \\(G : x \\mapsto \\displaystyle\\int_a^{x} g(t)\\,\\mathrm{d}t\\) est bornée Alors \\(\\displaystyle\\int_a^{+\\infty} f(t)\\,g(t)\\,\\mathrm{d}t\\) converge.","hint":"Critère d'Abel"},
  {"id":"mp11-thm-06","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Critère de Dirichlet.","a":"Soient \\(f, g : [a, +\\infty[ \\to \\mathbb{R}\\) telles que : \\n- \\(f\\) est de classe \\(\\mathcal{C}^1\\), monotone, et \\(f(t) \\to 0\\) quand \\(t \\to +\\infty\\) \\n- \\(g\\) est continue par morceaux et \\(G : x \\mapsto \\displaystyle\\int_a^{x} g(t)\\,\\mathrm{d}t\\) est bornée Alors \\(\\displaystyle\\int_a^{+\\infty} f(t)\\,g(t)\\,\\mathrm{d}t\\) converge.","hint":"Critère Dirichlet"},
  {"id":"mp11-thm-07","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Continuité sous le signe intégral.","a":"Soient \\(A \\subset \\mathbb{R}\\) un intervalle et \\(f : A \\times I \\to \\mathbb{R}\\) telle que : \\n- Pour tout \\(x \\in A\\), \\(t \\mapsto f(x, t)\\) est continue par morceaux sur \\(I\\) \\n- Pour tout \\(t \\in I\\), \\(x \\mapsto f(x, t)\\) est continue sur \\(A\\) \\n- Il existe \\(\\varphi : I \\to \\mathbb{R}_+\\) intégrable sur \\(I\\) (hypothèse de domination) telle que \\(\\forall\\,(x, t) \\in A \\times I,\\ |f(x, t)| \\leqslant \\varphi(t)\\) Alors la fonction \\(F : x \\","hint":"Continuité sous signe intégral"},
  {"id":"mp11-thm-08","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Dérivation sous le signe intégral (Leibniz).","a":"Soient \\(A \\subset \\mathbb{R}\\) un intervalle ouvert et \\(f : A \\times I \\to \\mathbb{R}\\) telle que : \\n- Pour tout \\(x \\in A\\), \\(t \\mapsto f(x, t)\\) est intégrable sur \\(I\\) \\n- Pour tout \\(t \\in I\\), \\(x \\mapsto f(x, t)\\) est de classe \\(\\mathcal{C}^1\\) sur \\(A\\) \\n- Il existe \\(\\psi : I \\to \\mathbb{R}_+\\) intégrable sur \\(I\\) (hypothèse de domination de la dérivée) telle que \\(\\forall\\,(x, t) \\in A \\times I,\\ \\left|\\frac{\\partial f}{\\partial x","hint":"Dérivation sous signe intégral..."},
  {"id":"mp11-thm-09","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Convergence dominée (admis).","a":"Soit \\((f_n)\\) une suite de fonctions continues par morceaux et intégrables sur \\(I\\) telle que : \\n- \\(f_n(t) \\to f(t)\\) pour presque tout \\(t \\in I\\) \\n- Il existe \\(\\varphi : I \\to \\mathbb{R}_+\\) intégrable sur \\(I\\) avec \\(|f_n(t)| \\leqslant \\varphi(t)\\) pour tout \\(n\\) et presque tout \\(t\\) Alors \\(f\\) est intégrable sur \\(I\\) et : \\[\\]","hint":"Convergence dominée (admis)"},
  {"id":"mp11-def-06","ch":"mp-11","chName":"Intégrales généralisées","type":"def","q":"Définir : Fonction Gamma.","a":"Pour \\(x > 0\\), on définit la fonction Gamma d'Euler par : \\[\\]","hint":"Fonction Gamma"},
  {"id":"mp11-thm-10","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Relation fonctionnelle.","a":"Pour tout \\(x > 0\\) : \\[\\]","hint":"Relation fonctionnelle"},
  {"id":"mp11-prop-04","ch":"mp-11","chName":"Intégrales généralisées","type":"prop","q":"Énoncer la proposition : Régularité.","a":"La fonction \\(\\Gamma\\) est de classe \\(\\mathcal{C}^\\infty\\) sur \\(]0, +\\infty[\\), et pour tout \\(n \\in \\mathbb{N}\\) : \\[\\]","hint":"Régularité"},
  {"id":"mp11-prop-05","ch":"mp-11","chName":"Intégrales généralisées","type":"prop","q":"Énoncer la proposition : Valeurs remarquables.","a":"\\n- \\(\\Gamma(1) = 1\\), \\(\\Gamma(2) = 1\\) \\n- \\(\\Gamma\\!\\left(\\frac{1}{2}\\right) = \\sqrt{\\pi}\\) (intégrale de Gauss) \\n- \\(\\Gamma\\!\\left(\\frac{3}{2}\\right) = \\frac{\\sqrt{\\pi}}{2}\\), \\(\\Gamma\\!\\left(\\frac{5}{2}\\right) = \\frac{3\\sqrt{\\pi}}{4}\\)","hint":"Valeurs remarquables"},
  {"id":"mp11-thm-11","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Formule de Stirling.","a":"Quand \\(n \\to +\\infty\\) : \\[\\]","hint":"Formule Stirling"},
  {"id":"mp11-def-07","ch":"mp-11","chName":"Intégrales généralisées","type":"def","q":"Définir : Fonction Bêta.","a":"Pour \\(p > 0\\) et \\(q > 0\\), on définit la fonction Bêta d'Euler par : \\[\\]","hint":"Fonction Bêta"},
  {"id":"mp11-prop-06","ch":"mp-11","chName":"Intégrales généralisées","type":"prop","q":"Énoncer la proposition : Propriétés de la fonction Bêta.","a":"\\n- Symétrie : \\(B(p, q) = B(q, p)\\) (changement de variable \\(u = 1 - t\\)) \\n- Forme trigonométrique : \\(B(p, q) = 2\\displaystyle\\int_0^{\\pi/2} (\\cos\\theta)^{2p-1}(\\sin\\theta)^{2q-1}\\,\\mathrm{d}\\theta\\) \\n- Autre forme : \\(B(p, q) = \\displaystyle\\int_0^{+\\infty} \\frac{u^{p-1}}{(1+u)^{p+q}}\\,\\mathrm{d}u\\) (substitution \\(t = \\frac{u}{1+u}\\))","hint":"Propriétés fonction Bêta"},
  {"id":"mp11-thm-12","ch":"mp-11","chName":"Intégrales généralisées","type":"thm","q":"Énoncer le théorème : Relation entre Bêta et Gamma.","a":"Pour tous \\(p > 0\\) et \\(q > 0\\) : \\[\\]","hint":"Relation entre Bêta Gamma"},
  {"id":"mp11-def-08","ch":"mp-11","chName":"Intégrales généralisées","type":"def","q":"Définir : Transformée de Laplace.","a":"Soit \\(f : [0, +\\infty[ \\to \\mathbb{R}\\) continue par morceaux. La transformée de Laplace de \\(f\\) est la fonction \\(\\mathcal{L}(f)\\) définie par : \\[\\]","hint":"Transformée Laplace"},
  {"id":"mp11-prop-07","ch":"mp-11","chName":"Intégrales généralisées","type":"prop","q":"Énoncer la proposition : Propriétés de la transformée de Laplace.","a":"\\n- Linéarité : \\(\\mathcal{L}(\\alpha f + \\beta g) = \\alpha\\,\\mathcal{L}(f) + \\beta\\,\\mathcal{L}(g)\\) \\n- Dérivation : si \\(f\\) est \\(\\mathcal{C}^1\\) et \\(f(0^+)\\) existe, alors \\(\\mathcal{L}(f')(p) = p\\,\\mathcal{L}(f)(p) - f(0^+)\\) \\n- Translation : \\(\\mathcal{L}(e^{at} f(t))(p) = \\mathcal{L}(f)(p - a)\\) \\n- Dilatation : pour \\(c > 0\\), \\(\\mathcal{L}(f(ct))(p) = \\frac{1}{c}\\,\\mathcal{L}(f)\\!\\left(\\frac{p}{c}\\right)\\)","hint":"Propriétés transformée Laplace"},
  {"id":"mp11-prop-08","ch":"mp-11","chName":"Intégrales généralisées","type":"prop","q":"Énoncer la proposition : Régularité de la transformée.","a":"Si \\(f : [0, +\\infty[ \\to \\mathbb{R}\\) est continue par morceaux et si \\(\\mathcal{L}(f)\\) converge pour \\(p > \\sigma_0\\), alors \\(F = \\mathcal{L}(f)\\) est de classe \\(\\mathcal{C}^\\infty\\) sur \\(]\\sigma_0, +\\infty[\\), et : \\[\\]","hint":"Régularité transformée"},
  {"id":"mp12-def-01","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"def","q":"Définir : Dérivée partielle.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) et \\(a = (a_1, \\ldots, a_n) \\in U\\). La dérivée partielle de \\(f\\) par rapport à la \\(i\\)-ème variable au point \\(a\\) est, si elle existe : \\[\\]","hint":"Dérivée partielle"},
  {"id":"mp12-def-02","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"def","q":"Définir : Gradient.","a":"Si toutes les dérivées partielles de \\(f : U \\to \\mathbb{R}\\) existent en \\(a\\), le gradient de \\(f\\) en \\(a\\) est le vecteur : \\[\\]","hint":"Gradient"},
  {"id":"mp12-def-03","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"def","q":"Définir : Matrice jacobienne.","a":"Soit \\(f = (f_1, \\ldots, f_p) : U \\subset \\mathbb{R}^n \\to \\mathbb{R}^p\\). Si toutes les dérivées partielles existent en \\(a\\), la matrice jacobienne de \\(f\\) en \\(a\\) est la matrice \\(J_f(a) \\in \\mathcal{M}_{p,n}(\\mathbb{R})\\) définie par : \\[\\]","hint":"Matrice jacobienne"},
  {"id":"mp12-def-04","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"def","q":"Définir : Fonction de classe \\(\\mathcal{C}^1\\).","a":"On dit que \\(f : U \\to \\mathbb{R}\\) est de classe \\(\\mathcal{C}^1\\) sur \\(U\\) si toutes les dérivées partielles \\(\\frac{\\partial f}{\\partial x_i}\\) existent et sont continues sur \\(U\\).","hint":"Fonction classe mathcal{C}^1"},
  {"id":"mp12-thm-01","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"thm","q":"Énoncer le théorème : Schwarz (symétrie des dérivées croisées).","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^2\\) sur \\(U\\). Alors pour tous \\(i, j \\in \\{1, \\ldots, n\\}\\) et tout \\(a \\in U\\) : \\[\\]","hint":"Schwarz (symétrie des dérivées..."},
  {"id":"mp12-def-05","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"def","q":"Définir : Application différentiable.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}^p\\) et \\(a \\in U\\). On dit que \\(f\\) est différentiable en \\(a\\) s'il existe une application linéaire \\(L \\in \\mathcal{L}(\\mathbb{R}^n, \\mathbb{R}^p)\\) telle que : \\[\\]","hint":"Application différentiable"},
  {"id":"mp12-prop-01","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"prop","q":"Énoncer la proposition : Différentiabilité implique continuité.","a":"Si \\(f\\) est différentiable en \\(a\\), alors \\(f\\) est continue en \\(a\\).","hint":"Différentiabilité implique continuité"},
  {"id":"mp12-prop-02","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"prop","q":"Énoncer la proposition : Lien avec les dérivées partielles.","a":"Si \\(f : U \\to \\mathbb{R}\\) est différentiable en \\(a\\), alors toutes les dérivées partielles existent en \\(a\\) et : \\[\\]","hint":"Lien avec les dérivées..."},
  {"id":"mp12-thm-02","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"thm","q":"Énoncer le théorème : Condition suffisante de différentiabilité.","a":"Si \\(f : U \\to \\mathbb{R}^p\\) admet des dérivées partielles sur \\(U\\) et si celles-ci sont continues en \\(a\\), alors \\(f\\) est différentiable en \\(a\\). En particulier : \\[\\]","hint":"Condition suffisante différentiabilité"},
  {"id":"mp12-thm-03","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"thm","q":"Énoncer le théorème : Composition (chain rule).","a":"Soient \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}^p\\) différentiable en \\(a\\) et \\(g : V \\subset \\mathbb{R}^p \\to \\mathbb{R}^q\\) différentiable en \\(f(a)\\), avec \\(f(U) \\subset V\\). Alors \\(g \\circ f\\) est différentiable en \\(a\\) et : \\[\\]","hint":"Composition (chain rule)"},
  {"id":"mp12-def-06","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"def","q":"Définir : Classe \\(\\mathcal{C}^k\\).","a":"On dit que \\(f : U \\to \\mathbb{R}\\) est de classe \\(\\mathcal{C}^1\\) sur \\(U\\) si toutes les dérivées partielles \\(\\frac{\\partial f}{\\partial x_i}\\) existent et sont continues sur \\(U\\).","hint":"Classe mathcal{C}^k"},
  {"id":"mp12-def-07","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"def","q":"Définir : Dérivées partielles d'ordre supérieur.","a":"Pour un multi-indice \\(\\alpha = (\\alpha_1, \\ldots, \\alpha_n) \\in \\mathbb{N}^n\\) de longueur \\(|\\alpha| = \\alpha_1 + \\cdots + \\alpha_n\\), on note : \\[\\]","hint":"Dérivées partielles d'ordre supérieur"},
  {"id":"mp12-thm-04","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"thm","q":"Énoncer le théorème : Schwarz (cas général).","a":"Si \\(f \\in \\mathcal{C}^k(U, \\mathbb{R})\\), alors pour tout multi-indice \\(\\alpha\\) avec \\(|\\alpha| \\leq k\\), la dérivée partielle \\(\\partial^\\alpha f\\) ne dépend pas de l'ordre dans lequel on effectue les dérivations. Autrement dit, les dérivées partielles d'ordre \\(\\leq k\\) commutent.","hint":"Schwarz (cas général)"},
  {"id":"mp12-prop-03","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"prop","q":"Énoncer la proposition : Opérations et régularité.","a":"Soient \\(f, g \\in \\mathcal{C}^k(U, \\mathbb{R})\\) et \\(\\lambda \\in \\mathbb{R}\\). Alors : \\n- \\(f + g\\), \\(\\lambda f\\), \\(f \\cdot g \\in \\mathcal{C}^k(U, \\mathbb{R})\\). \\n- Si \\(g\\) ne s'annule pas, \\(f/g \\in \\mathcal{C}^k(U, \\mathbb{R})\\). \\n- Si \\(h \\in \\mathcal{C}^k(V, \\mathbb{R}^n)\\) avec \\(h(V) \\subset U\\), alors \\(f \\circ h \\in \\mathcal{C}^k(V, \\mathbb{R})\\).","hint":"Opérations régularité"},
  {"id":"mp12-thm-05","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"thm","q":"Énoncer le théorème : Taylor-Young à l'ordre 2.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^2\\) et \\(a \\in U\\). Pour \\(h = (h_1, \\ldots, h_n) \\to 0\\) : \\[\\]","hint":"Taylor-Young l'ordre"},
  {"id":"mp12-def-08","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"def","q":"Définir : Extremum local.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\). On dit que \\(f\\) admet un minimum local en \\(a \\in U\\) s'il existe \\(r > 0\\) tel que \\(f(x) \\geq f(a)\\) pour tout \\(x \\in B(a, r) \\cap U\\). On définit de même le maximum local.","hint":"Extremum local"},
  {"id":"mp12-thm-06","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"thm","q":"Énoncer le théorème : Condition nécessaire (gradient nul).","a":"Soit \\(f : U \\to \\mathbb{R}\\) différentiable sur l'ouvert \\(U\\). Si \\(f\\) admet un extremum local en \\(a \\in U\\), alors : \\[\\]","hint":"Condition nécessaire (gradient nul)"},
  {"id":"mp12-def-09","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"def","q":"Définir : Matrice hessienne.","a":"Soit \\(f : U \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^2\\). La matrice hessienne de \\(f\\) en \\(a\\) est la matrice symétrique : \\[\\]","hint":"Matrice hessienne"},
  {"id":"mp12-thm-07","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"thm","q":"Énoncer le théorème : Conditions suffisantes (via la hessienne).","a":"Soit \\(f \\in \\mathcal{C}^2(U, \\mathbb{R})\\) et \\(a\\) un point critique de \\(f\\) (i.e. \\(\\nabla f(a) = 0\\)). \\n- Si \\(H_f(a)\\) est définie positive, alors \\(f\\) admet un minimum local strict en \\(a\\). \\n- Si \\(H_f(a)\\) est définie négative, alors \\(f\\) admet un maximum local strict en \\(a\\). \\n- Si \\(H_f(a)\\) est non dégénérée et indéfinie (valeurs propres de signes opposés), alors \\(a\\) est un point-selle.","hint":"Conditions suffisantes (via hessienne)"},
  {"id":"mp12-thm-08","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"thm","q":"Énoncer le théorème : Des fonctions implicites.","a":"Soient \\(U\\) un ouvert de \\(\\mathbb{R}^n \\times \\mathbb{R}^p\\), \\(F : U \\to \\mathbb{R}^p\\) de classe \\(\\mathcal{C}^1\\) et \\((a,b) \\in U\\) tel que \\(F(a,b) = 0\\). Si la matrice \\(\\frac{\\partial F}{\\partial y}(a,b) \\in \\mathcal{M}_p(\\mathbb{R})\\) est inversible, alors : \\n- il existe des ouverts \\(V \\ni a\\) dans \\(\\mathbb{R}^n\\) et \\(W \\ni b\\) dans \\(\\mathbb{R}^p\\) tels que pour tout \\(x \\in V\\), l'équation \\(F(x,y) = 0\\) admet une unique solution \\","hint":"Des fonctions implicites"},
  {"id":"mp12-prop-04","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"prop","q":"Énoncer la proposition : Régularité de la fonction implicite.","a":"Sous les hypothèses du théorème, si \\(F\\) est de classe \\(\\mathcal{C}^k\\) (\\(k \\geq 1\\)), alors \\(\\varphi\\) est aussi de classe \\(\\mathcal{C}^k\\). En particulier, si \\(F\\) est lisse, \\(\\varphi\\) l'est aussi.","hint":"Régularité fonction implicite"},
  {"id":"mp12-def-10","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"def","q":"Définir : Courbe de niveau, surface de niveau.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^1\\) et \\(c \\in \\mathbb{R}\\). L'ensemble de niveau \\(\\{x \\in U : f(x) = c\\}\\) est : \\n- une courbe de niveau si \\(n = 2\\), \\n- une surface de niveau si \\(n = 3\\). Si \\(\\nabla f(a) \\neq 0\\) en un point \\(a\\) de cet ensemble, alors le gradient est orthogonal à la courbe (ou surface) de niveau en \\(a\\).","hint":"Courbe niveau, surface niveau"},
  {"id":"mp12-thm-09","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"thm","q":"Énoncer le théorème : Multiplicateurs de Lagrange (une contrainte).","a":"Soient \\(f, g : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^1\\) et \\(S = \\{x \\in U : g(x) = 0\\}\\). Si \\(f_{|S}\\) admet un extremum local en \\(a \\in S\\) et si \\(\\nabla g(a) \\neq 0\\), alors il existe \\(\\lambda \\in \\mathbb{R}\\) (le multiplicateur de Lagrange) tel que : \\[\\]","hint":"Multiplicateurs Lagrange (une contrainte)"},
  {"id":"mp12-thm-10","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"thm","q":"Énoncer le théorème : Multiplicateurs de Lagrange (plusieurs contraintes).","a":"Soient \\(f : U \\to \\mathbb{R}\\) et \\(g_1, \\ldots, g_p : U \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^1\\), avec \\(p < n\\). On pose \\(S = \\{x \\in U : g_1(x) = \\cdots = g_p(x) = 0\\}\\). Si \\(f_{|S}\\) admet un extremum local en \\(a \\in S\\) et si les gradients \\(\\nabla g_1(a), \\ldots, \\nabla g_p(a)\\) sont linéairement indépendants, alors il existe \\(\\lambda_1, \\ldots, \\lambda_p \\in \\mathbb{R}\\) tels que : \\[\\]","hint":"Multiplicateurs Lagrange (plusieurs contraintes)"},
  {"id":"mp12-prop-05","ch":"mp-12","chName":"Fonctions de plusieurs variables","type":"prop","q":"Énoncer la proposition : Condition suffisante du second ordre (cas lié).","a":"Soit \\(a\\) un point critique lié avec multiplicateur \\(\\lambda\\). On considère la hessienne bordée ou, de manière équivalente, la restriction de \\(H_{\\mathcal{L}}(a)\\) au noyau de \\(J_g(a)\\) (l'espace tangent à la contrainte). Si cette forme quadratique restreinte est : \\n- définie positive : \\(a\\) est un minimum local de \\(f\\) sur \\(S\\) ; \\n- définie négative : \\(a\\) est un maximum local de \\(f\\) sur \\(S\\).","hint":"Condition suffisante second ordre..."},
  {"id":"mp13-def-01","ch":"mp-13","chName":"Séries de Fourier","type":"def","q":"Définir : Produit scalaire sur les fonctions \\(T\\)-périodiques.","a":"On munit l'espace \\(\\mathcal{E}\\) des fonctions \\(T\\)-périodiques continues par morceaux du produit scalaire hermitien : \\[\\]","hint":"Produit scalaire sur les..."},
  {"id":"mp13-prop-01","ch":"mp-13","chName":"Séries de Fourier","type":"prop","q":"Énoncer la proposition : Système orthonormal des exponentielles.","a":"La famille \\((e_n)_{n \\in \\mathbb{Z}}\\) définie par \\(e_n(t) = e^{in\\omega t}\\) forme un système orthonormal pour le produit scalaire ci-dessus : \\[\\]","hint":"Système orthonormal des exponentielles"},
  {"id":"mp13-def-02","ch":"mp-13","chName":"Séries de Fourier","type":"def","q":"Définir : Coefficients de Fourier exponentiels.","a":"Les coefficients de Fourier de \\(f\\) sont les nombres complexes : \\[\\]","hint":"Coefficients Fourier exponentiels"},
  {"id":"mp13-def-03","ch":"mp-13","chName":"Séries de Fourier","type":"def","q":"Définir : Coefficients réels \\(a_n\\), \\(b_n\\).","a":"Les coefficients de Fourier de \\(f\\) sont les nombres complexes : \\[\\]","hint":"Coefficients réels a_n, b_n"},
  {"id":"mp13-prop-02","ch":"mp-13","chName":"Séries de Fourier","type":"prop","q":"Énoncer la proposition : Lien entre coefficients réels et complexes.","a":"Pour \\(n \\geqslant 1\\) : \\[\\]","hint":"Lien entre coefficients réels..."},
  {"id":"mp13-prop-03","ch":"mp-13","chName":"Séries de Fourier","type":"prop","q":"Énoncer la proposition : Parité et coefficients de Fourier.","a":"Soit \\(f\\) une fonction \\(T\\)-périodique continue par morceaux à valeurs réelles. \\n- Si \\(f\\) est paire, alors \\(b_n = 0\\) pour tout \\(n \\geqslant 1\\), et \\(a_n = \\frac{4}{T} \\int_0^{T/2} f(t) \\cos(n\\omega t)\\, \\mathrm{d}t\\). La série de Fourier est une série en cosinus. \\n- Si \\(f\\) est impaire, alors \\(a_n = 0\\) pour tout \\(n \\geqslant 0\\), et \\(b_n = \\frac{4}{T} \\int_0^{T/2} f(t) \\sin(n\\omega t)\\, \\mathrm{d}t\\). La série de Fourier est une série en sinus.","hint":"Parité coefficients Fourier"},
  {"id":"mp13-def-04","ch":"mp-13","chName":"Séries de Fourier","type":"def","q":"Définir : Fonction \\(\\mathcal{C}^1\\) par morceaux.","a":"Une fonction \\(f : [a, b] \\to \\mathbb{C}\\) est dite \\(\\mathcal{C}^1\\) par morceaux s'il existe une subdivision \\(a = a_0 En particulier, \\(f\\) admet des limites à gauche et à droite en chaque point de discontinuité.","hint":"Fonction mathcal{C}^1 par morceaux"},
  {"id":"mp13-thm-01","ch":"mp-13","chName":"Séries de Fourier","type":"thm","q":"Énoncer le théorème : Théorème de Dirichlet (convergence ponctuelle).","a":"Soit \\(f\\) une fonction \\(T\\)-périodique et \\(\\mathcal{C}^1\\) par morceaux. Alors pour tout \\(t \\in \\mathbb{R}\\) : \\[\\]","hint":"Théorème Dirichlet (convergence ponctuelle)"},
  {"id":"mp13-prop-04","ch":"mp-13","chName":"Séries de Fourier","type":"prop","q":"Énoncer la proposition : Lemme de Riemann-Lebesgue.","a":"Soit \\(g : [a, b] \\to \\mathbb{C}\\) continue par morceaux. Alors : \\[\\]","hint":"Lemme Riemann-Lebesgue"},
  {"id":"mp13-prop-05","ch":"mp-13","chName":"Séries de Fourier","type":"prop","q":"Énoncer la proposition : Non-uniformité de la convergence.","a":"Si \\(f\\) est \\(\\mathcal{C}^1\\) par morceaux et présente au moins une discontinuité, alors la convergence de la série de Fourier est ponctuelle mais pas uniforme sur tout \\(\\mathbb{R}\\) (à cause du phénomène de Gibbs).","hint":"Non-uniformité convergence"},
  {"id":"mp13-thm-02","ch":"mp-13","chName":"Séries de Fourier","type":"thm","q":"Énoncer le théorème : Inégalité de Bessel.","a":"Pour toute fonction \\(f\\) \\(T\\)-périodique et continue par morceaux : \\[\\]","hint":"Inégalité Bessel"},
  {"id":"mp13-thm-03","ch":"mp-13","chName":"Séries de Fourier","type":"thm","q":"Énoncer le théorème : Égalité de Parseval.","a":"Pour toute fonction \\(f\\) \\(T\\)-périodique et continue par morceaux : \\[\\]","hint":"Égalité Parseval"},
  {"id":"mp13-prop-06","ch":"mp-13","chName":"Séries de Fourier","type":"prop","q":"Énoncer la proposition : Formule de Parseval généralisée.","a":"Pour \\(f, g\\) deux fonctions \\(T\\)-périodiques continues par morceaux : \\[\\]","hint":"Formule Parseval généralisée"},
  {"id":"mp13-thm-04","ch":"mp-13","chName":"Séries de Fourier","type":"thm","q":"Énoncer le théorème : Convergence normale de la série de Fourier.","a":"Si \\(\\displaystyle\\sum_{n=-\\infty}^{+\\infty} |c_n(f)| Si de plus \\(f\\) est continue, alors la série converge normalement vers \\(f\\) : \\[\\]","hint":"Convergence normale série Fourier"},
  {"id":"mp13-thm-05","ch":"mp-13","chName":"Séries de Fourier","type":"thm","q":"Énoncer le théorème : Décroissance des coefficients selon la régularité.","a":"Soit \\(f\\) une fonction \\(T\\)-périodique de classe \\(\\mathcal{C}^k\\) (avec \\(k \\geqslant 1\\)). Alors : \\[\\]","hint":"Décroissance des coefficients selon..."},
  {"id":"mp13-prop-07","ch":"mp-13","chName":"Séries de Fourier","type":"prop","q":"Énoncer la proposition : Critère suffisant de CVN.","a":"Si \\(f\\) est \\(T\\)-périodique et de classe \\(\\mathcal{C}^2\\), alors \\(c_n(f) = O(1/n^2)\\) et la série \\(\\sum |c_n(f)|\\) converge (car \\(\\sum 1/n^2\\) converge). Donc la série de Fourier de \\(f\\) converge normalement vers \\(f\\). Plus généralement, si \\(f \\in \\mathcal{C}^k\\) avec \\(k \\geqslant 2\\), la série de Fourier converge normalement.","hint":"Critère suffisant CVN"},
  {"id":"mp13-def-05","ch":"mp-13","chName":"Séries de Fourier","type":"def","q":"Définir : Fonction créneau.","a":"Fonction \\(2\\pi\\)-périodique impaire définie par \\(f(t) = 1\\) si \\(t \\in\\, ]0, \\pi[\\) et \\(f(t) = -1\\) si \\(t \\in\\, ]-\\pi, 0[\\), \\(f(0) = f(\\pi) = 0\\).","hint":"Fonction créneau"},
  {"id":"mp13-thm-06","ch":"mp-13","chName":"Séries de Fourier","type":"thm","q":"Énoncer le théorème : DSF du créneau.","a":"Les coefficients réels sont \\(a_n = 0\\) et \\(b_n = \\frac{2}{n\\pi}(1 - (-1)^n)\\), donc \\(b_{2k} = 0\\) et \\(b_{2k+1} = \\frac{4}{\\pi(2k+1)}\\). La série de Fourier est : \\[\\]","hint":"DSF créneau"},
  {"id":"mp13-thm-07","ch":"mp-13","chName":"Séries de Fourier","type":"thm","q":"Énoncer le théorème : DSF de la dent de scie.","a":"Pour \\(f(t) = t\\) sur \\(]-\\pi, \\pi]\\), prolongée par \\(2\\pi\\)-périodicité : \\[\\]","hint":"DSF dent scie"},
  {"id":"mp13-thm-08","ch":"mp-13","chName":"Séries de Fourier","type":"thm","q":"Énoncer le théorème : DSF de \\(|t|\\).","a":"Pour \\(f(t) = |t|\\) sur \\(]-\\pi, \\pi]\\), fonction paire. On a \\(a_0 = \\frac{\\pi}{2}\\), \\(b_n = 0\\), et \\(a_{2k} = 0\\), \\(a_{2k+1} = -\\frac{4}{\\pi(2k+1)^2}\\) : \\[|t| = \\frac{\\pi}{2} - \\frac{4}{\\pi} \\sum_{k=0}^{+\\infty} \\frac{\\cos((2k+1)t)}{(2k+1)^2}\\] En \\(t = 0\\) : \\(\\sum_{k=0}^{+\\infty} \\frac{1}{(2k+1)^2} = \\frac{\\pi^2}{8}\\).","hint":"DSF de |t|, cosinus impairs"},
  {"id":"mp13-thm-09","ch":"mp-13","chName":"Séries de Fourier","type":"thm","q":"Énoncer le théorème : DSF de \\(t^2\\).","a":"Pour \\(f(t) = t^2\\) sur \\(]-\\pi, \\pi]\\), fonction paire. On a \\(a_0 = \\frac{\\pi^2}{3}\\), \\(b_n = 0\\), et \\(a_n = \\frac{4(-1)^n}{n^2}\\) : \\[t^2 = \\frac{\\pi^2}{3} + 4 \\sum_{n=1}^{+\\infty} \\frac{(-1)^n}{n^2} \\cos(nt)\\] En \\(t = 0\\) : \\(\\sum \\frac{(-1)^{n+1}}{n^2} = \\frac{\\pi^2}{12}\\). En \\(t = \\pi\\) : \\(\\sum \\frac{1}{n^2} = \\frac{\\pi^2}{6}\\). Parseval : \\(\\sum \\frac{1}{n^4} = \\frac{\\pi^4}{90}\\).","hint":"DSF de t^2, zeta(2) et zeta(4)"},
  {"id":"mp13-thm-10","ch":"mp-13","chName":"Séries de Fourier","type":"thm","q":"Énoncer le théorème : DSF de \\(t^3\\).","a":"Pour \\(f(t) = t^3\\) sur \\(]-\\pi, \\pi]\\), fonction impaire. On a \\(a_n = 0\\) et \\(b_n = \\frac{2(-1)^{n+1}}{n}\\left(\\pi^2 - \\frac{6}{n^2}\\right)\\) : \\[t^3 = 2\\sum_{n=1}^{+\\infty} (-1)^{n+1}\\left(\\frac{\\pi^2}{n} - \\frac{6}{n^3}\\right) \\sin(nt)\\]","hint":"DSF de t^3, fonction impaire"},
  {"id":"mp13-thm-11","ch":"mp-13","chName":"Séries de Fourier","type":"thm","q":"Énoncer le théorème : Isomorphisme hilbertien.","a":"L'application qui à une fonction \\(f\\) \\(T\\)-périodique de carré intégrable associe la suite de ses coefficients de Fourier \\((c_n(f))_{n \\in \\mathbb{Z}}\\) réalise une isométrie de l'espace \\(L^2_T\\) (muni du produit scalaire \\(\\langle \\cdot, \\cdot \\rangle\\)) sur l'espace \\(\\ell^2(\\mathbb{Z})\\) (muni du produit scalaire \\(\\langle u, v \\rangle_{\\ell^2} = \\sum_{n \\in \\mathbb{Z}} u_n \\overline{v_n}\\)).","hint":"Isomorphisme hilbertien"},
  {"id":"mp14-def-01","ch":"mp-14","chName":"Familles sommables","type":"def","q":"Définir : Somme d'une famille de réels positifs.","a":"Soit \\((a_i)_{i \\in I}\\) une famille de réels positifs. On définit la somme de cette famille par : \\[\\]","hint":"Somme d'une famille réels..."},
  {"id":"mp14-prop-01","ch":"mp-14","chName":"Familles sommables","type":"prop","q":"Énoncer la proposition : Propriétés élémentaires.","a":"Soient \\((a_i)_{i \\in I}\\) et \\((b_i)_{i \\in I}\\) deux familles de réels positifs, et \\(\\lambda \\geq 0\\). Alors : \\n- Positivité : \\(\\sum_{i \\in I} a_i \\geq 0\\), avec égalité si et seulement si \\(a_i = 0\\) pour tout \\(i \\in I\\). \\n- Homogénéité : \\(\\sum_{i \\in I} \\lambda a_i = \\lambda \\sum_{i \\in I} a_i\\). \\n- Additivité : \\(\\sum_{i \\in I} (a_i + b_i) = \\sum_{i \\in I} a_i + \\sum_{i \\in I} b_i\\).","hint":"Propriétés élémentaires"},
  {"id":"mp14-thm-01","ch":"mp-14","chName":"Familles sommables","type":"thm","q":"Énoncer le théorème : Sommation par paquets (cas positif).","a":"Soit \\((I_k)_{k \\in K}\\) une partition de \\(I\\). Alors : \\[\\]","hint":"Sommation par paquets (cas..."},
  {"id":"mp14-prop-02","ch":"mp-14","chName":"Familles sommables","type":"prop","q":"Énoncer la proposition : Critère de sommabilité par comparaison.","a":"Soient \\((a_i)_{i \\in I}\\) et \\((b_i)_{i \\in I}\\) deux familles de réels positifs telles que \\(a_i \\leq b_i\\) pour tout \\(i \\in I\\). Si \\((b_i)\\) est sommable, alors \\((a_i)\\) est sommable et \\(\\sum a_i \\leq \\sum b_i\\).","hint":"Critère sommabilité par comparaison"},
  {"id":"mp14-def-02","ch":"mp-14","chName":"Familles sommables","type":"def","q":"Définir : Famille absolument sommable.","a":"Soit \\(E\\) un espace vectoriel normé et \\((a_i)_{i \\in I}\\) une famille d'éléments de \\(E\\). On dit que \\((a_i)\\) est sommable (ou absolument sommable) si la famille \\((\\|a_i\\|)_{i \\in I}\\) de réels positifs est sommable, c'est-à-dire si : \\[\\]","hint":"Famille absolument sommable"},
  {"id":"mp14-def-03","ch":"mp-14","chName":"Familles sommables","type":"def","q":"Définir : Somme d'une famille sommable.","a":"Si \\((a_i)_{i \\in I}\\) est sommable, on définit sa somme par passage à la limite sur les sommes finies. Plus précisément, \\(S = \\sum_{i \\in I} a_i\\) est l'unique élément de \\(E\\) tel que : \\[\\]","hint":"Somme d'une famille sommable"},
  {"id":"mp14-thm-02","ch":"mp-14","chName":"Familles sommables","type":"thm","q":"Énoncer le théorème : Convergence commutative.","a":"Soit \\((a_n)_{n \\in \\mathbb{N}}\\) une famille sommable dans un espace vectoriel normé complet \\(E\\). Alors pour toute bijection \\(\\sigma : \\mathbb{N} \\to \\mathbb{N}\\) : \\[\\]","hint":"Convergence commutative"},
  {"id":"mp14-prop-03","ch":"mp-14","chName":"Familles sommables","type":"prop","q":"Énoncer la proposition : Opérations sur les familles sommables.","a":"Soient \\((a_i)_{i \\in I}\\) et \\((b_i)_{i \\in I}\\) des familles sommables dans \\(E\\) et \\(\\lambda \\in \\mathbb{K}\\). Alors : \\n- \\((a_i + b_i)\\) est sommable et \\(\\sum (a_i + b_i) = \\sum a_i + \\sum b_i\\). \\n- \\((\\lambda a_i)\\) est sommable et \\(\\sum \\lambda a_i = \\lambda \\sum a_i\\). \\n- \\(\\left\\| \\sum_{i \\in I} a_i \\right\\| \\leq \\sum_{i \\in I} \\|a_i\\|\\) (inégalité triangulaire).","hint":"Opérations sur les familles..."},
  {"id":"mp14-prop-04","ch":"mp-14","chName":"Familles sommables","type":"prop","q":"Énoncer la proposition : Sommation par paquets (cas général).","a":"Soit \\((a_i)_{i \\in I}\\) une famille sommable dans \\(E\\) et \\((I_k)_{k \\in K}\\) une partition de \\(I\\). Alors chaque sous-famille \\((a_i)_{i \\in I_k}\\) est sommable, la famille \\(\\left(\\sum_{i \\in I_k} a_i\\right)_{k \\in K}\\) est sommable, et : \\[\\]","hint":"Sommation par paquets (cas..."},
  {"id":"mp14-thm-03","ch":"mp-14","chName":"Familles sommables","type":"thm","q":"Énoncer le théorème : Fubini discret.","a":"Soit \\((a_{i,j})_{(i,j) \\in I \\times J}\\) une famille sommable dans \\(\\mathbb{C}\\) (ou un evn complet). Alors : \\n- Pour tout \\(i \\in I\\), la famille \\((a_{i,j})_{j \\in J}\\) est sommable. \\n- Pour tout \\(j \\in J\\), la famille \\((a_{i,j})_{i \\in I}\\) est sommable. \\n- La famille \\(\\left(\\sum_{j \\in J} a_{i,j}\\right)_{i \\in I}\\) est sommable. \\n- La famille \\(\\left(\\sum_{i \\in I} a_{i,j}\\right)_{j \\in J}\\) est sommable.","hint":"Fubini discret"},
  {"id":"mp14-prop-05","ch":"mp-14","chName":"Familles sommables","type":"prop","q":"Énoncer la proposition : Critère de sommabilité pour les sommes doubles.","a":"Soit \\((a_{i,j})_{(i,j) \\in I \\times J}\\) une famille à valeurs complexes. Les conditions suivantes sont équivalentes : \\n- La famille \\((a_{i,j})\\) est sommable. \\n- \\(\\sum_{i \\in I} \\left( \\sum_{j \\in J} |a_{i,j}| \\right) < +\\infty\\). \\n- \\(\\sum_{j \\in J} \\left( \\sum_{i \\in I} |a_{i,j}| \\right) < +\\infty\\).","hint":"Critère sommabilité pour les..."},
  {"id":"mp14-thm-04","ch":"mp-14","chName":"Familles sommables","type":"thm","q":"Énoncer le théorème : Produit de Cauchy généralisé.","a":"Soient \\((a_i)_{i \\in I}\\) et \\((b_j)_{j \\in J}\\) deux familles sommables dans \\(\\mathbb{C}\\). Alors la famille \\((a_i b_j)_{(i,j) \\in I \\times J}\\) est sommable et : \\[\\]","hint":"Produit Cauchy généralisé"},
  {"id":"mp14-thm-05","ch":"mp-14","chName":"Familles sommables","type":"thm","q":"Énoncer le théorème : Sommabilité et convergence absolue.","a":"Soit \\((a_n)_{n \\in \\mathbb{N}}\\) une suite à valeurs dans un espace vectoriel normé complet \\(E\\). Alors : \\[\\]","hint":"Sommabilité convergence absolue"},
  {"id":"mp14-prop-06","ch":"mp-14","chName":"Familles sommables","type":"prop","q":"Énoncer la proposition : Réduction au cas dénombrable.","a":"Soit \\((a_i)_{i \\in I}\\) une famille sommable dans un evn. Alors : \\n- Le support \\(S = \\{i \\in I \\mid a_i \\neq 0\\}\\) est au plus dénombrable. \\n- \\(\\sum_{i \\in I} a_i = \\sum_{i \\in S} a_i\\). \\n- Si \\(S = \\{i_0, i_1, i_2, \\ldots\\}\\) est une énumération de \\(S\\), alors \\(\\sum_{i \\in I} a_i = \\sum_{n=0}^{+\\infty} a_{i_n}\\), et cette valeur est indépendante de l'énumération choisie.","hint":"Réduction cas dénombrable"},
  {"id":"mp14-thm-06","ch":"mp-14","chName":"Familles sommables","type":"thm","q":"Énoncer le théorème : Réarrangement de Riemann.","a":"Soit \\(\\sum a_n\\) une série réelle semi-convergente (convergente mais non absolument convergente). Alors pour tout \\(\\ell \\in \\mathbb{R} \\cup \\{-\\infty, +\\infty\\}\\), il existe une bijection \\(\\sigma : \\mathbb{N} \\to \\mathbb{N}\\) telle que : \\[\\]","hint":"Réarrangement Riemann"},
  {"id":"mp14-prop-07","ch":"mp-14","chName":"Familles sommables","type":"prop","q":"Énoncer la proposition : Interversion série-intégrale discrète.","a":"Soit \\((f_n)_{n \\geq 0}\\) une suite de fonctions de \\(I\\) dans \\(\\mathbb{C}\\) et \\((a_i)_{i \\in I}\\) une famille sommable. Si la famille \\((a_i f_n(i))_{(i,n) \\in I \\times \\mathbb{N}}\\) est sommable, alors : \\[\\]","hint":"Interversion série-intégrale discrète"},
  {"id":"mp14-def-04","ch":"mp-14","chName":"Familles sommables","type":"def","q":"Définir : Série de Dirichlet.","a":"Une série de Dirichlet est une série de la forme : \\[\\]","hint":"Série Dirichlet"},
  {"id":"mp14-prop-08","ch":"mp-14","chName":"Familles sommables","type":"prop","q":"Énoncer la proposition : Abscisse de convergence absolue.","a":"Pour toute série de Dirichlet \\(\\sum a_n / n^s\\), il existe \\(\\sigma_a \\in \\mathbb{R} \\cup \\{-\\infty, +\\infty\\}\\) appelée abscisse de convergence absolue telle que : \\n- Si \\(\\mathrm{Re}(s) > \\sigma_a\\), la série converge absolument (la famille est sommable). \\n- Si \\(\\mathrm{Re}(s) < \\sigma_a\\), la série ne converge pas absolument.","hint":"Abscisse convergence absolue"},
  {"id":"mp14-def-05","ch":"mp-14","chName":"Familles sommables","type":"def","q":"Définir : Produit infini.","a":"Soit \\((u_n)_{n \\geq 1}\\) une suite de complexes non nuls. On dit que le produit infini \\(\\prod_{n=1}^{+\\infty} u_n\\) converge si la suite des produits partiels \\(\\prod_{n=1}^{N} u_n\\) admet une limite finie non nulle. Si \\(u_n = 1 + a_n\\) avec \\(a_n \\to 0\\), on dit que le produit est absolument convergent si \\(\\sum |a_n| < +\\infty\\).","hint":"Produit infini"},
  {"id":"mp14-prop-09","ch":"mp-14","chName":"Familles sommables","type":"prop","q":"Énoncer la proposition : Lien logarithmique.","a":"Si \\(u_n = 1 + a_n\\) avec \\(|a_n| < 1\\) à partir d'un certain rang et \\(\\sum a_n\\) absolument convergente, alors le produit \\(\\prod (1 + a_n)\\) converge absolument, et : \\[\\]","hint":"Lien logarithmique"},
  {"id":"mp14-thm-07","ch":"mp-14","chName":"Familles sommables","type":"thm","q":"Énoncer le théorème : Formule du produit d'Euler.","a":"Pour tout \\(s \\in \\mathbb{R}\\) avec \\(s > 1\\) (ou plus généralement \\(s \\in \\mathbb{C}\\) avec \\(\\mathrm{Re}(s) > 1\\)), on a : \\[\\]","hint":"Formule produit d'Euler"},
  {"id":"mp15-def-01","ch":"mp-15","chName":"Séries de fonctions","type":"def","q":"Définir : Convergence simple d'une série de fonctions.","a":"La série de fonctions \\(\\sum f_n\\) converge simplement sur \\(A\\) si, pour tout \\(x \\in A\\), la série numérique \\(\\sum f_n(x)\\) converge. La somme est alors la fonction \\(S : A \\to \\mathbb{R}\\) définie par : \\[\\]","hint":"Convergence simple d'une série..."},
  {"id":"mp15-def-02","ch":"mp-15","chName":"Séries de fonctions","type":"def","q":"Définir : Convergence uniforme d'une série de fonctions.","a":"La série \\(\\sum f_n\\) converge uniformément sur \\(A\\) si la suite des sommes partielles \\((S_N)\\) converge uniformément sur \\(A\\), c'est-à-dire : \\[\\]","hint":"Convergence uniforme d'une série..."},
  {"id":"mp15-def-03","ch":"mp-15","chName":"Séries de fonctions","type":"def","q":"Définir : Convergence normale d'une série de fonctions.","a":"La série \\(\\sum f_n\\) converge normalement sur \\(A\\) si la série numérique à termes positifs \\(\\sum \\|f_n\\|_\\infty\\) converge, où \\(\\|f_n\\|_\\infty = \\sup_{x \\in A} |f_n(x)|\\).","hint":"Convergence normale d'une série..."},
  {"id":"mp15-thm-01","ch":"mp-15","chName":"Séries de fonctions","type":"thm","q":"Énoncer le théorème : CVN \\(\\Rightarrow\\) CVU \\(\\Rightarrow\\) CVS.","a":"On a les implications strictes suivantes : \\[\\]","hint":"CVN Rightarrow CVU Rightarrow..."},
  {"id":"mp15-thm-02","ch":"mp-15","chName":"Séries de fonctions","type":"thm","q":"Énoncer le théorème : Critère de Weierstrass (comparaison pour la CVN).","a":"S'il existe une suite \\((\\alpha_n)\\) de réels positifs telle que : \\n- \\(\\forall\\, n \\in \\mathbb{N},\\ \\forall\\, x \\in A, \\quad |f_n(x)| \\leqslant \\alpha_n\\) \\n- \\(\\sum \\alpha_n\\) converge alors la série \\(\\sum f_n\\) converge normalement (donc uniformément) sur \\(A\\).","hint":"Critère Weierstrass (comparaison pour..."},
  {"id":"mp15-prop-01","ch":"mp-15","chName":"Séries de fonctions","type":"prop","q":"Énoncer la proposition : Condition nécessaire de CVU.","a":"Si la série \\(\\sum f_n\\) converge uniformément sur \\(A\\), alors \\(\\|f_n\\|_\\infty \\to 0\\). Autrement dit, la suite \\((f_n)\\) converge uniformément vers \\(0\\) sur \\(A\\). C'est l'analogue du critère du terme général pour les séries numériques. La contraposée est utile : si \\(\\|f_n\\|_\\infty \\not\\to 0\\), la convergence n'est pas uniforme.","hint":"Condition nécessaire CVU"},
  {"id":"mp15-thm-03","ch":"mp-15","chName":"Séries de fonctions","type":"thm","q":"Énoncer le théorème : Continuité de la somme d'une série uniformément convergente.","a":"Soit \\(\\sum f_n\\) une série de fonctions continues sur \\(A\\). Si la série \\(\\sum f_n\\) converge uniformément sur \\(A\\), alors la somme \\(S = \\sum_{n=0}^{+\\infty} f_n\\) est continue sur \\(A\\).","hint":"Continuité somme d'une série..."},
  {"id":"mp15-prop-02","ch":"mp-15","chName":"Séries de fonctions","type":"prop","q":"Énoncer la proposition : Continuité sur tout compact via CVN.","a":"Si les \\(f_n\\) sont continues sur un ouvert \\(U\\) de \\(\\mathbb{R}\\) et si \\(\\sum f_n\\) converge normalement sur tout compact \\(K \\subset U\\), alors la somme \\(S\\) est continue sur \\(U\\). En effet, la continuité est une propriété locale : pour montrer que \\(S\\) est continue en \\(a \\in U\\), il suffit de travailler sur un voisinage compact de \\(a\\), sur lequel la CVN donne la CVU.","hint":"Continuité sur tout compact..."},
  {"id":"mp15-thm-04","ch":"mp-15","chName":"Séries de fonctions","type":"thm","q":"Énoncer le théorème : Intégration terme à terme sur un segment.","a":"Soient \\(f_n : [a, b] \\to \\mathbb{R}\\) des fonctions continues par morceaux. Si la série \\(\\sum f_n\\) converge uniformément sur \\([a, b]\\), alors la somme \\(S = \\sum_{n=0}^{+\\infty} f_n\\) est continue par morceaux et : \\[\\]","hint":"Intégration terme terme sur..."},
  {"id":"mp15-thm-05","ch":"mp-15","chName":"Séries de fonctions","type":"thm","q":"Énoncer le théorème : Intégration terme à terme sur un intervalle quelconque.","a":"Soient \\(f_n : I \\to \\mathbb{R}\\) des fonctions continues par morceaux sur un intervalle \\(I\\) (éventuellement non borné ou ouvert). Si : \\n- \\(\\sum f_n\\) converge simplement sur \\(I\\), \\n- il existe \\(\\varphi : I \\to \\mathbb{R}_+\\) intégrable sur \\(I\\) telle que pour tout \\(N\\) et tout \\(t \\in I\\), \\(\\left|\\sum_{n=0}^{N} f_n(t)\\right| \\leqslant \\varphi(t)\\), alors chaque \\(f_n\\) est intégrable sur \\(I\\), la somme \\(S\\) est intégrable sur \\(I\\), l","hint":"Intégration terme terme sur..."},
  {"id":"mp15-thm-06","ch":"mp-15","chName":"Séries de fonctions","type":"thm","q":"Énoncer le théorème : Dérivation terme à terme d'une série de fonctions.","a":"Soient \\(f_n : I \\to \\mathbb{R}\\) des fonctions de classe \\(\\mathcal{C}^1\\) sur un intervalle \\(I\\). On suppose : \\n- (H1) Il existe \\(x_0 \\in I\\) tel que la série \\(\\sum f_n(x_0)\\) converge (convergence simple en un point). \\n- (H2) La série des dérivées \\(\\sum f_n'\\) converge uniformément sur tout segment de \\(I\\). Alors : \\n- La série \\(\\sum f_n\\) converge uniformément sur tout segment de \\(I\\).","hint":"Dérivation terme terme d'une..."},
  {"id":"mp15-prop-03","ch":"mp-15","chName":"Séries de fonctions","type":"prop","q":"Énoncer la proposition : Dérivation terme à terme \\(\\mathcal{C}^k\\).","a":"Soient \\(f_n : [a, b] \\to \\mathbb{R}\\) des fonctions continues par morceaux. Si la série \\(\\sum f_n\\) converge uniformément sur \\([a, b]\\), alors la somme \\(S = \\sum_{n=0}^{+\\infty} f_n\\) est continue par morceaux et : \\[\\]","hint":"Dérivation terme terme mathcal{C}^k"},
  {"id":"mp15-def-04","ch":"mp-15","chName":"Séries de fonctions","type":"def","q":"Définir : Rayon de convergence.","a":"Le rayon de convergence de la série entière \\(\\sum a_n x^n\\) est : \\[\\]","hint":"Rayon convergence"},
  {"id":"mp15-prop-04","ch":"mp-15","chName":"Séries de fonctions","type":"prop","q":"Énoncer la proposition : Détermination du rayon de convergence.","a":"Si \\(a_n \\neq 0\\) à partir d'un certain rang et \\(\\frac{|a_{n+1}|}{|a_n|} \\to \\ell\\), alors \\(R = \\frac{1}{\\ell}\\). Plus généralement, \\(\\frac{1}{R} = \\limsup_{n \\to +\\infty} |a_n|^{1/n}\\) (formule de Hadamard).","hint":"Détermination rayon convergence"},
  {"id":"mp15-thm-07","ch":"mp-15","chName":"Séries de fonctions","type":"thm","q":"Énoncer le théorème : CVN sur tout compact de \\(]-R, R[\\).","a":"Si les \\(f_n\\) sont continues sur un ouvert \\(U\\) de \\(\\mathbb{R}\\) et si \\(\\sum f_n\\) converge normalement sur tout compact \\(K \\subset U\\), alors la somme \\(S\\) est continue sur \\(U\\). En effet, la continuité est une propriété locale : pour montrer que \\(S\\) est continue en \\(a \\in U\\), il suffit de travailler sur un voisinage compact de \\(a\\), sur lequel la CVN donne la CVU.","hint":"CVN sur tout compact..."},
  {"id":"mp15-thm-08","ch":"mp-15","chName":"Séries de fonctions","type":"thm","q":"Énoncer le théorème : Régularité \\(\\mathcal{C}^\\infty\\) des séries entières.","a":"Soit \\(S(x) = \\sum_{n=0}^{+\\infty} a_n x^n\\) de rayon \\(R > 0\\). Alors : \\n- \\(S\\) est de classe \\(\\mathcal{C}^\\infty\\) sur \\(]-R, R[\\). \\n- On peut dériver terme à terme à tout ordre : pour tout \\(k \\in \\mathbb{N}\\), \\[\\]","hint":"Régularité mathcal{C}^infty des séries..."},
  {"id":"mp15-def-05","ch":"mp-15","chName":"Séries de fonctions","type":"def","q":"Définir : Développement en série entière (DSE).","a":"On dit qu'une fonction \\(f\\) admet un développement en série entière (DSE) au voisinage de \\(0\\) s'il existe une suite \\((a_n)\\) et \\(r > 0\\) tels que, pour tout \\(x \\in ]-r, r[\\) : \\[\\]","hint":"Développement série entière (DSE)"},
  {"id":"mp15-def-06","ch":"mp-15","chName":"Séries de fonctions","type":"def","q":"Définir : Fonction zêta de Riemann.","a":"La fonction zêta de Riemann est définie par : \\[\\]","hint":"Fonction zêta Riemann"},
  {"id":"mp15-prop-05","ch":"mp-15","chName":"Séries de fonctions","type":"prop","q":"Énoncer la proposition : Régularité de \\(\\zeta\\).","a":"Soit \\(S(x) = \\sum_{n=0}^{+\\infty} a_n x^n\\) de rayon \\(R > 0\\). Alors : \\n- \\(S\\) est de classe \\(\\mathcal{C}^\\infty\\) sur \\(]-R, R[\\). \\n- On peut dériver terme à terme à tout ordre : pour tout \\(k \\in \\mathbb{N}\\), \\[\\]","hint":"Régularité zeta"},
  {"id":"mp15-thm-09","ch":"mp-15","chName":"Séries de fonctions","type":"thm","q":"Énoncer le théorème : Série de Weierstrass.","a":"Soient \\(a \\in ]0, 1[\\) et \\(b\\) un entier impair tel que \\(ab > 1 + \\frac{3\\pi}{2}\\). La fonction : \\[\\]","hint":"Série Weierstrass"},
  {"id":"mp15-thm-10","ch":"mp-15","chName":"Séries de fonctions","type":"thm","q":"Énoncer le théorème : Théorème de Weierstrass (approximation polynomiale).","a":"Toute fonction continue \\(f : [a, b] \\to \\mathbb{R}\\) est limite uniforme d'une suite de polynômes. Autrement dit, pour tout \\(\\varepsilon > 0\\), il existe un polynôme \\(P\\) tel que \\(\\|f - P\\|_\\infty \\leqslant \\varepsilon\\).","hint":"Théorème Weierstrass (approximation polynomiale)"},
  {"id":"mp15-prop-06","ch":"mp-15","chName":"Séries de fonctions","type":"prop","q":"Énoncer la proposition : Approximation trigonométrique.","a":"Toute fonction continue \\(2\\pi\\)-périodique \\(f : \\mathbb{R} \\to \\mathbb{R}\\) est limite uniforme d'une suite de polynômes trigonométriques : \\[\\]","hint":"Approximation trigonométrique"},
  {"id":"mp16-def-01","ch":"mp-16","chName":"Équations différentielles linéaires","type":"def","q":"Définir : Système différentiel linéaire.","a":"Un système différentiel linéaire (SDL) d'ordre 1 est une équation de la forme : \\[\\]","hint":"Système différentiel linéaire"},
  {"id":"mp16-thm-01","ch":"mp-16","chName":"Équations différentielles linéaires","type":"thm","q":"Énoncer le théorème : de Cauchy-Lipschitz linéaire.","a":"Soient \\(A \\in \\mathcal{C}(I, \\mathcal{M}_n(\\mathbb{K}))\\) et \\(B \\in \\mathcal{C}(I, \\mathbb{K}^n)\\). Pour tout \\(t_0 \\in I\\) et tout \\(X_0 \\in \\mathbb{K}^n\\), le problème de Cauchy : \\[\\]","hint":"Cauchy-Lipschitz linéaire"},
  {"id":"mp16-thm-02","ch":"mp-16","chName":"Équations différentielles linéaires","type":"thm","q":"Énoncer le théorème : Structure de l'espace des solutions.","a":"L'ensemble \\(\\mathcal{S}_H\\) des solutions du système homogène \\(X' = A(t)\\,X\\) est un sous-espace vectoriel de \\(\\mathcal{C}^1(I, \\mathbb{K}^n)\\) de dimension \\(n\\). L'ensemble des solutions du système complet est : \\[\\]","hint":"Structure l'espace des solutions"},
  {"id":"mp16-def-02","ch":"mp-16","chName":"Équations différentielles linéaires","type":"def","q":"Définir : Système fondamental de solutions.","a":"On appelle système fondamental de solutions du système homogène toute base \\((X_1, \\ldots, X_n)\\) de \\(\\mathcal{S}_H\\). La matrice \\(R(t) = \\bigl(X_1(t) \\mid \\cdots \\mid X_n(t)\\bigr) \\in \\mathcal{M}_n(\\mathbb{K})\\) dont les colonnes sont les vecteurs \\(X_i(t)\\) est appelée matrice fondamentale ou résolvante. Elle vérifie \\(R'(t) = A(t)\\,R(t)\\).","hint":"Système fondamental solutions"},
  {"id":"mp16-def-03","ch":"mp-16","chName":"Équations différentielles linéaires","type":"def","q":"Définir : Wronskien.","a":"Le wronskien d'un système de \\(n\\) solutions \\((X_1, \\ldots, X_n)\\) est la fonction : \\[\\]","hint":"Wronskien"},
  {"id":"mp16-thm-03","ch":"mp-16","chName":"Équations différentielles linéaires","type":"thm","q":"Énoncer le théorème : Formule de Liouville.","a":"Le wronskien de \\(n\\) solutions du système homogène \\(X' = A(t)\\,X\\) vérifie : \\[\\]","hint":"Formule Liouville"},
  {"id":"mp16-def-04","ch":"mp-16","chName":"Équations différentielles linéaires","type":"def","q":"Définir : Exponentielle de matrice.","a":"Pour toute matrice \\(A \\in \\mathcal{M}_n(\\mathbb{K})\\), on définit : \\[\\]","hint":"Exponentielle matrice"},
  {"id":"mp16-prop-01","ch":"mp-16","chName":"Équations différentielles linéaires","type":"prop","q":"Énoncer la proposition : Propriétés fondamentales.","a":"Pour toutes matrices \\(A, B \\in \\mathcal{M}_n(\\mathbb{K})\\) : \\n- \\(\\exp(0_n) = I_n\\). \\n- Si \\(AB = BA\\), alors \\(\\exp(A + B) = \\exp(A)\\exp(B)\\). \\n- \\(\\exp(A)\\) est inversible et \\(\\bigl(\\exp(A)\\bigr)^{-1} = \\exp(-A)\\). \\n- \\(\\det\\bigl(\\exp(A)\\bigr) = e^{\\mathrm{tr}(A)}\\). \\n- Si \\(P\\) est inversible, \\(\\exp(PAP^{-1}) = P\\,\\exp(A)\\,P^{-1}\\).","hint":"Propriétés fondamentales"},
  {"id":"mp16-prop-02","ch":"mp-16","chName":"Équations différentielles linéaires","type":"prop","q":"Énoncer la proposition : Dérivée de l'exponentielle.","a":"L'application \\(t \\mapsto \\exp(tA)\\) est de classe \\(\\mathcal{C}^\\infty\\) sur \\(\\mathbb{R}\\) et vérifie : \\[\\]","hint":"Dérivée l'exponentielle"},
  {"id":"mp16-thm-04","ch":"mp-16","chName":"Équations différentielles linéaires","type":"thm","q":"Énoncer le théorème : Solution du système homogène.","a":"La solution du problème de Cauchy \\(X' = AX\\), \\(X(0) = X_0\\) est : \\[\\]","hint":"Solution système homogène"},
  {"id":"mp16-thm-05","ch":"mp-16","chName":"Équations différentielles linéaires","type":"thm","q":"Énoncer le théorème : Méthode de variation de la constante.","a":"La solution du problème de Cauchy \\(X' = AX + B(t)\\), \\(X(t_0) = X_0\\) est donnée par la formule de Duhamel : \\[\\]","hint":"Méthode variation constante"},
  {"id":"mp16-prop-03","ch":"mp-16","chName":"Équations différentielles linéaires","type":"prop","q":"Énoncer la proposition : Réduction à un système d'ordre 1.","a":"En posant \\(X(t) = \\begin{pmatrix} y(t) \\\\ y'(t) \\\\ \\vdots \\\\ y^{(n-1)}(t) \\end{pmatrix}\\), l'équation \\((\\mathcal{E})\\) se ramène au système : \\[\\]","hint":"Réduction système d'ordre"},
  {"id":"mp16-thm-06","ch":"mp-16","chName":"Équations différentielles linéaires","type":"thm","q":"Énoncer le théorème : Structure des solutions.","a":"L'ensemble des solutions de l'équation homogène associée est un espace vectoriel de dimension \\(n\\). Pour tout \\(t_0 \\in I\\) et toutes conditions initiales \\(y(t_0) = y_0, y'(t_0) = y_1, \\ldots, y^{(n-1)}(t_0) = y_{n-1}\\), il existe une unique solution définie sur \\(I\\).","hint":"Structure des solutions"},
  {"id":"mp16-def-05","ch":"mp-16","chName":"Équations différentielles linéaires","type":"def","q":"Définir : Équation caractéristique.","a":"L'équation caractéristique associée à l'équation homogène \\(y^{(n)} + a_{n-1}\\,y^{(n-1)} + \\cdots + a_0\\,y = 0\\) (coefficients constants \\(a_i \\in \\mathbb{K}\\)) est : \\[\\]","hint":"Équation caractéristique"},
  {"id":"mp16-thm-07","ch":"mp-16","chName":"Équations différentielles linéaires","type":"thm","q":"Énoncer le théorème : Solutions de l'équation homogène à coefficients constants.","a":"Si le polynôme caractéristique admet les racines \\(r_1, \\ldots, r_p\\) de multiplicités respectives \\(m_1, \\ldots, m_p\\) (dans \\(\\mathbb{C}\\)), alors un système fondamental de solutions est constitué des fonctions : \\[\\]","hint":"Solutions l'équation homogène coefficients..."},
  {"id":"mp16-thm-08","ch":"mp-16","chName":"Équations différentielles linéaires","type":"thm","q":"Énoncer le théorème : Solutions de \\(y'' + ay' + by = 0\\).","a":"L'ensemble \\(\\mathcal{S}_H\\) des solutions du système homogène \\(X' = A(t)\\,X\\) est un sous-espace vectoriel de \\(\\mathcal{C}^1(I, \\mathbb{K}^n)\\) de dimension \\(n\\). L'ensemble des solutions du système complet est : \\[\\]","hint":"Solutions y'' ay'"},
  {"id":"mp16-prop-04","ch":"mp-16","chName":"Équations différentielles linéaires","type":"prop","q":"Énoncer la proposition : Second membre polynomial-exponentiel.","a":"Pour \\(y'' + ay' + by = P(t)\\,e^{\\gamma t}\\) où \\(P \\in \\mathbb{K}[t]\\) et \\(\\gamma \\in \\mathbb{K}\\), on cherche une solution particulière sous la forme : \\[\\]","hint":"Second membre polynomial-exponentiel"},
  {"id":"mp16-prop-05","ch":"mp-16","chName":"Équations différentielles linéaires","type":"prop","q":"Énoncer la proposition : Second membre trigonométrique.","a":"Pour résoudre \\(y'' + ay' + by = P(t)\\cos(\\omega t)\\) ou \\(P(t)\\sin(\\omega t)\\) à coefficients réels, on utilise la méthode de complexification. On résout d'abord : \\[\\]","hint":"Second membre trigonométrique"},
  {"id":"mp16-prop-06","ch":"mp-16","chName":"Équations différentielles linéaires","type":"prop","q":"Énoncer la proposition : Principe de superposition.","a":"Si \\(y_1\\) est solution de \\(y'' + ay' + by = f_1(t)\\) et \\(y_2\\) est solution de \\(y'' + ay' + by = f_2(t)\\), alors pour tous scalaires \\(\\alpha, \\beta\\) : \\[\\]","hint":"Principe superposition"},
  {"id":"mp16-def-06","ch":"mp-16","chName":"Équations différentielles linéaires","type":"def","q":"Définir : Équation d'Euler.","a":"Une équation d'Euler d'ordre 2 est une équation de la forme : \\[\\]","hint":"Équation d'Euler"},
  {"id":"mp16-prop-07","ch":"mp-16","chName":"Équations différentielles linéaires","type":"prop","q":"Énoncer la proposition : Résolution par changement de variable.","a":"Le changement de variable \\(t = e^u\\) (i.e. \\(u = \\ln t\\)) et \\(z(u) = y(e^u)\\) transforme l'équation d'Euler en une équation à coefficients constants : \\[\\]","hint":"Résolution par changement variable"},
  {"id":"mp17-def-01","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Application différentiable.","a":"Soit \\(f : U \\to F\\) et \\(a \\in U\\). On dit que \\(f\\) est différentiable en \\(a\\) s'il existe une application linéaire \\(L \\in \\mathcal{L}(E, F)\\) telle que : \\[\\]","hint":"Application différentiable"},
  {"id":"mp17-def-02","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Dérivées partielles.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}^p\\) et \\(a \\in U\\). La dérivée partielle de \\(f\\) par rapport à la \\(j\\)-ème variable en \\(a\\) est, si elle existe : \\[\\]","hint":"Dérivées partielles"},
  {"id":"mp17-thm-01","ch":"mp-17","chName":"Calcul différentiel","type":"thm","q":"Énoncer le théorème : Matrice jacobienne.","a":"Si \\(f = (f_1, \\ldots, f_p) : U \\subset \\mathbb{R}^n \\to \\mathbb{R}^p\\) est différentiable en \\(a\\), alors toutes les dérivées partielles \\(\\frac{\\partial f_i}{\\partial x_j}(a)\\) existent et la matrice de \\(\\mathrm{d}f_a\\) dans les bases canoniques est la matrice jacobienne : \\[J_f(a) = \\begin{pmatrix} \\dfrac{\\partial f_1}{\\partial x_1}(a) & \\cdots & \\dfrac{\\partial f_1}{\\partial x_n}(a) \\\\[6pt] \\vdots & \\ddots & \\vdots \\\\[6pt] \\dfrac{\\partial f_p","hint":"Matrice jacobienne"},
  {"id":"mp17-def-03","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Gradient.","a":"Lorsque \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) est différentiable en \\(a\\), le gradient de \\(f\\) en \\(a\\) est le vecteur : \\[\\]","hint":"Gradient"},
  {"id":"mp17-thm-02","ch":"mp-17","chName":"Calcul différentiel","type":"thm","q":"Énoncer le théorème : Composition (chain rule).","a":"Soient \\(f : U \\subset E \\to F\\) différentiable en \\(a\\) et \\(g : V \\subset F \\to G\\) différentiable en \\(f(a)\\), avec \\(f(U) \\subset V\\). Alors \\(g \\circ f\\) est différentiable en \\(a\\) et : \\[\\]","hint":"Composition (chain rule)"},
  {"id":"mp17-def-04","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Application de classe \\(\\mathcal{C}^1\\).","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}^p\\). On dit que \\(f\\) est de classe \\(\\mathcal{C}^1\\) sur \\(U\\) si toutes les dérivées partielles \\(\\frac{\\partial f_i}{\\partial x_j}\\) existent et sont continues sur \\(U\\). On note \\(f \\in \\mathcal{C}^1(U, \\mathbb{R}^p)\\).","hint":"Application classe mathcal{C}^1"},
  {"id":"mp17-thm-03","ch":"mp-17","chName":"Calcul différentiel","type":"thm","q":"Énoncer le théorème : Condition suffisante de différentiabilité.","a":"Si \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}^p\\) admet des dérivées partielles continues sur \\(U\\), alors \\(f\\) est différentiable en tout point de \\(U\\). Autrement dit : \\[\\]","hint":"Condition suffisante différentiabilité"},
  {"id":"mp17-def-05","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Application de classe \\(\\mathcal{C}^k\\).","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}^p\\). On dit que \\(f\\) est de classe \\(\\mathcal{C}^1\\) sur \\(U\\) si toutes les dérivées partielles \\(\\frac{\\partial f_i}{\\partial x_j}\\) existent et sont continues sur \\(U\\). On note \\(f \\in \\mathcal{C}^1(U, \\mathbb{R}^p)\\).","hint":"Application classe mathcal{C}^k"},
  {"id":"mp17-thm-04","ch":"mp-17","chName":"Calcul différentiel","type":"thm","q":"Énoncer le théorème : Symétrie des dérivées partielles.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^2\\). Alors pour tous \\(i, j \\in \\{1, \\ldots, n\\}\\) et tout \\(a \\in U\\) : \\[\\]","hint":"Symétrie des dérivées partielles"},
  {"id":"mp17-def-06","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Matrice hessienne.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^2\\). La matrice hessienne de \\(f\\) en \\(a\\) est la matrice symétrique (par Schwarz) : \\[\\]","hint":"Matrice hessienne"},
  {"id":"mp17-thm-05","ch":"mp-17","chName":"Calcul différentiel","type":"thm","q":"Énoncer le théorème : Formule de Taylor-Young à l'ordre 2.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^2\\) et \\(a \\in U\\). Alors au voisinage de \\(a\\) : \\[\\]","hint":"Formule Taylor-Young l'ordre"},
  {"id":"mp17-prop-01","ch":"mp-17","chName":"Calcul différentiel","type":"prop","q":"Énoncer la proposition : Taylor-Young à l'ordre \\(k\\).","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^2\\) et \\(a \\in U\\). Alors au voisinage de \\(a\\) : \\[\\]","hint":"Taylor-Young l'ordre"},
  {"id":"mp17-def-07","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Difféomorphisme.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to V \\subset \\mathbb{R}^n\\) avec \\(U, V\\) ouverts. On dit que \\(f\\) est un difféomorphisme de classe \\(\\mathcal{C}^k\\) de \\(U\\) sur \\(V\\) si \\(f\\) est bijective de \\(U\\) sur \\(V\\), \\(f \\in \\mathcal{C}^k(U, \\mathbb{R}^n)\\) et \\(f^{-1} \\in \\mathcal{C}^k(V, \\mathbb{R}^n)\\).","hint":"Difféomorphisme"},
  {"id":"mp17-prop-02","ch":"mp-17","chName":"Calcul différentiel","type":"prop","q":"Énoncer la proposition : Jacobien d'un difféomorphisme.","a":"Si \\(f : U \\to V\\) est un difféomorphisme de classe \\(\\mathcal{C}^1\\), alors pour tout \\(a \\in U\\), la matrice jacobienne \\(J_f(a)\\) est inversible et : \\[\\]","hint":"Jacobien d'un difféomorphisme"},
  {"id":"mp17-thm-06","ch":"mp-17","chName":"Calcul différentiel","type":"thm","q":"Énoncer le théorème : d'inversion locale.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}^n\\) de classe \\(\\mathcal{C}^k\\) (\\(k \\geq 1\\)) et \\(a \\in U\\) tel que \\(J_f(a)\\) soit inversible. Alors il existe un ouvert \\(U_0 \\subset U\\) contenant \\(a\\) et un ouvert \\(V_0\\) contenant \\(f(a)\\) tels que : \\[\\]","hint":"d'inversion locale"},
  {"id":"mp17-prop-03","ch":"mp-17","chName":"Calcul différentiel","type":"prop","q":"Énoncer la proposition : Difféomorphisme global.","a":"Soit \\(f : U \\to \\mathbb{R}^n\\) de classe \\(\\mathcal{C}^k\\), bijective de \\(U\\) sur \\(f(U)\\), avec \\(J_f(x)\\) inversible pour tout \\(x \\in U\\). Alors \\(f(U)\\) est ouvert et \\(f\\) est un \\(\\mathcal{C}^k\\)-difféomorphisme de \\(U\\) sur \\(f(U)\\).","hint":"Difféomorphisme global"},
  {"id":"mp17-thm-07","ch":"mp-17","chName":"Calcul différentiel","type":"thm","q":"Énoncer le théorème : des fonctions implicites.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\times \\mathbb{R}^p \\to \\mathbb{R}^p\\) de classe \\(\\mathcal{C}^k\\) (\\(k \\geq 1\\)) et \\((a, b) \\in U\\) tel que \\(f(a, b) = 0\\). Si la matrice \\(\\frac{\\partial f}{\\partial y}(a, b) \\in \\mathcal{M}_p(\\mathbb{R})\\) est inversible, alors il existe un ouvert \\(U_a \\subset \\mathbb{R}^n\\) contenant \\(a\\), un ouvert \\(V_b \\subset \\mathbb{R}^p\\) contenant \\(b\\) et une unique application \\(\\varphi : U_a \\to V_b\\) de classe \\","hint":"des fonctions implicites"},
  {"id":"mp17-def-08","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Extremum local.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) et \\(a \\in U\\). On dit que \\(f\\) admet un minimum local en \\(a\\) s'il existe \\(r > 0\\) tel que \\(f(x) \\geq f(a)\\) pour tout \\(x \\in B(a, r) \\cap U\\). On définit de même un maximum local. Un extremum local est un minimum ou un maximum local.","hint":"Extremum local"},
  {"id":"mp17-thm-08","ch":"mp-17","chName":"Calcul différentiel","type":"thm","q":"Énoncer le théorème : Condition nécessaire du premier ordre.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) différentiable en \\(a \\in U\\). Si \\(f\\) admet un extremum local en \\(a\\), alors : \\[\\]","hint":"Condition nécessaire premier ordre"},
  {"id":"mp17-thm-09","ch":"mp-17","chName":"Calcul différentiel","type":"thm","q":"Énoncer le théorème : Condition suffisante du second ordre.","a":"Soit \\(f : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^2\\) et \\(a \\in U\\) un point critique (\\(\\nabla f(a) = 0\\)). \\n- Si \\(H_f(a)\\) est définie positive, alors \\(f\\) admet un minimum local strict en \\(a\\). \\n- Si \\(H_f(a)\\) est définie négative, alors \\(f\\) admet un maximum local strict en \\(a\\). \\n- Si \\(H_f(a)\\) admet des valeurs propres de signes opposés, alors \\(a\\) est un point selle.","hint":"Condition suffisante second ordre"},
  {"id":"mp17-thm-10","ch":"mp-17","chName":"Calcul différentiel","type":"thm","q":"Énoncer le théorème : Multiplicateurs de Lagrange.","a":"Soit \\(f, g_1, \\ldots, g_p : U \\subset \\mathbb{R}^n \\to \\mathbb{R}\\) de classe \\(\\mathcal{C}^1\\), avec \\(p < n\\). On pose \\(S = \\{x \\in U : g_1(x) = \\cdots = g_p(x) = 0\\}\\). Si \\(f_{|S}\\) admet un extremum local en \\(a \\in S\\) et si les gradients \\(\\nabla g_1(a), \\ldots, \\nabla g_p(a)\\) sont linéairement indépendants, alors il existe des scalaires \\(\\lambda_1, \\ldots, \\lambda_p \\in \\mathbb{R}\\) (les multiplicateurs de Lagrange) tels que : \\[\\nabla","hint":"Multiplicateurs Lagrange"},
  {"id":"mp17-def-09","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Arc paramétré.","a":"Un arc paramétré de classe \\(\\mathcal{C}^k\\) dans \\(\\mathbb{R}^d\\) est une application \\(\\gamma : I \\to \\mathbb{R}^d\\) de classe \\(\\mathcal{C}^k\\), où \\(I\\) est un intervalle de \\(\\mathbb{R}\\). L'image \\(\\gamma(I)\\) est le support (ou trace) de l'arc. On dit que l'arc est régulier si \\(\\gamma'(t) \\neq 0\\) pour tout \\(t \\in I\\).","hint":"Arc paramétré"},
  {"id":"mp17-def-10","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Vecteur tangent et droite tangente.","a":"Si \\(\\gamma : I \\to \\mathbb{R}^d\\) est un arc de classe \\(\\mathcal{C}^1\\) et \\(t_0 \\in I\\) tel que \\(\\gamma'(t_0) \\neq 0\\), le vecteur \\(\\gamma'(t_0)\\) est appelé vecteur tangent à l'arc en \\(t_0\\). La droite tangente en \\(\\gamma(t_0)\\) est la droite dirigée par \\(\\gamma'(t_0)\\) : \\[\\]","hint":"Vecteur tangent droite tangente"},
  {"id":"mp17-prop-04","ch":"mp-17","chName":"Calcul différentiel","type":"prop","q":"Énoncer la proposition : Point régulier et point singulier.","a":"Soit \\(\\gamma : I \\to \\mathbb{R}^d\\) de classe \\(\\mathcal{C}^k\\) (\\(k \\geq 1\\)) et \\(t_0 \\in I\\). \\n- Si \\(\\gamma'(t_0) \\neq 0\\), le point est dit régulier (ou ordinaire) : la courbe admet une tangente bien définie. \\n- Si \\(\\gamma'(t_0) = 0\\), le point est singulier. On cherche alors le premier \\(p \\geq 2\\) tel que \\(\\gamma^{(p)}(t_0) \\neq 0\\) pour déterminer le comportement local (point de rebroussement, etc.).","hint":"Point régulier point singulier"},
  {"id":"mp17-def-11","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Longueur d'un arc.","a":"Soit \\(\\gamma : [a, b] \\to \\mathbb{R}^d\\) un arc de classe \\(\\mathcal{C}^1\\). La longueur de l'arc est : \\[\\]","hint":"Longueur d'un arc"},
  {"id":"mp17-def-12","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Abscisse curviligne.","a":"Soit \\(\\gamma : I \\to \\mathbb{R}^d\\) un arc régulier de classe \\(\\mathcal{C}^1\\) et \\(t_0 \\in I\\). L'abscisse curviligne à partir de \\(t_0\\) est la fonction : \\[\\]","hint":"Abscisse curviligne"},
  {"id":"mp17-def-13","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Courbure d'une courbe plane.","a":"Soit \\(\\gamma : I \\to \\mathbb{R}^2\\) un arc régulier de classe \\(\\mathcal{C}^2\\), paramétré par l'abscisse curviligne. La courbure en un point est : \\[\\]","hint":"Courbure d'une courbe plane"},
  {"id":"mp17-def-14","ch":"mp-17","chName":"Calcul différentiel","type":"def","q":"Définir : Rayon de courbure et cercle osculateur.","a":"En un point où \\(\\kappa \\neq 0\\), le rayon de courbure est \\(R = 1/\\kappa\\). Le cercle osculateur est le cercle de rayon \\(R\\) tangent à la courbe au point considéré, situé du côté vers lequel la courbe tourne. C'est le cercle qui approche le mieux la courbe à l'ordre 2.","hint":"Rayon courbure cercle osculateur"},
  {"id":"mp17-prop-05","ch":"mp-17","chName":"Calcul différentiel","type":"prop","q":"Énoncer la proposition : Courbure d'un graphe.","a":"Si la courbe est le graphe d'une fonction \\(y = f(x)\\) de classe \\(\\mathcal{C}^2\\), on paramètre par \\(\\gamma(t) = (t, f(t))\\) et la courbure vaut : \\[\\]","hint":"Courbure d'un graphe"},
  {"id":"mp18-def-01","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Densité de probabilité.","a":"Une fonction \\(f : \\mathbb{R} \\to \\mathbb{R}\\) est une densité de probabilité si : \\n- \\(f\\) est continue par morceaux et positive : \\(f(x) \\geq 0\\) pour tout \\(x \\in \\mathbb{R}\\). \\n- \\(f\\) est intégrable et normalisée : \\(\\displaystyle\\int_{-\\infty}^{+\\infty} f(x)\\,\\mathrm{d}x = 1\\). Une variable aléatoire \\(X\\) admet \\(f\\) pour densité si, pour tout intervalle \\([a, b]\\) : \\[\\]","hint":"Densité probabilité"},
  {"id":"mp18-def-02","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Fonction de répartition.","a":"La fonction de répartition de \\(X\\) est la fonction \\(F : \\mathbb{R} \\to [0, 1]\\) définie par : \\[\\]","hint":"Fonction répartition"},
  {"id":"mp18-thm-01","ch":"mp-18","chName":"Variables aléatoires à densité","type":"thm","q":"Énoncer le théorème : Lien densité / fonction de répartition.","a":"Si \\(X\\) admet une densité \\(f\\) continue par morceaux, alors sa fonction de répartition \\(F\\) est de classe \\(\\mathcal{C}^1\\) en tout point de continuité de \\(f\\), et : \\[\\]","hint":"Lien densité fonction répartition"},
  {"id":"mp18-prop-01","ch":"mp-18","chName":"Variables aléatoires à densité","type":"prop","q":"Énoncer la proposition : Probabilités et densité.","a":"Si \\(X\\) admet une densité, alors pour tout \\(x_0 \\in \\mathbb{R}\\) : \\[\\]","hint":"Probabilités densité"},
  {"id":"mp18-def-03","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Loi uniforme \\(\\mathcal{U}([a, b])\\).","a":"On dit que \\(X\\) suit la loi uniforme sur \\([a, b]\\) si sa densité est : \\[\\]","hint":"Loi uniforme mathcal{U}([a, b])"},
  {"id":"mp18-def-04","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Loi exponentielle \\(\\mathcal{E}(\\lambda)\\).","a":"On dit que \\(X\\) suit la loi uniforme sur \\([a, b]\\) si sa densité est : \\[\\]","hint":"Loi exponentielle mathcal{E}(lambda)"},
  {"id":"mp18-prop-02","ch":"mp-18","chName":"Variables aléatoires à densité","type":"prop","q":"Énoncer la proposition : Propriété d'absence de mémoire.","a":"La loi exponentielle est la seule loi à densité sur \\(\\mathbb{R}_+\\) vérifiant la propriété d'absence de mémoire : pour tous \\(s, t \\geq 0\\), \\[\\]","hint":"Propriété d'absence mémoire"},
  {"id":"mp18-def-05","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Loi normale (gaussienne) \\(\\mathcal{N}(\\mu, \\sigma^2)\\).","a":"Soit \\(\\mu \\in \\mathbb{R}\\) et \\(\\sigma > 0\\). On dit que \\(X\\) suit la loi normale de paramètres \\(\\mu\\) et \\(\\sigma^2\\) si sa densité est : \\[\\]","hint":"Loi normale (gaussienne) mathcal{N}(mu,..."},
  {"id":"mp18-prop-03","ch":"mp-18","chName":"Variables aléatoires à densité","type":"prop","q":"Énoncer la proposition : Intégrale de Gauss et normalisation.","a":"L'intégrale de Gauss vaut : \\[\\]","hint":"Intégrale Gauss normalisation"},
  {"id":"mp18-def-06","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Loi de Cauchy.","a":"On dit que \\(X\\) suit la loi de Cauchy standard si sa densité est : \\[\\]","hint":"Loi Cauchy"},
  {"id":"mp18-def-07","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Loi Gamma \\(\\Gamma(a, \\lambda)\\).","a":"Soit \\(\\lambda > 0\\). On dit que \\(X\\) suit la loi exponentielle de paramètre \\(\\lambda\\) si sa densité est : \\[\\]","hint":"Loi Gamma Gamma(a, lambda)"},
  {"id":"mp18-def-08","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Espérance.","a":"Soit \\(X\\) une variable aléatoire admettant la densité \\(f\\). L'espérance de \\(X\\) existe si \\(\\int_{-\\infty}^{+\\infty} |x|\\,f(x)\\,\\mathrm{d}x < +\\infty\\), et vaut alors : \\[\\]","hint":"Espérance"},
  {"id":"mp18-thm-02","ch":"mp-18","chName":"Variables aléatoires à densité","type":"thm","q":"Énoncer le théorème : Théorème de transfert.","a":"Soit \\(X\\) une variable aléatoire de densité \\(f\\) et \\(g : \\mathbb{R} \\to \\mathbb{R}\\) une fonction mesurable. Alors \\(g(X)\\) admet une espérance si et seulement si \\(\\int |g(x)|\\,f(x)\\,\\mathrm{d}x < +\\infty\\), et dans ce cas : \\[\\]","hint":"Théorème transfert"},
  {"id":"mp18-def-09","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Variance et écart-type.","a":"Si \\(X\\) admet un moment d'ordre 2 (i.e. \\(\\mathbb{E}(X^2) < +\\infty\\)), on définit la variance : \\[\\]","hint":"Variance écart-type"},
  {"id":"mp18-thm-03","ch":"mp-18","chName":"Variables aléatoires à densité","type":"thm","q":"Énoncer le théorème : Inégalité de Markov.","a":"Soit \\(X\\) une variable aléatoire positive admettant une espérance. Pour tout \\(a > 0\\) : \\[\\]","hint":"Inégalité Markov"},
  {"id":"mp18-thm-04","ch":"mp-18","chName":"Variables aléatoires à densité","type":"thm","q":"Énoncer le théorème : Inégalité de Bienaymé-Tchebychev.","a":"Soit \\(X\\) une variable aléatoire admettant un moment d'ordre 2. Pour tout \\(\\varepsilon > 0\\) : \\[\\]","hint":"Inégalité Bienaymé-Tchebychev"},
  {"id":"mp18-def-10","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Moments d'ordre \\(k\\).","a":"Le moment d'ordre \\(k\\) de \\(X\\) est \\(m_k = \\mathbb{E}(X^k)\\) lorsqu'il existe. Le moment centré d'ordre \\(k\\) est \\(\\mu_k = \\mathbb{E}\\bigl((X - \\mathbb{E}(X))^k\\bigr)\\). On a \\(\\mu_1 = 0\\), \\(\\mu_2 = \\mathrm{Var}(X)\\).","hint":"Moments d'ordre"},
  {"id":"mp18-def-11","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Fonction génératrice des moments.","a":"La fonction génératrice des moments (MGF) de \\(X\\) est définie, lorsqu'elle existe dans un voisinage de \\(0\\), par : \\[\\]","hint":"Fonction génératrice des moments"},
  {"id":"mp18-def-12","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Densité conjointe.","a":"Un couple \\((X, Y)\\) de variables aléatoires réelles est dit à densité s'il existe une fonction \\(f_{(X,Y)} : \\mathbb{R}^2 \\to \\mathbb{R}_+\\) intégrable telle que, pour tout borélien \\(B \\subset \\mathbb{R}^2\\) : \\[\\]","hint":"Densité conjointe"},
  {"id":"mp18-prop-04","ch":"mp-18","chName":"Variables aléatoires à densité","type":"prop","q":"Énoncer la proposition : Densités marginales.","a":"Si \\((X, Y)\\) admet la densité conjointe \\(f_{(X,Y)}\\), alors \\(X\\) et \\(Y\\) admettent des densités (dites marginales) données par : \\[\\]","hint":"Densités marginales"},
  {"id":"mp18-thm-05","ch":"mp-18","chName":"Variables aléatoires à densité","type":"thm","q":"Énoncer le théorème : Caractérisation de l'indépendance.","a":"Soit \\((X, Y)\\) un couple de variables aléatoires admettant une densité conjointe \\(f_{(X,Y)}\\). Alors \\(X\\) et \\(Y\\) sont indépendantes si et seulement si : \\[\\]","hint":"Caractérisation l'indépendance"},
  {"id":"mp18-def-13","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Covariance et coefficient de corrélation.","a":"Si \\(X\\) et \\(Y\\) admettent un moment d'ordre 2, la covariance de \\(X\\) et \\(Y\\) est : \\[\\]","hint":"Covariance coefficient corrélation"},
  {"id":"mp18-prop-05","ch":"mp-18","chName":"Variables aléatoires à densité","type":"prop","q":"Énoncer la proposition : Indépendance et corrélation.","a":"Si \\(X\\) et \\(Y\\) sont indépendantes et admettent un moment d'ordre 2, alors \\(\\mathrm{Cov}(X, Y) = 0\\) (on dit qu'elles sont non corrélées). La réciproque est fausse en général. Pour des variables indépendantes : \\(\\mathrm{Var}(X + Y) = \\mathrm{Var}(X) + \\mathrm{Var}(Y)\\).","hint":"Indépendance corrélation"},
  {"id":"mp18-def-14","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Produit de convolution.","a":"Si \\(X\\) et \\(Y\\) sont deux variables aléatoires indépendantes de densités respectives \\(f_X\\) et \\(f_Y\\), alors \\(Z = X + Y\\) admet pour densité le produit de convolution : \\[\\]","hint":"Produit convolution"},
  {"id":"mp18-thm-06","ch":"mp-18","chName":"Variables aléatoires à densité","type":"thm","q":"Énoncer le théorème : Somme de variables normales indépendantes.","a":"Si \\(X \\sim \\mathcal{N}(\\mu_1, \\sigma_1^2)\\) et \\(Y \\sim \\mathcal{N}(\\mu_2, \\sigma_2^2)\\) sont indépendantes, alors : \\[\\]","hint":"Somme variables normales indépendantes"},
  {"id":"mp18-prop-06","ch":"mp-18","chName":"Variables aléatoires à densité","type":"prop","q":"Énoncer la proposition : Somme d'exponentielles indépendantes.","a":"Si \\(X_1, \\ldots, X_n\\) sont des variables aléatoires indépendantes de loi \\(\\mathcal{E}(\\lambda)\\), alors leur somme suit une loi Gamma : \\[\\]","hint":"Somme d'exponentielles indépendantes"},
  {"id":"mp18-def-15","ch":"mp-18","chName":"Variables aléatoires à densité","type":"def","q":"Définir : Loi du chi-deux \\(\\chi^2(n)\\).","a":"Si \\(Z_1, \\ldots, Z_n\\) sont des variables aléatoires indépendantes de loi \\(\\mathcal{N}(0, 1)\\), alors : \\[\\]","hint":"Loi chi-deux chi^2(n)"},
  {"id":"mp18-prop-07","ch":"mp-18","chName":"Variables aléatoires à densité","type":"prop","q":"Énoncer la proposition : Additivité du chi-deux.","a":"Si \\(U \\sim \\chi^2(p)\\) et \\(V \\sim \\chi^2(q)\\) sont indépendantes, alors \\(U + V \\sim \\chi^2(p + q)\\). Cette propriété d'additivité découle directement de l'additivité de la loi Gamma (à paramètre \\(\\lambda\\) fixé).","hint":"Additivité chi-deux"},
  {"id":"mp18-prop-08","ch":"mp-18","chName":"Variables aléatoires à densité","type":"prop","q":"Énoncer la proposition : Méthode de la CDF.","a":"Pour trouver la loi de \\(Y = g(X)\\) lorsque \\(X\\) a une densité \\(f_X\\) : \\n- On calcule la CDF de \\(Y\\) : \\(F_Y(y) = P(Y \\leq y) = P(g(X) \\leq y)\\). \\n- On exprime cette probabilité en termes de \\(X\\) et on intègre. \\n- On dérive pour obtenir \\(f_Y(y) = F_Y'(y)\\). Cette méthode est universelle et fonctionne pour toute fonction \\(g\\) mesurable.","hint":"Méthode CDF"},
  {"id":"mp18-thm-07","ch":"mp-18","chName":"Variables aléatoires à densité","type":"thm","q":"Énoncer le théorème : Changement de variable pour les densités.","a":"Soit \\(X\\) une variable aléatoire de densité \\(f_X\\) et \\(g : I \\to J\\) un \\(\\mathcal{C}^1\\)-difféomorphisme (bijection de classe \\(\\mathcal{C}^1\\) d'inverse \\(\\mathcal{C}^1\\)) d'un intervalle \\(I\\) sur un intervalle \\(J\\), avec \\(P(X \\in I) = 1\\). Alors \\(Y = g(X)\\) admet pour densité : \\[\\]","hint":"Changement variable pour les..."},
  {"id":"mp18-thm-08","ch":"mp-18","chName":"Variables aléatoires à densité","type":"thm","q":"Énoncer le théorème : Changement de variable en dimension 2.","a":"Soit \\((X, Y)\\) un couple de densité \\(f_{(X,Y)}\\) et \\(\\varphi : U \\to V\\) un \\(\\mathcal{C}^1\\)-difféomorphisme d'un ouvert \\(U \\subset \\mathbb{R}^2\\) sur un ouvert \\(V\\), avec \\(P((X,Y) \\in U) = 1\\). Posons \\((S, T) = \\varphi(X, Y)\\). Alors la densité de \\((S, T)\\) est : \\[\\]","hint":"Changement variable dimension"},
  {"id":"mp19-def-01","ch":"mp-19","chName":"Convergences et statistiques","type":"def","q":"Définir : Convergence en probabilité.","a":"On dit que la suite \\((X_n)\\) converge en probabilité vers une variable aléatoire \\(X\\), et on note \\(X_n \\xrightarrow{P} X\\), si : \\[\\]","hint":"Convergence probabilité"},
  {"id":"mp19-prop-01","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : Unicité de la limite.","a":"Si \\(X_n \\xrightarrow{P} X\\) et \\(X_n \\xrightarrow{P} Y\\), alors \\(X = Y\\) presque sûrement. La limite en probabilité est donc essentiellement unique.","hint":"Unicité limite"},
  {"id":"mp19-prop-02","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : Inégalité de Markov et inégalité de Bienaymé-Tchebychev.","a":"Soit \\(X\\) une variable aléatoire réelle admettant un moment d'ordre 2. \\n- Inégalité de Markov : pour tout \\(a > 0\\), \\(\\displaystyle P(|X| \\geq a) \\leq \\frac{E(|X|)}{a}\\). \\n- Inégalité de Bienaymé-Tchebychev : pour tout \\(\\varepsilon > 0\\), \\(\\displaystyle P\\bigl(|X - E(X)| \\geq \\varepsilon\\bigr) \\leq \\frac{V(X)}{\\varepsilon^2}\\).","hint":"Inégalité Markov inégalité Bienaymé-Tchebychev"},
  {"id":"mp19-thm-01","ch":"mp-19","chName":"Convergences et statistiques","type":"thm","q":"Énoncer le théorème : Loi faible des grands nombres.","a":"Soit \\((X_n)_{n \\geq 1}\\) une suite de variables aléatoires mutuellement indépendantes, de même loi, admettant une espérance \\(\\mu = E(X_1)\\) et une variance \\(\\sigma^2 = V(X_1)\\). On pose \\(\\overline{X}_n = \\frac{1}{n}\\sum_{k=1}^n X_k\\). Alors : \\[\\]","hint":"Loi faible des grands..."},
  {"id":"mp19-def-02","ch":"mp-19","chName":"Convergences et statistiques","type":"def","q":"Définir : Convergence presque sûre.","a":"On dit que la suite \\((X_n)\\) converge presque sûrement vers \\(X\\), et on note \\(X_n \\xrightarrow{p.s.} X\\), si : \\[\\]","hint":"Convergence presque sûre"},
  {"id":"mp19-prop-03","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : Caractérisation séquentielle.","a":"La convergence presque sûre \\(X_n \\xrightarrow{p.s.} X\\) est équivalente à : \\[\\]","hint":"Caractérisation séquentielle"},
  {"id":"mp19-thm-02","ch":"mp-19","chName":"Convergences et statistiques","type":"thm","q":"Énoncer le théorème : Loi forte des grands nombres.","a":"Soit \\((X_n)_{n \\geq 1}\\) une suite de variables aléatoires mutuellement indépendantes, de même loi, admettant une espérance \\(\\mu = E(X_1)\\). Alors : \\[\\]","hint":"Loi forte des grands..."},
  {"id":"mp19-prop-04","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : La convergence p.s. implique la convergence en probabilité.","a":"Si \\(X_n \\xrightarrow{p.s.} X\\), alors \\(X_n \\xrightarrow{P} X\\). La réciproque est fausse en général.","hint":"convergence p.s. implique convergence..."},
  {"id":"mp19-def-03","ch":"mp-19","chName":"Convergences et statistiques","type":"def","q":"Définir : Convergence en loi.","a":"On dit que la suite \\((X_n)\\) converge en loi vers \\(X\\), et on note \\(X_n \\xrightarrow{\\mathcal{L}} X\\), si pour tout point de continuité \\(x\\) de la fonction de répartition \\(F_X\\) de \\(X\\) : \\[\\]","hint":"Convergence loi"},
  {"id":"mp19-prop-05","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : La convergence en probabilité implique la convergence en loi.","a":"Si \\(X_n \\xrightarrow{P} X\\), alors \\(X_n \\xrightarrow{\\mathcal{L}} X\\). La réciproque est fausse en général, sauf lorsque la limite est une constante.","hint":"convergence probabilité implique convergence..."},
  {"id":"mp19-prop-06","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : Cas de la convergence vers une constante.","a":"Soit \\(c \\in \\mathbb{R}\\). Les assertions suivantes sont équivalentes : \\n- \\(X_n \\xrightarrow{\\mathcal{L}} c\\) (convergence en loi vers la constante \\(c\\)). \\n- \\(X_n \\xrightarrow{P} c\\) (convergence en probabilité vers \\(c\\)).","hint":"Cas convergence vers une..."},
  {"id":"mp19-thm-03","ch":"mp-19","chName":"Convergences et statistiques","type":"thm","q":"Énoncer le théorème : Théorème central limite (TCL).","a":"Soit \\((X_n)_{n \\geq 1}\\) une suite de variables aléatoires i.i.d. d'espérance \\(\\mu\\) et de variance \\(\\sigma^2 > 0\\). Alors : \\[\\]","hint":"Théorème central limite (TCL)"},
  {"id":"mp19-prop-07","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : Intervalle de confiance asymptotique pour la moyenne.","a":"Sous les hypothèses du TCL, pour un niveau de confiance \\(1 - \\alpha\\) : \\[\\]","hint":"Intervalle confiance asymptotique pour..."},
  {"id":"mp19-def-04","ch":"mp-19","chName":"Convergences et statistiques","type":"def","q":"Définir : Convergence dans \\(L^p\\).","a":"On dit que la suite \\((X_n)\\) converge en probabilité vers une variable aléatoire \\(X\\), et on note \\(X_n \\xrightarrow{P} X\\), si : \\[\\]","hint":"Convergence dans L^p"},
  {"id":"mp19-prop-08","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : La convergence \\(L^p\\) implique la convergence en probabilité.","a":"On dit que la suite \\((X_n)\\) converge en probabilité vers une variable aléatoire \\(X\\), et on note \\(X_n \\xrightarrow{P} X\\), si : \\[\\]","hint":"convergence L^p implique convergence..."},
  {"id":"mp19-prop-09","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : Hiérarchie des convergences \\(L^p\\).","a":"Si \\(1 \\leq p \\leq q\\), alors la convergence dans \\(L^q\\) implique la convergence dans \\(L^p\\). En particulier, la convergence en moyenne quadratique (\\(L^2\\)) implique la convergence en moyenne (\\(L^1\\)).","hint":"Hiérarchie des convergences L^p"},
  {"id":"mp19-thm-04","ch":"mp-19","chName":"Convergences et statistiques","type":"thm","q":"Énoncer le théorème : Hiérarchie complète des convergences.","a":"Les implications suivantes résument les liens entre les modes de convergence : \\[\\]","hint":"Hiérarchie complète des convergences"},
  {"id":"mp19-def-05","ch":"mp-19","chName":"Convergences et statistiques","type":"def","q":"Définir : Estimateur ponctuel.","a":"Un estimateur de \\(\\theta\\) est une statistique \\(T_n = T_n(X_1, \\ldots, X_n)\\), c'est-à-dire une fonction mesurable de l'échantillon, à valeurs dans \\(\\Theta\\).","hint":"Estimateur ponctuel"},
  {"id":"mp19-def-06","ch":"mp-19","chName":"Convergences et statistiques","type":"def","q":"Définir : Biais et estimateur sans biais.","a":"Le biais de l'estimateur \\(T_n\\) est \\(b(T_n) = E_\\theta(T_n) - \\theta\\). L'estimateur est dit sans biais si \\(b(T_n) = 0\\) pour tout \\(\\theta \\in \\Theta\\), c'est-à-dire si \\(E_\\theta(T_n) = \\theta\\). L'estimateur est dit asymptotiquement sans biais si \\(b(T_n) \\to 0\\) quand \\(n \\to +\\infty\\).","hint":"Biais estimateur sans biais"},
  {"id":"mp19-def-07","ch":"mp-19","chName":"Convergences et statistiques","type":"def","q":"Définir : Estimateur convergent (consistant).","a":"L'estimateur \\(T_n\\) est dit convergent (ou consistant) si \\(T_n \\xrightarrow{P} \\theta\\) pour tout \\(\\theta \\in \\Theta\\).","hint":"Estimateur convergent (consistant)"},
  {"id":"mp19-prop-10","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : Critère de convergence par le risque quadratique.","a":"Si \\(T_n\\) est un estimateur de \\(\\theta\\) tel que : \\[\\]","hint":"Critère convergence par risque..."},
  {"id":"mp19-def-08","ch":"mp-19","chName":"Convergences et statistiques","type":"def","q":"Définir : Fonction de vraisemblance et EMV.","a":"Soit \\((x_1, \\ldots, x_n)\\) une réalisation de l'échantillon. La fonction de vraisemblance est : \\[\\]","hint":"Fonction vraisemblance EMV"},
  {"id":"mp19-prop-11","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : Propriétés de l'EMV (admis).","a":"Sous des conditions de régularité, l'estimateur du maximum de vraisemblance \\(\\hat{\\theta}_n\\) vérifie : \\n- Convergence : \\(\\hat{\\theta}_n \\xrightarrow{P} \\theta\\) (consistance). \\n- Normalité asymptotique : \\(\\sqrt{n}(\\hat{\\theta}_n - \\theta) \\xrightarrow{\\mathcal{L}} \\mathcal{N}\\bigl(0, I(\\theta)^{-1}\\bigr)\\), où \\(I(\\theta)\\) est l'information de Fisher. \\n- Efficacité asymptotique : il atteint asymptotiquement la borne de Cramér-Rao.","hint":"Propriétés l'EMV (admis)"},
  {"id":"mp19-def-09","ch":"mp-19","chName":"Convergences et statistiques","type":"def","q":"Définir : Hypothèses et test.","a":"On considère deux hypothèses : \\n- \\(H_0\\) : hypothèse nulle (hypothèse que l'on cherche à rejeter), par exemple \\(\\theta = \\theta_0\\). \\n- \\(H_1\\) : hypothèse alternative, par exemple \\(\\theta \\neq \\theta_0\\) (test bilatéral), \\(\\theta > \\theta_0\\) ou \\(\\theta < \\theta_0\\) (test unilatéral). Un test est une application mesurable \\(\\varphi : \\mathbb{R}^n \\to \\{0, 1\\}\\). On rejette \\(H_0\\) si \\(\\varphi(X_1, \\ldots, X_n) = 1\\).","hint":"Hypothèses test"},
  {"id":"mp19-def-10","ch":"mp-19","chName":"Convergences et statistiques","type":"def","q":"Définir : Erreurs de première et seconde espèce.","a":"On distingue deux types d'erreurs : \\n- Erreur de première espèce (type I) : rejeter \\(H_0\\) alors que \\(H_0\\) est vraie. Sa probabilité est \\(\\alpha = P_{\\theta_0}(\\varphi = 1)\\). \\n- Erreur de seconde espèce (type II) : ne pas rejeter \\(H_0\\) alors que \\(H_1\\) est vraie. Sa probabilité est \\(\\beta = P_{\\theta_1}(\\varphi = 0)\\). Le niveau (ou seuil) du test est \\(\\alpha\\). La puissance du test est \\(1 - \\beta\\).","hint":"Erreurs première seconde espèce"},
  {"id":"mp19-def-11","ch":"mp-19","chName":"Convergences et statistiques","type":"def","q":"Définir : Région critique et p-valeur.","a":"La région critique (ou zone de rejet) est l'ensemble \\(W = \\{(x_1, \\ldots, x_n) : \\varphi(x_1, \\ldots, x_n) = 1\\}\\). En pratique, on construit une statistique de test \\(T_n\\) dont on connaît la loi sous \\(H_0\\), et on rejette si \\(T_n\\) tombe dans une zone extrême. La p-valeur est la probabilité, sous \\(H_0\\), d'obtenir une valeur de la statistique de test au moins aussi extrême que celle observée. On rejette \\(H_0\\) si la p-valeur est inférieure au niveau \\(\\alpha\\).","hint":"Région critique p-valeur"},
  {"id":"mp19-thm-05","ch":"mp-19","chName":"Convergences et statistiques","type":"thm","q":"Énoncer le théorème : Test de la moyenne (variance connue).","a":"Soit \\((X_1, \\ldots, X_n)\\) un échantillon i.i.d. de loi \\(\\mathcal{N}(\\mu, \\sigma^2)\\) avec \\(\\sigma^2\\) connue. Pour tester \\(H_0 : \\mu = \\mu_0\\) contre \\(H_1 : \\mu \\neq \\mu_0\\) au niveau \\(\\alpha\\), on utilise la statistique : \\[\\]","hint":"Test moyenne (variance connue)"},
  {"id":"mp19-prop-12","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : Test de la moyenne (variance inconnue).","a":"Si \\(\\sigma^2\\) est inconnue, on la remplace par la variance empirique corrigée \\(S_n^2\\). La statistique : \\[\\]","hint":"Test moyenne (variance inconnue)"},
  {"id":"mp19-thm-06","ch":"mp-19","chName":"Convergences et statistiques","type":"thm","q":"Énoncer le théorème : Test du \\(\\chi^2\\) de Pearson.","a":"On observe les effectifs \\((N_1, \\ldots, N_r)\\) dans \\(r\\) catégories, avec \\(\\sum N_i = n\\). Sous l'hypothèse \\(H_0\\) spécifiant les probabilités théoriques \\((p_1, \\ldots, p_r)\\), la statistique : \\[\\]","hint":"Test chi^2 Pearson"},
  {"id":"mp19-prop-13","ch":"mp-19","chName":"Convergences et statistiques","type":"prop","q":"Énoncer la proposition : Bilan des liens entre convergences et statistique.","a":"Les résultats de convergence fondent toute la statistique asymptotique : \\n- La loi des grands nombres garantit la convergence des estimateurs empiriques (consistance). \\n- Le théorème central limite fournit la loi asymptotique des estimateurs, permettant de construire intervalles de confiance et tests. \\n- La convergence en loi du \\(\\chi^2\\) justifie les tests d'adéquation et d'indépendance.","hint":"Bilan des liens entre..."}
];

